'use client';

import { useEffect, useState } from 'react';
import Link from 'next/link';
import { useToast } from '@/contexts/ToastContext';

import type { AnalyticsSummary, TopProduct, CustomerCountry } from '@/lib/services/analyticsService';

export default function AdminAnalyticsPage() {
    const { showToast } = useToast();
    const [summary, setSummary] = useState<AnalyticsSummary | null>(null);
    const [topProducts, setTopProducts] = useState<TopProduct[]>([]);
    const [countries, setCountries] = useState<CustomerCountry[]>([]);
    const [loading, setLoading] = useState(true);
    const [showDatePicker, setShowDatePicker] = useState(false);
    const [startDate, setStartDate] = useState(() => {
        const d = new Date();
        d.setDate(d.getDate() - 30);
        return d.toISOString().split('T')[0];
    });
    const [endDate, setEndDate] = useState(() => new Date().toISOString().split('T')[0]);
    const dateRange = `${new Date(startDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })} – ${new Date(endDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}`;

    useEffect(() => {
        async function fetchData() {
            try {
                const [summaryRes, productsRes, countriesRes] = await Promise.all([
                    fetch('/api/analytics?type=summary', { cache: 'no-store' }),
                    fetch('/api/analytics?type=top-products', { cache: 'no-store' }),
                    fetch('/api/analytics?type=customers-by-country', { cache: 'no-store' })
                ]);

                const summaryData = await summaryRes.json();
                const productsData = await productsRes.json();
                const countriesData = await countriesRes.json();

                if (summaryData.success) setSummary(summaryData.data);
                if (productsData.success) setTopProducts(productsData.data);
                if (countriesData.success) setCountries(countriesData.data);
            } catch (err) {
                console.error('Failed to load analytics:', err);
            } finally {
                setLoading(false);
            }
        }
        fetchData();
    }, []);

    const handleDownloadPDF = async () => {
        // Dynamic import to avoid SSR issues
        const html2canvas = (await import('html2canvas')).default;
        const jsPDF = (await import('jspdf')).default;

        const element = document.getElementById('analytics-dashboard');
        if (!element) return;

        try {
            const canvas = await html2canvas(element, {
                scale: 2,
                logging: false,
                useCORS: true
            });
            const imgData = canvas.toDataURL('image/png');
            const pdf = new jsPDF({
                orientation: 'landscape',
                unit: 'px',
                format: [canvas.width, canvas.height]
            });

            pdf.addImage(imgData, 'PNG', 0, 0, canvas.width, canvas.height);
            pdf.save('analytics-report.pdf');
        } catch (err) {
            console.error('PDF Export failed:', err);
            showToast('Failed to generate PDF', 'error');
        }
    };

    return (
        <div className="flex h-full min-h-0 w-full overflow-hidden bg-[#f6f7f8] dark:bg-[#101922] font-[family-name:var(--font-inter)]">


            <div className="flex-1 flex flex-col h-full min-h-0 overflow-auto">


                {/* Main Content */}
                <main id="analytics-dashboard" className="flex-1 p-4 md:p-8 max-w-[1600px] mx-auto w-full space-y-6 bg-[#f6f7f8] dark:bg-[#101922]">
                    {/* Page Header */}
                    <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
                        <div>
                            <h1 className="text-3xl font-black tracking-tight text-[#0d141b] dark:text-[#f3f4f6]">Analytics & Reports</h1>
                            <p className="text-[#4c739a] dark:text-[#9ca3af] mt-1 text-sm md:text-base">Overview of sales performance, product trends, and customer distribution.</p>
                        </div>
                        <div className="flex items-center gap-2">
                            {/* Date Range Picker */}
                            <div className="relative">
                                <button
                                    onClick={() => setShowDatePicker(p => !p)}
                                    className="flex items-center gap-2 px-3 py-2 bg-white dark:bg-[#1a2632] border border-[#e7edf3] dark:border-[#2b3a4a] rounded-lg text-sm font-medium text-[#0d141b] dark:text-[#f3f4f6] shadow-sm hover:bg-gray-50 dark:hover:bg-gray-800 transition-colors"
                                >
                                    <span className="material-symbols-outlined text-base">calendar_today</span>
                                    <span className="hidden sm:inline">{dateRange}</span>
                                    <span className="material-symbols-outlined text-base text-[#4c739a] dark:text-[#9ca3af]">arrow_drop_down</span>
                                </button>
                                {showDatePicker && (
                                    <div className="absolute right-0 top-full mt-2 z-50 bg-white dark:bg-[#1a2632] border border-[#e7edf3] dark:border-[#2b3a4a] rounded-xl shadow-xl p-4 flex flex-col gap-3" style={{ minWidth: '260px' }}>
                                        <p className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Select Date Range</p>
                                        <div className="flex flex-col gap-2">
                                            <label className="text-xs font-medium text-slate-700 dark:text-slate-300">From</label>
                                            <input
                                                type="date"
                                                value={startDate}
                                                max={endDate}
                                                onChange={e => setStartDate(e.target.value)}
                                                className="px-3 py-1.5 rounded-lg bg-slate-50 dark:bg-[#101922] border border-slate-200 dark:border-slate-700 text-sm text-slate-900 dark:text-white focus:ring-2 focus:ring-[#d41132] outline-none"
                                            />
                                        </div>
                                        <div className="flex flex-col gap-2">
                                            <label className="text-xs font-medium text-slate-700 dark:text-slate-300">To</label>
                                            <input
                                                type="date"
                                                value={endDate}
                                                min={startDate}
                                                max={new Date().toISOString().split('T')[0]}
                                                onChange={e => setEndDate(e.target.value)}
                                                className="px-3 py-1.5 rounded-lg bg-slate-50 dark:bg-[#101922] border border-slate-200 dark:border-slate-700 text-sm text-slate-900 dark:text-white focus:ring-2 focus:ring-[#d41132] outline-none"
                                            />
                                        </div>
                                        <div className="flex gap-2 pt-1">
                                            <button
                                                onClick={() => { setShowDatePicker(false); }}
                                                className="flex-1 py-1.5 text-xs font-bold text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg transition-colors"
                                            >Cancel</button>
                                            <button
                                                onClick={() => setShowDatePicker(false)}
                                                className="flex-1 py-1.5 text-xs font-bold bg-[#d41132] text-white rounded-lg hover:bg-[#b30f2a] transition-colors"
                                            >Apply</button>
                                        </div>
                                    </div>
                                )}
                            </div>
                            {/* Export Button */}
                            <button
                                onClick={handleDownloadPDF}
                                className="flex items-center gap-2 px-3 py-2 bg-[#d41132] hover:bg-[#b30f2a] text-white rounded-lg text-sm font-bold shadow-sm transition-all active:scale-95"
                            >
                                <span className="material-symbols-outlined text-base">download</span>
                                <span className="hidden sm:inline">Export PDF</span>
                            </button>
                        </div>
                    </div>

                    {/* KPI Cards Grid */}
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                        {/* Card 1 */}
                        <div className="bg-white dark:bg-[#1a2632] p-5 rounded-xl border border-[#e7edf3] dark:border-[#2b3a4a] shadow-sm flex flex-col gap-1">
                            <div className="flex justify-between items-start">
                                <p className="text-[#4c739a] dark:text-[#9ca3af] text-sm font-medium">Total Revenue</p>
                                <div className="p-1.5 bg-green-100 dark:bg-green-900/30 rounded text-green-700 dark:text-green-400">
                                    <span className="material-symbols-outlined text-sm">trending_up</span>
                                </div>
                            </div>
                            <div className="flex items-baseline gap-2 mt-2">
                                <h3 className="text-2xl font-bold text-[#0d141b] dark:text-[#f3f4f6]">${summary?.totalRevenue?.toLocaleString() ?? '0'}</h3>
                                <span className="text-sm font-semibold text-green-600 dark:text-green-400">+12%</span>
                            </div>
                            <p className="text-xs text-[#4c739a] dark:text-[#9ca3af] mt-1">Compared to last month</p>
                        </div>
                        {/* Card 2 */}
                        <div className="bg-white dark:bg-[#1a2632] p-5 rounded-xl border border-[#e7edf3] dark:border-[#2b3a4a] shadow-sm flex flex-col gap-1">
                            <div className="flex justify-between items-start">
                                <p className="text-[#4c739a] dark:text-[#9ca3af] text-sm font-medium">New Orders</p>
                                <div className="p-1.5 bg-green-100 dark:bg-green-900/30 rounded text-green-700 dark:text-green-400">
                                    <span className="material-symbols-outlined text-sm">trending_up</span>
                                </div>
                            </div>
                            <div className="flex items-baseline gap-2 mt-2">
                                <h3 className="text-2xl font-bold text-[#0d141b] dark:text-[#f3f4f6]">{summary?.totalOrders?.toLocaleString() ?? '0'}</h3>
                                <span className="text-sm font-semibold text-green-600 dark:text-green-400">+5%</span>
                            </div>
                            <p className="text-xs text-[#4c739a] dark:text-[#9ca3af] mt-1">Compared to last month</p>
                        </div>
                        {/* Card 3 */}
                        <div className="bg-white dark:bg-[#1a2632] p-5 rounded-xl border border-[#e7edf3] dark:border-[#2b3a4a] shadow-sm flex flex-col gap-1">
                            <div className="flex justify-between items-start">
                                <p className="text-[#4c739a] dark:text-[#9ca3af] text-sm font-medium">Avg. Order Value</p>
                                <div className="p-1.5 bg-blue-100 dark:bg-blue-900/30 rounded text-#a20e26 dark:text-#e85273">
                                    <span className="material-symbols-outlined text-sm">remove</span>
                                </div>
                            </div>
                            <div className="flex items-baseline gap-2 mt-2">
                                <h3 className="text-2xl font-bold text-[#0d141b] dark:text-[#f3f4f6]">${summary?.avgOrderValue ?? '0'}</h3>
                                <span className="text-sm font-semibold text-#b30f2a dark:text-#e85273">+2%</span>
                            </div>
                            <p className="text-xs text-[#4c739a] dark:text-[#9ca3af] mt-1">Stable performance</p>
                        </div>
                        {/* Card 4 */}
                        <div className="bg-white dark:bg-[#1a2632] p-5 rounded-xl border border-[#e7edf3] dark:border-[#2b3a4a] shadow-sm flex flex-col gap-1">
                            <div className="flex justify-between items-start">
                                <p className="text-[#4c739a] dark:text-[#9ca3af] text-sm font-medium">Total Returns</p>
                                <div className="p-1.5 bg-green-100 dark:bg-green-900/30 rounded text-green-700 dark:text-green-400">
                                    <span className="material-symbols-outlined text-sm">arrow_downward</span>
                                </div>
                            </div>
                            <div className="flex items-baseline gap-2 mt-2">
                                <h3 className="text-2xl font-bold text-[#0d141b] dark:text-[#f3f4f6]">{summary?.totalReturns ?? '0'}</h3>
                                <span className="text-sm font-semibold text-green-600 dark:text-green-400">-1.5%</span>
                            </div>
                            <p className="text-xs text-[#4c739a] dark:text-[#9ca3af] mt-1">Improvement in quality</p>
                        </div>
                    </div>

                    {/* Main Revenue Chart */}
                    <div className="bg-white dark:bg-[#1a2632] rounded-xl border border-[#e7edf3] dark:border-[#2b3a4a] shadow-sm p-6">
                        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-6 gap-4">
                            <div>
                                <h3 className="text-lg font-bold text-[#0d141b] dark:text-[#f3f4f6]">Revenue (Last 12 Months)</h3>
                                <p className="text-sm text-[#4c739a] dark:text-[#9ca3af]">Year over year growth: <span className="text-green-600 font-medium">+8.5%</span></p>
                            </div>
                            <div className="flex items-center gap-2">
                                <span className="size-3 rounded-full bg-[#d41132]"></span>
                                <span className="text-xs font-medium text-[#4c739a] dark:text-[#9ca3af] mr-3">Current Year</span>
                                <span className="size-3 rounded-full bg-gray-300 dark:bg-gray-600"></span>
                                <span className="text-xs font-medium text-[#4c739a] dark:text-[#9ca3af]">Previous Year</span>
                            </div>
                        </div>
                        <div className="relative w-full h-[300px] md:h-[350px]">
                            {/* CSS Bar Chart based on order status breakdown */}
                            {summary && Object.keys(summary.byStatus).length > 0 ? (
                                <div className="w-full h-full flex flex-col justify-end gap-2 pt-6 pb-2">
                                    <div className="flex items-end justify-around gap-3 h-full">
                                        {Object.entries(summary.byStatus).map(([status, count], i) => {
                                            const maxCount = Math.max(...Object.values(summary.byStatus));
                                            const heightPct = maxCount > 0 ? Math.max(10, (count / maxCount) * 100) : 10;
                                            const colors: Record<string, string> = {
                                                PENDING: 'bg-yellow-400',
                                                PROCESSING: 'bg-blue-400',
                                                SHIPPED: 'bg-purple-400',
                                                DELIVERED: 'bg-green-400',
                                                CANCELLED: 'bg-red-400',
                                            };
                                            return (
                                                <div key={status} className="flex flex-col items-center flex-1 gap-1 min-w-0">
                                                    <span className="text-xs font-bold text-slate-600 dark:text-slate-300">{count}</span>
                                                    <div
                                                        className={`w-full rounded-t-md transition-all duration-700 ${colors[status] ?? 'bg-slate-400'}`}
                                                        style={{ height: `${heightPct}%` }}
                                                    />
                                                    <span className="text-[10px] text-slate-500 dark:text-slate-400 text-center truncate w-full">{status.charAt(0) + status.slice(1).toLowerCase()}</span>
                                                </div>
                                            );
                                        })}
                                    </div>
                                </div>
                            ) : (
                                <div className="w-full h-full bg-[#f6f7f8] dark:bg-[#101922] rounded-lg flex flex-col items-center justify-center gap-2">
                                    <span className="material-symbols-outlined text-4xl text-slate-300 dark:text-slate-600">bar_chart</span>
                                    <p className="text-[#4c739a] dark:text-[#9ca3af] text-sm">No order data available yet.</p>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Charts Split Row */}
                    <div className="grid grid-cols-1 lg:grid-cols-1 sm:grid-cols-3 gap-6">
                        {/* Top Selling Products */}
                        <div className="lg:col-span-2 bg-white dark:bg-[#1a2632] rounded-xl border border-[#e7edf3] dark:border-[#2b3a4a] shadow-sm p-6">
                            <h3 className="text-lg font-bold text-[#0d141b] dark:text-[#f3f4f6] mb-6">Top Selling Products</h3>
                            <div className="space-y-6">
                                {topProducts.length > 0 ? topProducts.map((product, i) => (
                                    <div key={i} className="space-y-2">
                                        <div className="flex justify-between text-sm font-medium">
                                            <span className="text-[#0d141b] dark:text-[#f3f4f6]">{product.name}</span>
                                            <span className="text-[#4c739a] dark:text-[#9ca3af]">{product.sales} Sales</span>
                                        </div>
                                        <div className="h-2 w-full bg-[#f6f7f8] dark:bg-gray-700 rounded-full overflow-hidden">
                                            <div className="h-full bg-[#d41132] rounded-full" style={{ width: `${product.percentage}%`, opacity: 1 - i * 0.15 }}></div>
                                        </div>
                                    </div>
                                )) : (
                                    <p className="text-sm text-[#4c739a] dark:text-[#9ca3af]">No product data available</p>
                                )}
                            </div>
                        </div>

                        {/* Order Status */}
                        <div className="bg-white dark:bg-[#1a2632] rounded-xl border border-[#e7edf3] dark:border-[#2b3a4a] shadow-sm p-6 flex flex-col">
                            <h3 className="text-lg font-bold text-[#0d141b] dark:text-[#f3f4f6] mb-6">Order Status</h3>
                            <div className="flex flex-1 items-center justify-center relative my-4">
                                {/* Donut Chart Placeholder */}
                                <div className="size-[200px] rounded-full border-[40px] border-[#d41132] border-t-[#60a5fa] border-r-[#ef4444] flex items-center justify-center">
                                    <div className="flex flex-col items-center">
                                        <span className="text-2xl font-bold text-[#0d141b] dark:text-[#f3f4f6]">1.2K</span>
                                        <span className="text-xs text-[#4c739a] dark:text-[#9ca3af]">Orders</span>
                                    </div>
                                </div>
                            </div>
                            <div className="flex justify-center gap-4 mt-2">
                                <div className="flex items-center gap-2">
                                    <span className="size-3 rounded-full bg-[#d41132]"></span>
                                    <span className="text-xs font-medium text-[#4c739a] dark:text-[#9ca3af]">Delivered</span>
                                </div>
                                <div className="flex items-center gap-2">
                                    <span className="size-3 rounded-full bg-[#60a5fa]"></span>
                                    <span className="text-xs font-medium text-[#4c739a] dark:text-[#9ca3af]">Processing</span>
                                </div>
                                <div className="flex items-center gap-2">
                                    <span className="size-3 rounded-full bg-red-500"></span>
                                    <span className="text-xs font-medium text-[#4c739a] dark:text-[#9ca3af]">Returned</span>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* World Map Visualization */}
                    <div className="bg-white dark:bg-[#1a2632] rounded-xl border border-[#e7edf3] dark:border-[#2b3a4a] shadow-sm p-6">
                        <div className="flex flex-col sm:flex-row justify-between sm:items-center mb-6 gap-4">
                            <h3 className="text-lg font-bold text-[#0d141b] dark:text-[#f3f4f6]">Customers by Country</h3>
                            <div className="flex gap-2">
                                <span className="px-3 py-1 text-xs font-medium bg-[#d41132]/10 text-[#d41132] rounded-full">Global View</span>
                                <span className="px-3 py-1 text-xs font-medium bg-[#f6f7f8] dark:bg-gray-800 text-[#4c739a] dark:text-[#9ca3af] rounded-full cursor-pointer hover:bg-gray-200 dark:hover:bg-gray-700">North America</span>
                                <span className="px-3 py-1 text-xs font-medium bg-[#f6f7f8] dark:bg-gray-800 text-[#4c739a] dark:text-[#9ca3af] rounded-full cursor-pointer hover:bg-gray-200 dark:hover:bg-gray-700">Europe</span>
                            </div>
                        </div>
                        <div className="flex flex-col lg:flex-row gap-8">
                            {/* Map Graphic Placeholder */}
                            <div className="flex-1 relative bg-[#eef4ff] dark:bg-[#1f2d3d] rounded-lg min-h-[300px] overflow-hidden flex flex-col items-center justify-center gap-3">
                                <span className="material-symbols-outlined text-6xl text-blue-200 dark:text-blue-800">public</span>
                                <p className="text-[#4c739a] dark:text-[#9ca3af] text-sm font-medium">Customer Distribution</p>
                                {countries.length === 0 && (
                                    <p className="text-xs text-slate-400">No customer location data available</p>
                                )}
                                {countries.length > 0 && (
                                    <div className="w-full px-6 mt-2 space-y-2">
                                        {countries.map((c, i) => (
                                            <div key={i} className="flex items-center gap-2">
                                                <span className="text-base">{c.flag}</span>
                                                <div className="flex-1 h-2 bg-blue-100 dark:bg-blue-900/30 rounded-full overflow-hidden">
                                                    <div className="h-full bg-blue-400 dark:bg-blue-500 rounded-full" style={{ width: `${c.percentage}%` }} />
                                                </div>
                                                <span className="text-xs text-slate-500 w-8 text-right">{c.percentage}%</span>
                                            </div>
                                        ))}
                                    </div>
                                )}
                            </div>
                            {/* Country List */}
                            <div className="w-full lg:w-80 flex flex-col justify-center gap-4">
                                {countries.length > 0 ? countries.map((c, i) => (
                                    <div key={i} className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 p-3 bg-[#f6f7f8] dark:bg-[#101922] rounded-lg">
                                        <div className="flex items-center gap-3">
                                            <span className="text-lg">{c.flag}</span>
                                            <span className="text-sm font-medium text-[#0d141b] dark:text-[#f3f4f6]">{c.country}</span>
                                        </div>
                                        <span className="text-sm font-bold text-[#0d141b] dark:text-[#f3f4f6]">{c.percentage}%</span>
                                    </div>
                                )) : (
                                    <p className="text-sm text-[#4c739a] dark:text-[#9ca3af] text-center">No customer data available</p>
                                )}
                            </div>
                        </div>
                    </div>
                </main>
            </div>
        </div>
    );
}

'use client';

import { useState, useEffect, useCallback, useRef } from 'react';
import { useToast } from '@/contexts/ToastContext';
import AdminPageLayout from '@/components/admin/shared/AdminPageLayout';
import AdminTable from '@/components/admin/shared/AdminTable';
import AdminPagination from '@/components/admin/shared/AdminPagination';
import AdminBulkActionsBar from '@/components/admin/shared/AdminBulkActionsBar';
import ConfirmModal from '@/components/admin/ConfirmModal';

interface Category {
    id: string;
    name: string;
    slug: string;
    image_url: string | null;
    display_order: number;
    is_visible: boolean;
    product_count?: number;
}

const emptyForm = { name: '', slug: '', image_url: '', display_order: '0', is_visible: true };

export default function AdminCategoriesPage() {
    const [categories, setCategories] = useState<Category[]>([]);
    const [loading, setLoading] = useState(true);
    const [isUploading, setIsUploading] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [showModal, setShowModal] = useState(false);
    const [editingCategory, setEditingCategory] = useState<Category | null>(null);
    const [form, setForm] = useState(emptyForm);
    const [saving, setSaving] = useState(false);
    const { showToast } = useToast();
    const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
    const [isBulkDeleting, setIsBulkDeleting] = useState(false);
    const [currentPage, setCurrentPage] = useState(1);
    const [itemsPerPage, setItemsPerPage] = useState(10);
    const [searchQuery, setSearchQuery] = useState('');
    const [activeMenu, setActiveMenu] = useState<string | null>(null);
    const [confirmModal, setConfirmModal] = useState<{
        isOpen: boolean;
        title: string;
        message: string;
        onConfirm: () => void;
    }>({
        isOpen: false,
        title: '',
        message: '',
        onConfirm: () => { },
    });

    // Close menu when clicking outside
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            const target = event.target as Element;
            if (activeMenu && !target.closest('.action-menu-trigger') && !target.closest('.action-menu')) {
                setActiveMenu(null);
            }
        };
        document.addEventListener('click', handleClickOutside);
        return () => document.removeEventListener('click', handleClickOutside);
    }, [activeMenu]);

    const toggleMenu = (id: string, e: React.MouseEvent) => {
        e.stopPropagation();
        setActiveMenu(activeMenu === id ? null : id);
    };

    const loadCategories = useCallback(async () => {
        setLoading(true);
        const res = await fetch('/api/categories');
        const data = await res.json();
        if (data.success) setCategories(data.data);
        setLoading(false);
    }, []);

    useEffect(() => { loadCategories(); }, [loadCategories]);

    const generateSlug = (name: string) => name.toLowerCase().replace(/[^a-z0-9\s-]/g, '').replace(/\s+/g, '-');

    const openCreate = () => { setEditingCategory(null); setForm(emptyForm); setShowModal(true); };
    const openEdit = (c: Category) => {
        setEditingCategory(c);
        setForm({ name: c.name, slug: c.slug, image_url: c.image_url || '', display_order: String(c.display_order), is_visible: c.is_visible });
        setShowModal(true);
    };

    const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        setIsUploading(true);
        try {
            const formData = new FormData();
            formData.append('file', file);
            const res = await fetch('/api/media', { method: 'POST', body: formData });
            const data = await res.json();
            if (!data.success) throw new Error(data.message);
            setForm(f => ({ ...f, image_url: data.url }));
        } catch (error) {
            console.error('Upload failed:', error);
            showToast('Failed to upload image', 'error');
        } finally {
            setIsUploading(false);
        }
    };

    const handleSave = async () => {
        setSaving(true);
        const payload = { name: form.name, slug: form.slug || generateSlug(form.name), image_url: form.image_url || null, display_order: parseInt(form.display_order), is_visible: form.is_visible };
        const method = editingCategory ? 'PUT' : 'POST';
        const url = editingCategory ? `/api/categories?id=${editingCategory.id}` : '/api/categories';
        const res = await fetch(url, { method, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
        const data = await res.json();
        if (data.success) { showToast(editingCategory ? `Category "${form.name}" updated successfully.` : `Category "${form.name}" created successfully.`, 'success'); setShowModal(false); loadCategories(); }
        else showToast(data.message || 'Failed to save category.', 'error');
        setSaving(false);
    };

    const handleDelete = async (id: string) => {
        const cat = categories.find(c => c.id === id);
        setConfirmModal({
            isOpen: true,
            title: `Delete Category "${cat?.name}"`,
            message: 'Products in this category won\'t be deleted, but they\'ll lose their category assignment.',
            onConfirm: async () => {
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
                const res = await fetch(`/api/categories?id=${id}`, { method: 'DELETE' });
                const data = await res.json();
                if (data.success) { showToast(`Category "${cat?.name}" was deleted successfully.`, 'success'); loadCategories(); }
                else showToast(`Failed to delete category "${cat?.name}".`, 'error');
            }
        });
    };

    const handleBulkDelete = async () => {
        if (isBulkDeleting || selectedIds.size === 0) return;
        setConfirmModal({
            isOpen: true,
            title: 'Delete Categories',
            message: `Are you sure you want to delete ${selectedIds.size} categories? This action cannot be undone.`,
            onConfirm: async () => {
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
                setIsBulkDeleting(true);
                try {
                    const results = await Promise.all(
                        Array.from(selectedIds).map(id =>
                            fetch(`/api/categories?id=${id}`, { method: 'DELETE' }).then(res => res.json())
                        )
                    );
                    const successCount = results.filter(r => r.success).length;
                    const failCount = selectedIds.size - successCount;
                    if (failCount > 0) {
                        showToast(`Bulk delete finished. ${successCount} deleted, ${failCount} failed.`, 'error');
                    } else {
                        showToast(`${successCount} categories were deleted successfully.`, 'success');
                    }
                    loadCategories();
                    setSelectedIds(new Set());
                } catch (err) {
                    showToast('An error occurred during bulk deletion.', 'error');
                } finally {
                    setIsBulkDeleting(false);
                }
            }
        });
    };

    const toggleSelectAll = () => {
        const visibleItems = filteredCategories.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);
        const allVisibleSelected = visibleItems.every(c => selectedIds.has(c.id));

        setSelectedIds(prev => {
            const next = new Set(prev);
            if (allVisibleSelected) {
                visibleItems.forEach(c => next.delete(c.id));
            } else {
                visibleItems.forEach(c => next.add(c.id));
            }
            return next;
        });
    };

    const toggleSelect = (id: string) => {
        setSelectedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            return next;
        });
    };

    const filteredCategories = categories.filter(cat =>
        cat.name.toLowerCase().includes(searchQuery.toLowerCase())
    );

    return (
        <AdminPageLayout
            title="Categories"
            subtitle="Manage product categories shown in the shop filters"
            stats={
                <>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Total</p>
                        <p className="text-base font-black text-[#0d141b] dark:text-white leading-none mt-0.5">{categories.length}</p>
                    </div>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Visible</p>
                        <p className="text-base font-black text-[#0d141b] dark:text-white leading-none mt-0.5">{categories.filter(c => c.is_visible).length}</p>
                    </div>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Hidden</p>
                        <p className="text-base font-black text-[#0d141b] dark:text-white leading-none mt-0.5">{categories.filter(c => !c.is_visible).length}</p>
                    </div>
                </>
            }
            actions={
                <button onClick={openCreate} className="flex items-center gap-2 bg-[#d41132] hover:bg-[#b30f2a] text-white px-5 py-2.5 rounded-xl font-bold text-sm transition-all shadow-sm hover:shadow-md">
                    <span className="material-symbols-outlined text-[18px]">add</span> Add Category
                </button>
            }
            filters={
                <div className="flex-1 min-w-[200px] relative">
                    <span className="absolute left-3 top-2.5 text-black/40 dark:text-white/40 material-symbols-outlined text-[20px]">search</span>
                    <input type="text" placeholder="Search categories..." value={searchQuery}
                        onChange={(e) => { setSearchQuery(e.target.value); setCurrentPage(1); }}
                        className="w-full pl-10 pr-4 py-2 rounded-lg bg-white dark:bg-[#1a2632] border border-[#e5e7eb] dark:border-[#2d3b4a] focus:ring-2 focus:ring-[#d41132] outline-none transition-all dark:text-white text-sm" />
                </div>
            }
            pagination={
                <AdminPagination
                    currentPage={currentPage}
                    totalItems={filteredCategories.length}
                    itemsPerPage={itemsPerPage}
                    onPageChange={setCurrentPage}
                    onItemsPerPageChange={(val) => {
                        setItemsPerPage(val);
                        setCurrentPage(1);
                    }}
                />
            }
            bulkActions={
                <AdminBulkActionsBar
                    selectedCount={selectedIds.size}
                    onCancel={() => setSelectedIds(new Set())}
                    onDelete={handleBulkDelete}
                    isDeleting={isBulkDeleting}
                />
            }
        >
            <AdminTable
                headers={['Image', 'Category Name', 'Slug', 'Order', 'Products', 'Status', 'Actions']}
                onSelectAll={toggleSelectAll}
                isAllSelected={filteredCategories.length > 0 && filteredCategories.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage).every(c => selectedIds.has(c.id))}
            >
                {loading ? (
                    <tr>
                        <td colSpan={8} className="px-6 py-8 text-center text-gray-500">
                            <div className="flex items-center justify-center gap-2">
                                <span className="material-symbols-outlined animate-spin">progress_activity</span>
                                Loading categories...
                            </div>
                        </td>
                    </tr>
                ) : filteredCategories.length === 0 ? (
                    <tr>
                        <td colSpan={8} className="px-6 py-8 text-center text-gray-500">
                            No categories found.
                        </td>
                    </tr>
                ) : (
                    filteredCategories.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage).map((cat) => (
                        <tr key={cat.id} className={`group hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors ${selectedIds.has(cat.id) ? 'bg-[#d41132]/5 dark:bg-[#d41132]/10' : ''}`}>
                            <td className="py-4 px-6" onClick={(e) => e.stopPropagation()}>
                                <input
                                    type="checkbox"
                                    className="rounded border-slate-300 text-[#d41132] focus:ring-[#d41132] bg-transparent cursor-pointer"
                                    checked={selectedIds.has(cat.id)}
                                    onChange={() => toggleSelect(cat.id)}
                                />
                            </td>
                            <td className="py-3 px-6">
                                <div className="w-12 h-12 rounded-lg overflow-hidden bg-slate-100 dark:bg-slate-700 border border-slate-200 dark:border-slate-600">
                                    {cat.image_url ? <img src={cat.image_url} alt={cat.name} className="w-full h-full object-cover" /> : (
                                        <div className="w-full h-full flex items-center justify-center text-slate-300">
                                            <span className="material-symbols-outlined text-xl">category</span>
                                        </div>
                                    )}
                                </div>
                            </td>
                            <td className="py-3 px-6">
                                <div>
                                    <p className="font-bold text-slate-900 dark:text-white leading-tight">{cat.name}</p>
                                </div>
                            </td>
                            <td className="py-3 px-6">
                                <span className="font-mono text-xs text-slate-500 uppercase font-bold tracking-wider">/{cat.slug}</span>
                            </td>
                            <td className="py-3 px-6">
                                <span className="bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-300 px-2 py-0.5 rounded text-xs font-black">{cat.display_order}</span>
                            </td>
                            <td className="py-3 px-6">
                                <span className="text-sm font-black text-slate-900 dark:text-white">{cat.product_count || 0}</span>
                            </td>
                            <td className="py-3 px-6">
                                <span className={`px-2 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${cat.is_visible ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400' : 'bg-slate-100 text-slate-500 dark:bg-slate-700 dark:text-slate-400'}`}>
                                    {cat.is_visible ? 'Visible' : 'Hidden'}
                                </span>
                            </td>
                            <td className="px-6 py-4 text-right relative">
                                <button onClick={(e) => toggleMenu(cat.id, e)}
                                    className="action-menu-trigger text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 p-1 rounded-full hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors">
                                    <span className="material-symbols-outlined">more_vert</span>
                                </button>
                                {activeMenu === cat.id && (
                                    <div className="absolute right-8 top-12 z-20 w-48 bg-white dark:bg-slate-800 rounded-lg shadow-lg border border-slate-200 dark:border-slate-700 py-1 action-menu animate-in zoom-in-95 duration-150 origin-top-right">
                                        <button onClick={() => { openEdit(cat); setActiveMenu(null); }} className="w-full text-left px-4 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700 flex items-center gap-2">
                                            <span className="material-symbols-outlined text-lg">edit</span> Edit
                                        </button>
                                        <div className="h-px bg-slate-100 dark:bg-slate-700 my-1"></div>
                                        <button onClick={() => { handleDelete(cat.id); setActiveMenu(null); }} className="w-full text-left px-4 py-2 text-sm text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 flex items-center gap-2">
                                            <span className="material-symbols-outlined text-lg">delete</span> Delete
                                        </button>
                                    </div>
                                )}
                            </td>
                        </tr>
                    ))
                )}
            </AdminTable>

            {/* Create/Edit Modal */}
            {showModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-in fade-in duration-200">
                    <div className="bg-white dark:bg-slate-800 rounded-2xl w-full max-w-lg shadow-2xl border border-slate-200 dark:border-slate-700 animate-in zoom-in-95 duration-200">
                        <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 p-6 border-b border-slate-200 dark:border-slate-700">
                            <h2 className="text-lg font-black text-slate-900 dark:text-white">{editingCategory ? 'Edit Category' : 'New Category'}</h2>
                            <button onClick={() => setShowModal(false)} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg transition-colors">
                                <span className="material-symbols-outlined">close</span>
                            </button>
                        </div>
                        <div className="p-6 space-y-4">
                            <div>
                                <label className="block text-xs font-bold uppercase tracking-widest text-slate-500 mb-1.5">Name *</label>
                                <input value={form.name} onChange={e => setForm(f => ({ ...f, name: e.target.value, slug: generateSlug(e.target.value) }))} placeholder="Leather Jackets" className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm focus:border-[#d41132] outline-none dark:text-white" />
                            </div>
                            <div>
                                <label className="block text-xs font-bold uppercase tracking-widest text-slate-500 mb-1.5">Slug</label>
                                <input value={form.slug} onChange={e => setForm(f => ({ ...f, slug: e.target.value }))} placeholder="leather-jackets" className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm font-mono focus:border-[#d41132] outline-none dark:text-white" />
                            </div>
                            <div>
                                <label className="block text-xs font-bold uppercase tracking-widest text-slate-500 mb-1.5">Image</label>
                                <div className="flex gap-2">
                                    <input value={form.image_url} onChange={e => setForm(f => ({ ...f, image_url: e.target.value }))} placeholder="https://..." className="flex-1 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm focus:border-[#d41132] outline-none dark:text-white" />
                                    <input type="file" ref={fileInputRef} onChange={handleImageUpload} className="hidden" accept="image/*" />
                                    <button
                                        type="button"
                                        onClick={() => fileInputRef.current?.click()}
                                        disabled={isUploading}
                                        className="px-4 py-2 bg-slate-100 dark:bg-slate-700 hover:bg-slate-200 dark:hover:bg-slate-600 rounded-lg transition-colors flex items-center justify-center text-slate-600 dark:text-slate-300"
                                    >
                                        {isUploading ? (
                                            <span className="material-symbols-outlined animate-spin text-sm">refresh</span>
                                        ) : (
                                            <span className="material-symbols-outlined text-sm">cloud_upload</span>
                                        )}
                                    </button>
                                </div>
                                {form.image_url && (
                                    <div className="mt-2 w-16 h-16 rounded-lg overflow-hidden border border-slate-200 dark:border-slate-600">
                                        <img src={form.image_url} alt="Preview" className="w-full h-full object-cover" />
                                    </div>
                                )}
                            </div>
                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-xs font-bold uppercase tracking-widest text-slate-500 mb-1.5">Display Order</label>
                                    <input type="number" value={form.display_order} onChange={e => setForm(f => ({ ...f, display_order: e.target.value }))} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm focus:border-[#d41132] outline-none dark:text-white" />
                                </div>
                                <div className="flex items-end pb-0.5">
                                    <label className="flex items-center gap-3 cursor-pointer">
                                        <div onClick={() => setForm(f => ({ ...f, is_visible: !f.is_visible }))} className={`relative w-11 h-6 rounded-full transition-all ${form.is_visible ? 'bg-green-500' : 'bg-slate-300 dark:bg-slate-600'}`}>
                                            <span className={`absolute top-0.5 left-0.5 w-5 h-5 bg-white rounded-full shadow transition-transform ${form.is_visible ? 'translate-x-5' : ''}`} />
                                        </div>
                                        <span className="text-sm font-medium text-slate-700 dark:text-slate-300">Visible</span>
                                    </label>
                                </div>
                            </div>
                        </div>
                        <div className="flex gap-3 p-6 border-t border-slate-200 dark:border-slate-700">
                            <button onClick={() => setShowModal(false)} className="flex-1 py-2.5 rounded-xl border border-slate-200 dark:border-slate-600 text-slate-600 dark:text-slate-300 font-bold text-sm hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors">Cancel</button>
                            <button onClick={handleSave} disabled={saving || !form.name} className="flex-1 py-2.5 rounded-xl bg-[#d41132] hover:bg-[#b30f2a] text-white font-bold text-sm transition-colors disabled:opacity-50">
                                {saving ? 'Saving...' : (editingCategory ? 'Save Changes' : 'Create Category')}
                            </button>
                        </div>
                    </div>
                </div>
            )}

            <ConfirmModal
                isOpen={confirmModal.isOpen}
                title={confirmModal.title}
                message={confirmModal.message}
                onConfirm={confirmModal.onConfirm}
                onCancel={() => setConfirmModal(prev => ({ ...prev, isOpen: false }))}
            />
        </AdminPageLayout>
    );
}

"use client";

import { useState, useEffect } from "react";
import { contentService, CMSContent } from "@/lib/services/contentService";
import AdminFilterTabs from "@/components/admin/shared/AdminFilterTabs";

export default function CMSAdminPage() {
    const [content, setContent] = useState<CMSContent[]>([]);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState<string | null>(null);
    const [message, setMessage] = useState<{ text: string; type: 'success' | 'error' } | null>(null);
    const [activeCategory, setActiveCategory] = useState('announcement');

    useEffect(() => {
        loadContent();
    }, []);

    const loadContent = async () => {
        try {
            const data = await contentService.getAll();
            setContent(data);
        } catch (error) {
            setMessage({ text: "Failed to load content", type: 'error' });
        } finally {
            setLoading(false);
        }
    };

    const handleUpdate = async (id: string, newContent: string) => {
        setSaving(id);
        setMessage(null);
        try {
            await contentService.updateContent(id, newContent);
            setContent(prev => prev.map(item => item.id === id ? { ...item, content: newContent } : item));
            setMessage({ text: "Content updated successfully!", type: 'success' });
        } catch (error) {
            setMessage({ text: "Failed to update content", type: 'error' });
        } finally {
            setSaving(null);
        }
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center min-h-[400px]">
                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-[#c27a2a]"></div>
            </div>
        );
    }

    const categories = [
        { name: 'Global / Header', prefix: 'announcement' },
        { name: 'Home Page', prefix: 'home' },
        { name: 'Bespoke Experience', prefix: 'bespoke' },
        { name: 'Shipping & Fit Guide', prefix: 'shipping' }
    ];

    return (
        <div className="p-8 max-w-6xl mx-auto font-[family-name:var(--font-inter)]">
            <div className="flex justify-between items-center mb-10">
                <div>
                    <h1 className="text-3xl font-black text-slate-900 uppercase tracking-tight">Content Management</h1>
                    <p className="text-slate-500 mt-1">Directly control headings, text, and buttons across the storefront.</p>
                </div>
                {message && (
                    <div className={`px-4 py-2 rounded-lg text-sm font-bold animate-in fade-in slide-in-from-top-2 ${message.type === 'success' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                        {message.text}
                    </div>
                )}
            </div>

            <div className="mb-8">
                <AdminFilterTabs
                    tabs={categories.map(cat => ({ label: cat.name, value: cat.prefix }))}
                    activeTab={activeCategory}
                    onTabChange={setActiveCategory}
                />
            </div>

            <div className="space-y-12">
                {categories.filter(cat => cat.prefix === activeCategory).map((cat) => (
                    <section key={cat.name} className="space-y-6">
                        <div className="flex items-center gap-4">
                            <h2 className="text-lg font-black uppercase tracking-widest text-[#c27a2a]">{cat.name}</h2>
                            <div className="flex-1 h-px bg-slate-100"></div>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            {content
                                .filter(item => item.slug.startsWith(cat.prefix))
                                .map((item) => (
                                    <div key={item.id} className="bg-white rounded-2xl p-6 border border-slate-100 shadow-sm hover:shadow-md transition-shadow">
                                        <div className="flex justify-between items-start mb-4">
                                            <div>
                                                <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">{item.slug}</p>
                                                <h3 className="font-bold text-slate-700 mt-1">{item.description}</h3>
                                            </div>
                                            <span className="bg-slate-50 text-[10px] px-2 py-1 rounded font-bold text-slate-400 uppercase">{item.contentType}</span>
                                        </div>

                                        <div className="relative">
                                            {item.contentType === 'text' || item.contentType === 'html' ? (
                                                <textarea
                                                    className="w-full bg-slate-50 border-2 border-transparent focus:border-[#c27a2a] outline-none rounded-xl p-4 text-sm font-medium transition-all min-h-[100px] resize-none"
                                                    defaultValue={item.content}
                                                    onBlur={(e) => {
                                                        if (e.target.value !== item.content) {
                                                            handleUpdate(item.id, e.target.value);
                                                        }
                                                    }}
                                                />
                                            ) : (
                                                <input
                                                    type="text"
                                                    className="w-full bg-slate-50 border-2 border-transparent focus:border-[#c27a2a] outline-none rounded-xl p-4 text-sm font-medium transition-all"
                                                    defaultValue={item.content}
                                                    onBlur={(e) => {
                                                        if (e.target.value !== item.content) {
                                                            handleUpdate(item.id, e.target.value);
                                                        }
                                                    }}
                                                />
                                            )}
                                            {saving === item.id && (
                                                <div className="absolute inset-0 bg-white/60 backdrop-blur-[1px] flex items-center justify-center rounded-xl">
                                                    <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-[#c27a2a]"></div>
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                ))}
                        </div>
                    </section>
                ))}
            </div>

            <div className="mt-16 pt-8 border-t border-slate-100 text-center">
                <p className="text-xs text-slate-400 font-medium">CMS version 1.0 • Changes are applied immediately to the live production site.</p>
            </div>
        </div>
    );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { useToast } from '@/contexts/ToastContext';
import AdminPageLayout from '@/components/admin/shared/AdminPageLayout';
import AdminFilterTabs from '@/components/admin/shared/AdminFilterTabs';
import AdminTable from '@/components/admin/shared/AdminTable';
import AdminPagination from '@/components/admin/shared/AdminPagination';
import AdminBulkActionsBar from '@/components/admin/shared/AdminBulkActionsBar';
import ConfirmModal from '@/components/admin/ConfirmModal';

interface Coupon {
    id: string;
    code: string;
    discount_type: 'percentage' | 'flat';
    value: number;
    min_order_amount: number | null;
    max_uses: number | null;
    uses_count: number;
    is_active: boolean;
    expiry_date: string | null;
    created_at: string;
}

const emptyForm: { code: string; discount_type: 'percentage' | 'flat'; value: string; min_order_amount: string; max_uses: string; expiry_date: string; is_active: boolean } = {
    code: '', discount_type: 'percentage', value: '', min_order_amount: '', max_uses: '', expiry_date: '', is_active: true
};

export default function AdminCouponsPage() {
    const [coupons, setCoupons] = useState<Coupon[]>([]);
    const [loading, setLoading] = useState(true);
    const [showModal, setShowModal] = useState(false);
    const [editingCoupon, setEditingCoupon] = useState<Coupon | null>(null);
    const [form, setForm] = useState(emptyForm);
    const [saving, setSaving] = useState(false);
    const { showToast } = useToast();
    const [statusFilter, setStatusFilter] = useState<'all' | 'active' | 'inactive'>('all');
    const [activeMenu, setActiveMenu] = useState<string | null>(null);
    const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
    const [isBulkDeleting, setIsBulkDeleting] = useState(false);
    const [currentPage, setCurrentPage] = useState(1);
    const [itemsPerPage, setItemsPerPage] = useState(10);
    const [confirmModal, setConfirmModal] = useState<{
        isOpen: boolean;
        title: string;
        message: string;
        onConfirm: () => void;
    }>({
        isOpen: false,
        title: '',
        message: '',
        onConfirm: () => { },
    });

    // Close menu when clicking outside
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            const target = event.target as Element;
            if (activeMenu && !target.closest('.action-menu-trigger') && !target.closest('.action-menu')) {
                setActiveMenu(null);
            }
        };
        document.addEventListener('click', handleClickOutside);
        return () => document.removeEventListener('click', handleClickOutside);
    }, [activeMenu]);

    const toggleMenu = (id: string, e: React.MouseEvent) => {
        e.stopPropagation();
        setActiveMenu(activeMenu === id ? null : id);
    };

    const loadCoupons = useCallback(async () => {
        setLoading(true);
        const res = await fetch('/api/coupons/admin');
        const data = await res.json();
        if (data.success) setCoupons(data.data);
        setLoading(false);
    }, []);

    useEffect(() => { loadCoupons(); }, [loadCoupons]);

    const openCreate = () => { setEditingCoupon(null); setForm(emptyForm); setShowModal(true); };
    const openEdit = (c: Coupon) => {
        setEditingCoupon(c);
        setForm({
            code: c.code, discount_type: c.discount_type,
            value: String(c.value), min_order_amount: String(c.min_order_amount || ''),
            max_uses: String(c.max_uses || ''),
            expiry_date: c.expiry_date ? c.expiry_date.split('T')[0] : '',
            is_active: c.is_active
        });
        setShowModal(true);
    };

    const handleSave = async () => {
        setSaving(true);
        const payload = {
            code: form.code.toUpperCase(),
            discount_type: form.discount_type,
            value: parseFloat(form.value),
            min_order_amount: form.min_order_amount ? parseFloat(form.min_order_amount) : null,
            max_uses: form.max_uses ? parseInt(form.max_uses) : null,
            expiry_date: form.expiry_date || null,
            is_active: form.is_active,
        };
        const method = editingCoupon ? 'PUT' : 'POST';
        const url = editingCoupon ? `/api/coupons/admin?id=${editingCoupon.id}` : '/api/coupons/admin';
        const res = await fetch(url, { method, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
        const data = await res.json();
        if (data.success) { showToast(editingCoupon ? `Coupon "${form.code}" updated successfully.` : `Coupon "${form.code}" created successfully.`, 'success'); setShowModal(false); loadCoupons(); }
        else showToast(data.message || 'Failed to save coupon.', 'error');
        setSaving(false);
    };

    const handleDelete = async (id: string) => {
        const coupon = coupons.find(c => c.id === id);
        setConfirmModal({
            isOpen: true,
            title: `Delete Coupon "${coupon?.code}"`,
            message: 'Are you sure you want to delete this coupon? This action cannot be undone.',
            onConfirm: async () => {
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
                const res = await fetch(`/api/coupons/admin?id=${id}`, { method: 'DELETE' });
                const data = await res.json();
                if (data.success) { showToast(`Coupon "${coupon?.code}" was deleted successfully.`, 'success'); loadCoupons(); }
                else showToast(`Failed to delete coupon "${coupon?.code}".`, 'error');
            }
        });
    };

    const toggleActive = async (c: Coupon) => {
        const res = await fetch(`/api/coupons/admin?id=${c.id}`, {
            method: 'PUT', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ ...c, is_active: !c.is_active })
        });
        if (res.ok) {
            showToast(`Coupon "${c.code}" is now ${!c.is_active ? 'active' : 'inactive'}.`, 'success');
        } else {
            showToast(`Failed to update status for coupon "${c.code}".`, 'error');
        }
        loadCoupons();
    };

    const filteredCoupons = coupons.filter(c => {
        if (statusFilter === 'active') return c.is_active;
        if (statusFilter === 'inactive') return !c.is_active;
        return true;
    });

    const handleBulkDelete = async () => {
        if (isBulkDeleting || selectedIds.size === 0) return;
        setConfirmModal({
            isOpen: true,
            title: 'Delete Coupons',
            message: `Are you sure you want to delete ${selectedIds.size} coupons? This action cannot be undone.`,
            onConfirm: async () => {
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
                setIsBulkDeleting(true);
                try {
                    const results = await Promise.all(
                        Array.from(selectedIds).map(id =>
                            fetch(`/api/coupons/admin?id=${id}`, { method: 'DELETE' }).then(res => res.json())
                        )
                    );
                    const successCount = results.filter(r => r.success).length;
                    const failCount = selectedIds.size - successCount;
                    if (failCount > 0) {
                        showToast(`Bulk delete finished. ${successCount} deleted, ${failCount} failed.`, 'error');
                    } else {
                        showToast(`${successCount} coupons were deleted successfully.`, 'success');
                    }
                    loadCoupons();
                    setSelectedIds(new Set());
                } catch (err) {
                    showToast('An error occurred during bulk deletion.', 'error');
                } finally {
                    setIsBulkDeleting(false);
                }
            }
        });
    };

    const toggleSelectAll = () => {
        const visibleCoupons = filteredCoupons.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);
        const allVisibleSelected = visibleCoupons.every(c => selectedIds.has(c.id));

        setSelectedIds(prev => {
            const next = new Set(prev);
            if (allVisibleSelected) {
                visibleCoupons.forEach(c => next.delete(c.id));
            } else {
                visibleCoupons.forEach(c => next.add(c.id));
            }
            return next;
        });
    };

    const toggleSelect = (id: string) => {
        setSelectedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            return next;
        });
    };

    return (
        <AdminPageLayout
            title="Coupons"
            subtitle="Create and manage discount codes for your storefront"
            actions={
                <button onClick={openCreate} className="flex items-center gap-2 bg-[#d41132] hover:bg-[#b30f2a] text-white px-5 py-2.5 rounded-xl font-bold text-sm transition-all shadow-sm hover:shadow-md">
                    <span className="material-symbols-outlined text-[18px]">add</span> New Coupon
                </button>
            }
            filters={
                <AdminFilterTabs
                    tabs={[
                        { label: 'All Coupons', value: 'all' },
                        { label: 'Active', value: 'active' },
                        { label: 'Inactive', value: 'inactive' },
                    ]}
                    activeTab={statusFilter}
                    onTabChange={(val) => setStatusFilter(val as any)}
                />
            }
            pagination={
                <AdminPagination
                    currentPage={currentPage}
                    totalItems={filteredCoupons.length}
                    itemsPerPage={itemsPerPage}
                    onPageChange={setCurrentPage}
                    onItemsPerPageChange={(val) => {
                        setItemsPerPage(val);
                        setCurrentPage(1);
                    }}
                />
            }
            stats={
                <>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Total Coupons</p>
                        <p className="text-base font-black text-[#0d141b] dark:text-white leading-none mt-0.5">{coupons.length}</p>
                    </div>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Active</p>
                        <p className="text-base font-black text-[#0d141b] dark:text-white leading-none mt-0.5">{coupons.filter(c => c.is_active).length}</p>
                    </div>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Inactive</p>
                        <p className="text-base font-black text-[#0d141b] dark:text-white leading-none mt-0.5">{coupons.filter(c => !c.is_active).length}</p>
                    </div>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Total Uses</p>
                        <p className="text-base font-black text-[#0d141b] dark:text-white leading-none mt-0.5">{coupons.reduce((sum, c) => sum + (c.uses_count || 0), 0)}</p>
                    </div>
                </>
            }
            bulkActions={
                <AdminBulkActionsBar
                    selectedCount={selectedIds.size}
                    onCancel={() => setSelectedIds(new Set())}
                    onDelete={handleBulkDelete}
                    isDeleting={isBulkDeleting}
                />
            }
        >
            <AdminTable
                headers={['Code', 'Type', 'Value', 'Min. Order', 'Uses', 'Expiry', 'Status', 'Actions']}
                onSelectAll={toggleSelectAll}
                isAllSelected={filteredCoupons.length > 0 && filteredCoupons.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage).every(c => selectedIds.has(c.id))}
            >
                {loading ? (
                    <tr>
                        <td colSpan={9} className="py-12 text-center text-slate-500 dark:text-slate-400 font-bold">
                            <div className="flex items-center justify-center gap-2">
                                <span className="material-symbols-outlined animate-spin">progress_activity</span>
                                Loading coupons...
                            </div>
                        </td>
                    </tr>
                ) : filteredCoupons.length === 0 ? (
                    <tr>
                        <td colSpan={9} className="py-12 text-center text-slate-500 dark:text-slate-400">
                            No codes found.
                        </td>
                    </tr>
                ) : (
                    filteredCoupons.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage).map((c) => (
                        <tr key={c.id} className={`group hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors ${selectedIds.has(c.id) ? 'bg-[#d41132]/5 dark:bg-[#d41132]/10' : ''}`}>
                            <td className="py-4 px-6" onClick={(e) => e.stopPropagation()}>
                                <input
                                    type="checkbox"
                                    className="rounded border-slate-300 text-[#d41132] focus:ring-[#d41132] bg-transparent cursor-pointer"
                                    checked={selectedIds.has(c.id)}
                                    onChange={() => toggleSelect(c.id)}
                                />
                            </td>
                            <td className="px-4 py-4"><span className="font-mono font-bold text-slate-900 dark:text-white bg-slate-100 dark:bg-slate-700 px-2 py-1 rounded text-xs">{c.code}</span></td>
                            <td className="px-4 py-4 capitalize text-slate-600 dark:text-slate-300">{c.discount_type}</td>
                            <td className="px-4 py-4 font-bold text-slate-900 dark:text-white">{c.discount_type === 'percentage' ? `${c.value}%` : `$${c.value}`}</td>
                            <td className="px-4 py-4 text-slate-500 dark:text-slate-400 font-medium">{c.min_order_amount ? `$${c.min_order_amount}` : '—'}</td>
                            <td className="px-4 py-4 text-slate-500 dark:text-slate-400 font-medium">{c.uses_count || 0}{c.max_uses ? `/${c.max_uses}` : ''}</td>
                            <td className="px-4 py-4 text-slate-500 dark:text-slate-400 font-medium">{c.expiry_date ? new Date(c.expiry_date).toLocaleDateString() : '—'}</td>
                            <td className="px-4 py-4">
                                <button onClick={() => toggleActive(c)} className={`px-2.5 py-1 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${c.is_active ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400' : 'bg-slate-100 text-slate-500 dark:bg-slate-700 dark:text-slate-400'}`}>
                                    {c.is_active ? 'Active' : 'Inactive'}
                                </button>
                            </td>
                            <td className="px-4 py-4 text-right relative">
                                <button
                                    onClick={(e) => toggleMenu(c.id, e)}
                                    className="action-menu-trigger text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 p-1 rounded-full hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors"
                                >
                                    <span className="material-symbols-outlined">more_vert</span>
                                </button>
                                {activeMenu === c.id && (
                                    <div className="absolute right-8 top-12 z-20 w-48 bg-white dark:bg-slate-800 rounded-lg shadow-lg border border-slate-200 dark:border-slate-700 py-1 action-menu animate-in zoom-in-95 duration-150 origin-top-right">
                                        <button onClick={() => { toggleActive(c); setActiveMenu(null); }} className="w-full text-left px-4 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700 flex items-center gap-2">
                                            <span className="material-symbols-outlined text-lg">{c.is_active ? 'toggle_off' : 'toggle_on'}</span> {c.is_active ? 'Deactivate' : 'Activate'}
                                        </button>
                                        <button onClick={() => { openEdit(c); setActiveMenu(null); }} className="w-full text-left px-4 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700 flex items-center gap-2">
                                            <span className="material-symbols-outlined text-lg">edit</span> Edit
                                        </button>
                                        <div className="h-px bg-slate-100 dark:bg-slate-700 my-1"></div>
                                        <button onClick={() => { handleDelete(c.id); setActiveMenu(null); }} className="w-full text-left px-4 py-2 text-sm text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 flex items-center gap-2">
                                            <span className="material-symbols-outlined text-lg">delete</span> Delete
                                        </button>
                                    </div>
                                )}
                            </td>
                        </tr>
                    ))
                )}
            </AdminTable>

            {/* Create/Edit Modal */}
            {showModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-in fade-in duration-200">
                    <div className="bg-white dark:bg-slate-800 rounded-2xl w-full max-w-lg shadow-2xl border border-slate-200 dark:border-slate-700 animate-in zoom-in-95 duration-200">
                        <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 p-6 border-b border-slate-200 dark:border-slate-700">
                            <h2 className="text-lg font-black text-slate-900 dark:text-white">{editingCoupon ? 'Edit Coupon' : 'Create Coupon'}</h2>
                            <button onClick={() => setShowModal(false)} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg transition-colors">
                                <span className="material-symbols-outlined">close</span>
                            </button>
                        </div>
                        <div className="p-6 space-y-4">
                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-xs font-bold uppercase tracking-widest text-slate-500 mb-1.5">Code *</label>
                                    <input value={form.code} onChange={e => setForm(f => ({ ...f, code: e.target.value.toUpperCase() }))} placeholder="SUMMER25" className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm font-mono uppercase focus:border-[#d41132] outline-none" />
                                </div>
                                <div>
                                    <label className="block text-xs font-bold uppercase tracking-widest text-slate-500 mb-1.5">Type *</label>
                                    <select value={form.discount_type} onChange={e => setForm(f => ({ ...f, discount_type: e.target.value as any }))} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm focus:border-[#d41132] outline-none">
                                        <option value="percentage">Percentage (%)</option>
                                        <option value="flat">Flat Amount ($)</option>
                                    </select>
                                </div>
                            </div>
                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-xs font-bold uppercase tracking-widest text-slate-500 mb-1.5">Value *</label>
                                    <input type="number" value={form.value} onChange={e => setForm(f => ({ ...f, value: e.target.value }))} placeholder={form.discount_type === 'percentage' ? '10' : '25'} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm focus:border-[#d41132] outline-none" />
                                </div>
                                <div>
                                    <label className="block text-xs font-bold uppercase tracking-widest text-slate-500 mb-1.5">Min. Order ($)</label>
                                    <input type="number" value={form.min_order_amount} onChange={e => setForm(f => ({ ...f, min_order_amount: e.target.value }))} placeholder="50" className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm focus:border-[#d41132] outline-none" />
                                </div>
                            </div>
                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-xs font-bold uppercase tracking-widest text-slate-500 mb-1.5">Max Uses</label>
                                    <input type="number" value={form.max_uses} onChange={e => setForm(f => ({ ...f, max_uses: e.target.value }))} placeholder="Unlimited" className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm focus:border-[#d41132] outline-none" />
                                </div>
                                <div>
                                    <label className="block text-xs font-bold uppercase tracking-widest text-slate-500 mb-1.5">Expiry Date</label>
                                    <input type="date" value={form.expiry_date} onChange={e => setForm(f => ({ ...f, expiry_date: e.target.value }))} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm focus:border-[#d41132] outline-none" />
                                </div>
                            </div>
                            <div className="flex items-center gap-3">
                                <button onClick={() => setForm(f => ({ ...f, is_active: !f.is_active }))} className={`relative w-12 h-6 rounded-full transition-all ${form.is_active ? 'bg-green-500' : 'bg-slate-300 dark:bg-slate-600'}`}>
                                    <span className={`absolute top-0.5 left-0.5 w-5 h-5 bg-white rounded-full shadow transition-transform ${form.is_active ? 'translate-x-6' : ''}`} />
                                </button>
                                <span className="text-sm font-medium text-slate-700 dark:text-slate-300">{form.is_active ? 'Active' : 'Inactive'}</span>
                            </div>
                        </div>
                        <div className="flex gap-3 p-6 border-t border-slate-200 dark:border-slate-700">
                            <button onClick={() => setShowModal(false)} className="flex-1 py-2.5 rounded-xl border border-slate-200 dark:border-slate-600 text-slate-600 dark:text-slate-300 font-bold text-sm hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors">Cancel</button>
                            <button onClick={handleSave} disabled={saving || !form.code || !form.value} className="flex-1 py-2.5 rounded-xl bg-[#d41132] hover:bg-[#b30f2a] text-white font-bold text-sm transition-colors disabled:opacity-50">
                                {saving ? 'Saving...' : (editingCoupon ? 'Save Changes' : 'Create Coupon')}
                            </button>
                        </div>
                    </div>
                </div>
            )}

            <ConfirmModal
                isOpen={confirmModal.isOpen}
                title={confirmModal.title}
                message={confirmModal.message}
                onConfirm={confirmModal.onConfirm}
                onCancel={() => setConfirmModal(prev => ({ ...prev, isOpen: false }))}
            />
        </AdminPageLayout>
    );
}

'use client';

import { useEffect, useState } from 'react';
import AdminPageLayout from '@/components/admin/shared/AdminPageLayout';
import AdminTable from '@/components/admin/shared/AdminTable';
import AdminPagination from '@/components/admin/shared/AdminPagination';
import AdminBulkActionsBar from '@/components/admin/shared/AdminBulkActionsBar';
import { useToast } from '@/contexts/ToastContext';
import { Customer } from '@/lib/supabase';
import AdminFilterTabs from '@/components/admin/shared/AdminFilterTabs';


// Extended type matching API response
interface CustomerWithStats extends Customer {
    ordersCount: number;
    totalSpent: number;
}

import AdminCustomerModal, { pCustomer } from '@/components/admin/AdminCustomerModal';
import ConfirmModal from '@/components/admin/ConfirmModal';
import CustomerViewDrawer from '@/components/admin/CustomerViewDrawer';

export default function AdminCustomersPage() {
    const { showToast } = useToast();
    const [customers, setCustomers] = useState<CustomerWithStats[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [selectedSegment, setSelectedSegment] = useState('all');
    const [currentPage, setCurrentPage] = useState(1);
    const [itemsPerPage, setItemsPerPage] = useState(10);

    // Modal State
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingCustomer, setEditingCustomer] = useState<Customer | null>(null);
    const [viewingCustomer, setViewingCustomer] = useState<CustomerWithStats | null>(null);
    const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
    const [isBulkDeleting, setIsBulkDeleting] = useState(false);
    const [isMounted, setIsMounted] = useState(false);
    const [confirmModal, setConfirmModal] = useState<{
        isOpen: boolean;
        title: string;
        message: string;
        onConfirm: () => void;
    }>({
        isOpen: false,
        title: '',
        message: '',
        onConfirm: () => { },
    });

    useEffect(() => {
        setIsMounted(true);
    }, []);

    useEffect(() => {
        loadCustomers();
    }, []);

    const loadCustomers = async () => {
        try {
            // Fetching a large limit to support client-side filtering for now (Pilot Phase)
            const res = await fetch('/api/customers?limit=1000');
            const data = await res.json();

            if (data.success) {
                setCustomers(data.data);
            } else {
                console.error('Failed to load customers:', data.error);
            }
        } catch (error) {
            console.error('Failed to load customers data:', error);
        } finally {
            setLoading(false);
        }
    };

    const handleSearch = async (query: string) => {
        setSearchQuery(query);
        // Client-side filtering active
    };

    const filteredCustomers = customers.filter(c => {
        const matchesSearch = c.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
            c.email.toLowerCase().includes(searchQuery.toLowerCase());

        if (!matchesSearch) return false;

        if (selectedSegment === 'all') return true;
        if (selectedSegment === 'vip') return c.totalSpent > 500;
        if (selectedSegment === 'repeat') return c.ordersCount > 1;
        if (selectedSegment === 'wholesale') return false; // Placeholder

        return true;
    });

    const [activeMenu, setActiveMenu] = useState<string | null>(null);

    // Close menu when clicking outside
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            const target = event.target as Element;
            if (activeMenu && !target.closest('.action-menu-trigger') && !target.closest('.action-menu')) {
                setActiveMenu(null);
            }
        };
        document.addEventListener('click', handleClickOutside);
        return () => document.removeEventListener('click', handleClickOutside);
    }, [activeMenu]);

    const handleExport = () => {
        const headers = ['ID', 'Name', 'Email', 'Phone', 'Location', 'Created At'];
        const csvContent = [
            headers.join(','),
            ...customers.map(customer => [
                customer.id,
                `"${customer.name}"`,
                customer.email,
                customer.phone || '',
                `"${[customer.city, customer.country].filter(Boolean).join(', ') || ''}"`,
                new Date(customer.createdAt).toLocaleDateString()
            ].join(','))
        ].join('\n');

        const blob = new Blob([csvContent], { type: 'text/csv' });
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `customers-export-${new Date().toISOString().split('T')[0]}.csv`;
        a.click();
        window.URL.revokeObjectURL(url);
    };

    const handleDeleteCustomer = async (id: string) => {
        if (isBulkDeleting) return;

        const customer = customers.find(c => c.id === id);
        if (!customer) return;

        setConfirmModal({
            isOpen: true,
            title: `Delete ${customer.name}`,
            message: `Are you sure you want to delete "${customer.name}"? To comply with GDPR and preserve financial history, their personal data will be permanently anonymized. This cannot be undone.`,
            onConfirm: async () => {
                try {
                    const res = await fetch(`/api/customers/${id}`, {
                        method: 'DELETE',
                    });

                    if (!res.ok) throw new Error('Failed to delete customer');

                    // Optimistic update
                    setCustomers(customers.filter(c => c.id !== id));
                    setSelectedIds(prev => {
                        const next = new Set(prev);
                        next.delete(id);
                        return next;
                    });
                    showToast(`"${customer.name}" was successfully deleted (anonymized).`, 'success');
                } catch (error) {
                    console.error('Error deleting customer:', error);
                    showToast(`Failed to delete "${customer.name}". Please try again.`, 'error');
                    loadCustomers(); // Refresh on error
                } finally {
                    setConfirmModal(prev => ({ ...prev, isOpen: false }));
                }
            }
        });
    };

    const handleBulkDelete = async () => {
        if (isBulkDeleting || selectedIds.size === 0) return;

        const count = selectedIds.size;
        setConfirmModal({
            isOpen: true,
            title: `Delete ${count} Customers`,
            message: `Are you sure you want to delete ${count} selected customers? To preserve financial history, their personal data will be permanently anonymized. This action cannot be undone.`,
            onConfirm: async () => {
                setIsBulkDeleting(true);
                const idsToDelete = Array.from(selectedIds);
                let successCount = 0;
                let failCount = 0;

                try {
                    await Promise.all(idsToDelete.map(async (id) => {
                        try {
                            const res = await fetch(`/api/customers/${id}`, { method: 'DELETE' });
                            if (res.ok) successCount++;
                            else failCount++;
                        } catch (err) {
                            failCount++;
                        }
                    }));

                    if (successCount > 0) {
                        setCustomers(prev => prev.filter(c => !selectedIds.has(c.id)));
                        setSelectedIds(new Set());
                    }

                    if (failCount > 0) {
                        showToast(`Bulk delete finished with errors. Deleted (Anonymized): ${successCount}, Failed: ${failCount}`, 'error');
                    } else {
                        showToast(`Successfully deleted and anonymized ${successCount} customers.`, 'success');
                    }
                } catch (error) {
                    console.error('Bulk delete error:', error);
                    showToast('An error occurred during bulk deletion.', 'error');
                } finally {
                    setIsBulkDeleting(false);
                    setConfirmModal(prev => ({ ...prev, isOpen: false }));
                    loadCustomers();
                }
            }
        });
    };

    const toggleSelectAll = () => {
        const visibleIds = filteredCustomers.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage).map(c => c.id);
        const allVisibleSelected = visibleIds.every(id => selectedIds.has(id));

        setSelectedIds(prev => {
            const next = new Set(prev);
            if (allVisibleSelected) {
                visibleIds.forEach(id => next.delete(id));
            } else {
                visibleIds.forEach(id => next.add(id));
            }
            return next;
        });
    };

    const toggleSelect = (id: string) => {
        setSelectedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            return next;
        });
    };

    const handleCreateCustomer = async (data: pCustomer) => {
        try {
            const res = await fetch('/api/customers', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(data),
            });
            const result = await res.json();

            if (result.success) {
                await loadCustomers();
                setIsModalOpen(false);
                showToast(`"${data.name}" has been added successfully.`, 'success');
            } else {
                showToast('Failed to add customer: ' + (result.error || result.message), 'error');
            }
        } catch (error) {
            console.error('Error creating customer:', error);
            showToast('An error occurred while adding the customer.', 'error');
        }
    };

    const handleUpdateCustomer = async (data: pCustomer) => {
        if (!editingCustomer) return;
        try {
            const res = await fetch(`/api/customers/${editingCustomer.id}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(data),
            });
            const result = await res.json();

            if (result.success) {
                await loadCustomers();
                setIsModalOpen(false);
                setEditingCustomer(null);
                showToast(`"${data.name}"'s profile has been updated.`, 'success');
            } else {
                showToast('Failed to update customer: ' + result.error, 'error');
            }
        } catch (error) {
            console.error('Error updating customer:', error);
            showToast(`An error occurred while updating the customer.`, 'error');
        }
    };

    const openCreateModal = () => {
        setEditingCustomer(null);
        setIsModalOpen(true);
    };

    const openEditModal = (customer: Customer) => {
        setEditingCustomer(customer);
        setIsModalOpen(true);
    };

    const toggleMenu = (customerId: string, e: React.MouseEvent) => {
        e.stopPropagation();
        setActiveMenu(activeMenu === customerId ? null : customerId);
    };

    return (
        <AdminPageLayout
            title="Customer Management"
            subtitle="Manage and view your customer database, track spending, and segment users."
            stats={
                <>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Total Customers</p>
                        <p className="text-base font-black text-[#0d141b] dark:text-white leading-none mt-0.5">{customers.length}</p>
                    </div>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">VIP (&gt;$500)</p>
                        <p className="text-base font-black text-[#0d141b] dark:text-white leading-none mt-0.5">{customers.filter(c => c.totalSpent > 500).length}</p>
                    </div>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Repeat Buyers</p>
                        <p className="text-base font-black text-[#0d141b] dark:text-white leading-none mt-0.5">{customers.filter(c => c.ordersCount > 1).length}</p>
                    </div>
                </>
            }
            actions={
                <div className="flex gap-3">
                    <button
                        onClick={handleExport}
                        className="flex items-center gap-2 px-4 py-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg text-slate-700 dark:text-slate-200 font-medium text-sm hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors"
                    >
                        <span className="material-symbols-outlined text-lg">download</span>
                        Export CSV
                    </button>
                    <button
                        onClick={openCreateModal}
                        className="flex items-center gap-2 px-4 py-2 bg-[#d41132] text-white rounded-lg font-medium text-sm hover:bg-[#b30f2a] transition-colors shadow-sm shadow-red-200 dark:shadow-none">
                        <span className="material-symbols-outlined text-lg">add</span>
                        Add Customer
                    </button>
                </div>
            }
            filters={
                <div className="flex flex-col lg:flex-row justify-between items-center gap-4 w-full">
                    {/* Search */}
                    <div className="relative w-full lg:w-full md:w-96 group">
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                            <span className="material-symbols-outlined text-slate-400">search</span>
                        </div>
                        <input
                            className="block w-full pl-10 pr-3 py-2.5 border-none rounded-lg bg-slate-100 dark:bg-slate-800 text-slate-900 dark:text-white placeholder-slate-500 dark:placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-[#d41132]/50 text-sm transition-all"
                            placeholder="Search by name, email, or order ID..."
                            type="text"
                            value={searchQuery}
                            onChange={(e) => handleSearch(e.target.value)}
                        />
                    </div>
                    {/* Segment Pills */}
                    <AdminFilterTabs
                        tabs={[
                            { label: 'All Customers', value: 'all' },
                            { label: 'VIP', value: 'vip' },
                            { label: 'Repeat Buyers', value: 'repeat' },
                            { label: 'Wholesale', value: 'wholesale' },
                        ]}
                        activeTab={selectedSegment}
                        onTabChange={setSelectedSegment}
                    />
                </div>
            }
            pagination={
                <AdminPagination
                    currentPage={currentPage}
                    totalItems={filteredCustomers.length}
                    itemsPerPage={itemsPerPage}
                    onPageChange={setCurrentPage}
                    onItemsPerPageChange={(val) => {
                        setItemsPerPage(val);
                        setCurrentPage(1);
                    }}
                />
            }
            bulkActions={
                <AdminBulkActionsBar
                    selectedCount={selectedIds.size}
                    onCancel={() => setSelectedIds(new Set())}
                    onDelete={handleBulkDelete}
                    isDeleting={isBulkDeleting}
                />
            }
        >
            <AdminTable
                headers={['Customer', 'Contact', 'Location', 'Orders', 'Total Spent', 'Created', 'Actions']}
                onSelectAll={toggleSelectAll}
                isAllSelected={filteredCustomers.length > 0 && filteredCustomers.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage).every(c => selectedIds.has(c.id))}
            >
                {loading ? (
                    <tr>
                        <td colSpan={8} className="py-12 text-center text-slate-500 dark:text-slate-400 font-bold">
