'use client';

import { useState, useEffect, useCallback } from 'react';
import { contentService } from '@/lib/services/contentService';
import AdminFilterTabs from '@/components/admin/shared/AdminFilterTabs';

const sections = [
    {
        id: 'hero', title: 'Hero Section', icon: 'photo_library',
        fields: [
            { key: 'home_hero_title', label: 'Hero Title', type: 'text', placeholder: 'Crafted for the World' },
            { key: 'home_hero_subtitle', label: 'Hero Subtitle', type: 'textarea', placeholder: 'Premium leather goods...' },
            { key: 'home_hero_cta', label: 'CTA Button Text', type: 'text', placeholder: 'Shop Collection' },
            { key: 'home_hero_image', label: 'Background Image URL', type: 'url', placeholder: 'https://...' },
        ]
    },
    {
        id: 'announcement', title: 'Announcement Bar', icon: 'campaign',
        fields: [
            { key: 'announcement_text', label: 'Primary Announcement', type: 'text', placeholder: 'Free Worldwide Shipping on orders over $150' },
            { key: 'announcement_2', label: 'Second Announcement', type: 'text', placeholder: 'Bespoke Orders Available | 12-15 Days' },
            { key: 'announcement_3', label: 'Third Announcement', type: 'text', placeholder: 'Quality that Lasts a Lifetime' },
        ]
    },
    {
        id: 'featured', title: 'Featured Section', icon: 'grade',
        fields: [
            { key: 'home_featured_title', label: 'Section Title', type: 'text', placeholder: 'Featured Collections' },
            { key: 'home_featured_subtitle', label: 'Section Subtitle', type: 'textarea', placeholder: 'Timeless pieces crafted with precision...' },
        ]
    },
    {
        id: 'testimonials', title: 'Testimonials', icon: 'format_quote',
        fields: [
            { key: 'home_testimonials_title', label: 'Section Title', type: 'text', placeholder: 'Stories from our Customers' },
        ]
    },
    {
        id: 'seo', title: 'SEO & Metadata', icon: 'manage_search',
        fields: [
            { key: 'home_meta_title', label: 'Page Title (SEO)', type: 'text', placeholder: 'Luxe Leather Co. | Handcrafted Premium Leather Goods' },
            { key: 'home_meta_description', label: 'Meta Description', type: 'textarea', placeholder: 'Discover handcrafted premium leather...' },
        ]
    }
];

export default function AdminHomepagePage() {
    const [content, setContent] = useState<Record<string, string>>({});
    const [saving, setSaving] = useState<Record<string, boolean>>({});
    const [savedKeys, setSavedKeys] = useState<Set<string>>(new Set());
    const [activeSection, setActiveSection] = useState('hero');
    const [loading, setLoading] = useState(true);

    const loadContent = useCallback(async () => {
        setLoading(true);
        const allKeys = sections.flatMap(s => s.fields.map(f => f.key));
        const result: Record<string, string> = {};
        await Promise.all(allKeys.map(async key => {
            result[key] = await contentService.getBySlug(key);
        }));
        setContent(result);
        setLoading(false);
    }, []);

    useEffect(() => { loadContent(); }, [loadContent]);

    const handleChange = (key: string, value: string) => {
        setContent(prev => ({ ...prev, [key]: value }));
    };

    const handleSave = async (key: string, value: string) => {
        setSaving(prev => ({ ...prev, [key]: true }));
        await contentService.updateContent(key, value);
        setSaving(prev => ({ ...prev, [key]: false }));
        setSavedKeys(prev => { const s = new Set(prev); s.add(key); return s; });
        setTimeout(() => setSavedKeys(prev => { const s = new Set(prev); s.delete(key); return s; }), 2000);
    };

    const activeFields = sections.find(s => s.id === activeSection)?.fields || [];

    return (
        <main className="flex-1 overflow-y-auto bg-[#f6f7f8] dark:bg-[#101922] p-6 md:p-8">
            <div className="mb-8">
                <h1 className="text-2xl font-black text-slate-900 dark:text-white">Homepage Builder</h1>
                <p className="text-slate-500 dark:text-slate-400 text-sm mt-1">Edit every section of the homepage in real-time — changes reflect instantly on the live site</p>
            </div>

            <div className="mb-6">
                <AdminFilterTabs
                    tabs={sections.map(s => ({ label: s.title, value: s.id }))}
                    activeTab={activeSection}
                    onTabChange={setActiveSection}
                />
            </div>

            <div className="flex flex-col gap-6">
                {/* Fields */}
                <div className="flex-1">
                    <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 p-6">
                        <h2 className="text-lg font-black text-slate-900 dark:text-white mb-6 flex items-center gap-2">
                            <span className="material-symbols-outlined text-[#d41132]">{sections.find(s => s.id === activeSection)?.icon}</span>
                            {sections.find(s => s.id === activeSection)?.title}
                        </h2>
                        {loading ? (
                            <div className="flex items-center justify-center py-12">
                                <span className="material-symbols-outlined animate-spin text-3xl text-slate-400">progress_activity</span>
                            </div>
                        ) : (
                            <div className="space-y-6">
                                {activeFields.map(field => (
                                    <div key={field.key}>
                                        <label className="block text-xs font-bold uppercase tracking-widest text-slate-500 dark:text-slate-400 mb-2">{field.label}</label>
                                        {field.type === 'textarea' ? (
                                            <textarea
                                                value={content[field.key] || ''}
                                                onChange={e => handleChange(field.key, e.target.value)}
                                                rows={3}
                                                placeholder={field.placeholder}
                                                className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-600 rounded-xl px-4 py-3 text-sm focus:border-[#d41132] outline-none resize-none dark:text-white transition-colors"
                                            />
                                        ) : (
                                            <input
                                                type={field.type || 'text'}
                                                value={content[field.key] || ''}
                                                onChange={e => handleChange(field.key, e.target.value)}
                                                placeholder={field.placeholder}
                                                className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-600 rounded-xl px-4 py-3 text-sm focus:border-[#d41132] outline-none dark:text-white transition-colors"
                                            />
                                        )}
                                        <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 mt-2">
                                            <p className="text-[10px] text-slate-400 font-mono">{field.key}</p>
                                            <button
                                                onClick={() => handleSave(field.key, content[field.key] || '')}
                                                disabled={saving[field.key]}
                                                className={`flex items-center gap-1.5 px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${savedKeys.has(field.key) ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400' : 'bg-[#d41132]/10 text-[#d41132] hover:bg-[#d41132] hover:text-white'}`}
                                            >
                                                {saving[field.key] ? (
                                                    <><span className="material-symbols-outlined text-[14px] animate-spin">progress_activity</span> Saving</>
                                                ) : savedKeys.has(field.key) ? (
                                                    <><span className="material-symbols-outlined text-[14px]">check</span> Saved</>
                                                ) : 'Save'}
                                            </button>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </main>
    );
}

'use client';

import { useState, useEffect, useCallback, useRef } from 'react';
import AdminPageLayout from '@/components/admin/shared/AdminPageLayout';
import AdminTable from '@/components/admin/shared/AdminTable';
import AdminPagination from '@/components/admin/shared/AdminPagination';
import AdminBulkActionsBar from '@/components/admin/shared/AdminBulkActionsBar';

import { useToast } from '@/contexts/ToastContext';
import ConfirmModal from '@/components/admin/ConfirmModal';

interface MediaFile {
    name: string;
    url: string;
    size: number;
    created_at: string;
}

export default function AdminMediaPage() {
    const { showToast } = useToast();
    const [files, setFiles] = useState<MediaFile[]>([]);
    const [loading, setLoading] = useState(true);
    const [uploading, setUploading] = useState(false);
    const [copiedUrl, setCopiedUrl] = useState<string | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const [currentPage, setCurrentPage] = useState(1);
    const [itemsPerPage, setItemsPerPage] = useState(10);

    const [searchQuery, setSearchQuery] = useState('');
    const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
    const [isBulkDeleting, setIsBulkDeleting] = useState(false);
    const [activeMenu, setActiveMenu] = useState<string | null>(null);

    const [confirmModal, setConfirmModal] = useState<{
        isOpen: boolean;
        title: string;
        message: string;
        onConfirm: () => void;
    }>({
        isOpen: false,
        title: '',
        message: '',
        onConfirm: () => { },
    });

    // Close menu when clicking outside
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            const target = event.target as Element;
            if (activeMenu && !target.closest('.action-menu-trigger') && !target.closest('.action-menu')) {
                setActiveMenu(null);
            }
        };
        document.addEventListener('click', handleClickOutside);
        return () => document.removeEventListener('click', handleClickOutside);
    }, [activeMenu]);

    const toggleMenu = (fileName: string, e: React.MouseEvent) => {
        e.stopPropagation();
        setActiveMenu(activeMenu === fileName ? null : fileName);
    };

    const load = useCallback(async () => {
        setLoading(true);
        const res = await fetch('/api/media');
        const data = await res.json();
        if (data.success) setFiles(data.data);
        setLoading(false);
    }, []);

    useEffect(() => { load(); }, [load]);

    const handleUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        setUploading(true);
        const formData = new FormData();
        formData.append('file', file);
        const res = await fetch('/api/media', { method: 'POST', body: formData });
        const data = await res.json();
        if (data.success) { showToast(`Image "${file.name}" uploaded successfully.`, 'success'); load(); }
        else showToast(data.message || 'Image upload failed.', 'error');
        setUploading(false);
        if (fileInputRef.current) fileInputRef.current.value = '';
    };

    const copyUrl = (url: string) => {
        navigator.clipboard.writeText(url);
        setCopiedUrl(url);
        showToast('Image URL copied to clipboard.', 'success');
        setTimeout(() => setCopiedUrl(null), 2000);
    };

    const handleDelete = async (name: string) => {
        if (isBulkDeleting) return;

        setConfirmModal({
            isOpen: true,
            title: `Delete Image "${name}"`,
            message: 'Delete this image permanently? This action cannot be undone and may break links in your site.',
            onConfirm: async () => {
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
                const res = await fetch(`/api/media?name=${encodeURIComponent(name)}`, { method: 'DELETE' });
                if ((await res.json()).success) {
                    showToast(`Image "${name}" was deleted successfully.`, 'success');
                    setFiles(prev => prev.filter(f => f.name !== name));
                    setSelectedIds(prev => {
                        const next = new Set(prev);
                        next.delete(name);
                        return next;
                    });
                } else {
                    showToast(`Failed to delete image "${name}".`, 'error');
                }
            }
        });
    };

    const handleBulkDelete = async () => {
        if (isBulkDeleting || selectedIds.size === 0) return;

        const count = selectedIds.size;
        setConfirmModal({
            isOpen: true,
            title: `Delete ${count} Images`,
            message: `Are you sure you want to delete ${count} images? This action cannot be undone.`,
            onConfirm: async () => {
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
                setIsBulkDeleting(true);
                const namesToDelete = Array.from(selectedIds);
                let successCount = 0;
                let failCount = 0;

                try {
                    await Promise.all(namesToDelete.map(async (name) => {
                        try {
                            const res = await fetch(`/api/media?name=${encodeURIComponent(name)}`, { method: 'DELETE' });
                            if ((await res.json()).success) successCount++;
                            else failCount++;
                        } catch (err) {
                            failCount++;
                        }
                    }));

                    if (successCount > 0) {
                        setFiles(prev => prev.filter(f => !selectedIds.has(f.name)));
                        setSelectedIds(new Set());
                    }

                    if (failCount > 0) {
                        showToast(`Bulk delete finished. ${successCount} deleted, ${failCount} failed.`, 'error');
                    } else {
                        showToast(`${successCount} images were deleted successfully.`, 'success');
                    }
                } catch (error) {
                    console.error('Bulk delete error:', error);
                    showToast('An error occurred during bulk deletion.', 'error');
                } finally {
                    setIsBulkDeleting(false);
                    load(); // Refresh to ensure sync
                }
            }
        });
    };

    const toggleSelectAll = () => {
        const visibleNames = filteredFiles.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage).map(f => f.name);
        const allVisibleSelected = visibleNames.every(name => selectedIds.has(name));

        setSelectedIds(prev => {
            const next = new Set(prev);
            if (allVisibleSelected) {
                visibleNames.forEach(name => next.delete(name));
            } else {
                visibleNames.forEach(name => next.add(name));
            }
            return next;
        });
    };

    const toggleSelect = (name: string) => {
        setSelectedIds(prev => {
            const next = new Set(prev);
            if (next.has(name)) next.delete(name);
            else next.add(name);
            return next;
        });
    };

    const formatSize = (bytes: number) => bytes < 1024 * 1024 ? `${(bytes / 1024).toFixed(0)}KB` : `${(bytes / (1024 * 1024)).toFixed(1)}MB`;

    const filteredFiles = files.filter(file =>
        file.name.toLowerCase().includes(searchQuery.toLowerCase())
    );

    // Calculate stats
    const totalSize = files.reduce((acc, f) => acc + f.size, 0);

    return (
        <AdminPageLayout
            title="Media Library"
            subtitle={`${files.length} images \u00b7 Upload and manage image assets`}
            actions={
                <>
                    <input ref={fileInputRef} type="file" accept="image/*" onChange={handleUpload} className="hidden" />
                    <button
                        onClick={() => fileInputRef.current?.click()}
                        disabled={uploading}
                        className="flex items-center gap-2 px-4 py-2 bg-[#d41132] hover:bg-[#b30f2a] text-white text-sm font-bold rounded-lg shadow-md transition-colors disabled:opacity-60"
                    >
                        {uploading ? (
                            <><span className="material-symbols-outlined text-[20px] animate-spin">progress_activity</span> Uploading...</>
                        ) : (
                            <><span className="material-symbols-outlined text-[20px]">upload</span> Upload Image</>
                        )}
                    </button>
                </>
            }
            stats={
                <>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Total Images</p>
                        <p className="text-base font-black text-[#0d141b] dark:text-white leading-none mt-0.5">{files.length}</p>
                    </div>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Total Size</p>
                        <p className="text-base font-black text-[#0d141b] dark:text-white leading-none mt-0.5">{formatSize(totalSize)}</p>
                    </div>
                </>
            }
            filters={
                <div className="flex-1 min-w-[200px] relative">
                    <span className="absolute left-3 top-2.5 text-black/40 dark:text-white/40 material-symbols-outlined text-[20px]">search</span>
                    <input type="text" placeholder="Search media..." value={searchQuery}
                        onChange={(e) => { setSearchQuery(e.target.value); setCurrentPage(1); }}
                        className="w-full pl-10 pr-4 py-2 rounded-lg bg-white dark:bg-[#1a2632] border border-[#e5e7eb] dark:border-[#2d3b4a] focus:ring-2 focus:ring-[#d41132] outline-none transition-all dark:text-white text-sm" />
                </div>
            }
            pagination={
                <AdminPagination
                    currentPage={currentPage}
                    totalItems={filteredFiles.length}
                    itemsPerPage={itemsPerPage}
                    onPageChange={setCurrentPage}
                    onItemsPerPageChange={(val) => {
                        setItemsPerPage(val);
                        setCurrentPage(1);
                    }}
                />
            }
            bulkActions={
                <AdminBulkActionsBar
                    selectedCount={selectedIds.size}
                    onCancel={() => setSelectedIds(new Set())}
                    onDelete={handleBulkDelete}
                    isDeleting={isBulkDeleting}
                />
            }
        >
            <AdminTable
                headers={['Preview', 'Filename', 'Size', 'Actions']}
                onSelectAll={toggleSelectAll}
                isAllSelected={filteredFiles.length > 0 && filteredFiles.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage).every(f => selectedIds.has(f.name))}
            >
                {loading ? (
                    <tr>
                        <td colSpan={5} className="px-6 py-8 text-center text-gray-500">
                            <div className="flex items-center justify-center gap-2">
                                <span className="material-symbols-outlined animate-spin">progress_activity</span>
                                Loading media...
                            </div>
                        </td>
                    </tr>
                ) : filteredFiles.length === 0 ? (
                    <tr>
                        <td colSpan={5} className="px-6 py-8 text-center text-gray-500">
                            No images found.
                        </td>
                    </tr>
                ) : (
                    filteredFiles.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage).map((file) => (
                        <tr key={file.name} className={`hover:bg-[#f6f7f8] dark:hover:bg-[#17202b] transition-colors group ${selectedIds.has(file.name) ? 'bg-[#d41132]/5 dark:bg-[#d41132]/10' : ''}`}>
                            <td className="px-6 py-4" onClick={(e) => e.stopPropagation()}>
                                <input
                                    type="checkbox"
                                    className="rounded border-slate-300 text-[#d41132] focus:ring-[#d41132] bg-transparent cursor-pointer"
                                    checked={selectedIds.has(file.name)}
                                    onChange={() => toggleSelect(file.name)}
                                />
                            </td>
                            <td className="px-6 py-4">
                                <img src={file.url} alt={file.name} className="w-10 h-10 rounded-lg object-cover" />
                            </td>
                            <td className="px-6 py-4">
                                <p className="font-bold text-slate-900 dark:text-white text-sm truncate">{file.name}</p>
                            </td>
                            <td className="px-6 py-4 text-sm font-medium text-gray-600 dark:text-gray-300">
                                {formatSize(file.size)}
                            </td>
                            <td className="px-6 py-4 text-right relative">
                                <button
                                    onClick={(e) => toggleMenu(file.name, e)}
                                    className="action-menu-trigger text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 p-1 rounded-full hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors"
                                >
                                    <span className="material-symbols-outlined">more_vert</span>
                                </button>
                                {activeMenu === file.name && (
                                    <div className="absolute right-8 top-12 z-20 w-48 bg-white dark:bg-slate-800 rounded-lg shadow-lg border border-slate-200 dark:border-slate-700 py-1 action-menu animate-in zoom-in-95 duration-150 origin-top-right">
                                        <button onClick={() => { copyUrl(file.url); setActiveMenu(null); }} className="w-full text-left px-4 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700 flex items-center gap-2">
                                            <span className="material-symbols-outlined text-lg">link</span> Copy URL
                                        </button>
                                        <div className="h-px bg-slate-100 dark:bg-slate-700 my-1"></div>
                                        <button onClick={() => { handleDelete(file.name); setActiveMenu(null); }} className="w-full text-left px-4 py-2 text-sm text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 flex items-center gap-2">
                                            <span className="material-symbols-outlined text-lg">delete</span> Delete
                                        </button>
                                    </div>
                                )}
                            </td>
                        </tr>
                    ))
                )}
            </AdminTable>

            <ConfirmModal
                isOpen={confirmModal.isOpen}
                title={confirmModal.title}
                message={confirmModal.message}
                onConfirm={confirmModal.onConfirm}
                onCancel={() => setConfirmModal(prev => ({ ...prev, isOpen: false }))}
            />
        </AdminPageLayout>
    );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import AdminPageLayout from '@/components/admin/shared/AdminPageLayout';
import AdminTable from '@/components/admin/shared/AdminTable';
import AdminPagination from '@/components/admin/shared/AdminPagination';
import AdminBulkActionsBar from '@/components/admin/shared/AdminBulkActionsBar';

import { useToast } from '@/contexts/ToastContext';
import ConfirmModal from '@/components/admin/ConfirmModal';

interface NavItem {
    id: string;
    label: string;
    url: string;
    display_order: number;
    is_visible: boolean;
    opens_in_new_tab: boolean;
}

const emptyForm = { label: '', url: '', display_order: '0', is_visible: true, opens_in_new_tab: false };

export default function AdminNavigationPage() {
    const { showToast } = useToast();
    const [items, setItems] = useState<NavItem[]>([]);
    const [loading, setLoading] = useState(true);
    const [showModal, setShowModal] = useState(false);
    const [editingItem, setEditingItem] = useState<NavItem | null>(null);
    const [form, setForm] = useState(emptyForm);
    const [saving, setSaving] = useState(false);

    const [currentPage, setCurrentPage] = useState(1);
    const [itemsPerPage, setItemsPerPage] = useState(10);

    const [searchQuery, setSearchQuery] = useState('');
    const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
    const [isBulkDeleting, setIsBulkDeleting] = useState(false);
    const [activeMenu, setActiveMenu] = useState<string | null>(null);

    const [confirmModal, setConfirmModal] = useState<{
        isOpen: boolean;
        title: string;
        message: string;
        onConfirm: () => void;
    }>({
        isOpen: false,
        title: '',
        message: '',
        onConfirm: () => { },
    });

    // Close menu when clicking outside
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            const target = event.target as Element;
            if (activeMenu && !target.closest('.action-menu-trigger') && !target.closest('.action-menu')) {
                setActiveMenu(null);
            }
        };
        document.addEventListener('click', handleClickOutside);
        return () => document.removeEventListener('click', handleClickOutside);
    }, [activeMenu]);

    const toggleMenu = (itemId: string, e: React.MouseEvent) => {
        e.stopPropagation();
        setActiveMenu(activeMenu === itemId ? null : itemId);
    };

    const load = useCallback(async () => {
        setLoading(true);
        const res = await fetch('/api/nav-items');
        const data = await res.json();
        if (data.success) setItems(data.data.sort((a: NavItem, b: NavItem) => a.display_order - b.display_order));
        setLoading(false);
    }, []);

    useEffect(() => { load(); }, [load]);

    const openCreate = () => { setEditingItem(null); setForm({ ...emptyForm, display_order: String(items.length + 1) }); setShowModal(true); };
    const openEdit = (item: NavItem) => {
        setEditingItem(item);
        setForm({ label: item.label, url: item.url, display_order: String(item.display_order), is_visible: item.is_visible, opens_in_new_tab: item.opens_in_new_tab });
        setShowModal(true);
    };

    const handleSave = async () => {
        setSaving(true);
        const payload = { label: form.label, url: form.url, display_order: parseInt(form.display_order), is_visible: form.is_visible, opens_in_new_tab: form.opens_in_new_tab };
        const method = editingItem ? 'PUT' : 'POST';
        const url = editingItem ? `/api/nav-items?id=${editingItem.id}` : '/api/nav-items';
        const res = await fetch(url, { method, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
        const data = await res.json();
        if (data.success) { showToast(editingItem ? `Navigation link "${form.label}" updated successfully.` : `Navigation link "${form.label}" created successfully.`, 'success'); setShowModal(false); load(); }
        else showToast(data.message || 'Failed to save navigation link.', 'error');
        setSaving(false);
    };

    const handleDelete = async (id: string) => {
        if (isBulkDeleting) return;

        const navItem = items.find(i => i.id === id);
        setConfirmModal({
            isOpen: true,
            title: `Remove Nav Link "${navItem?.label}"`,
            message: 'Remove this nav link? This action cannot be undone.',
            onConfirm: async () => {
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
                try {
                    const res = await fetch(`/api/nav-items?id=${id}`, { method: 'DELETE' });
                    if ((await res.json()).success) {
                        showToast(`Navigation link "${navItem?.label}" was removed successfully.`, 'success');
                        setItems(prev => prev.filter(i => i.id !== id));
                        setSelectedIds(prev => {
                            const next = new Set(prev);
                            next.delete(id);
                            return next;
                        });
                    } else {
                        showToast('Failed to delete', 'error');
                        load();
                    }
                } catch (error) {
                    console.error('Error deleting nav item:', error);
                    showToast('Failed to delete nav item. Please try again.', 'error');
                    load();
                }
            }
        });
    };

    const handleBulkDelete = async () => {
        if (isBulkDeleting || selectedIds.size === 0) return;

        const count = selectedIds.size;
        setConfirmModal({
            isOpen: true,
            title: `Delete ${count} Nav Items`,
            message: `Are you sure you want to delete ${count} nav items? This action cannot be undone.`,
            onConfirm: async () => {
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
                setIsBulkDeleting(true);
                const idsToDelete = Array.from(selectedIds);
                let successCount = 0;
                let failCount = 0;

                try {
                    await Promise.all(idsToDelete.map(async (id) => {
                        try {
                            const res = await fetch(`/api/nav-items?id=${id}`, { method: 'DELETE' });
                            if (res.ok) successCount++;
                            else failCount++;
                        } catch (err) {
                            failCount++;
                        }
                    }));

                    if (successCount > 0) {
                        setItems(prev => prev.filter(i => !selectedIds.has(i.id)));
                        setSelectedIds(new Set());
                    }

                    if (failCount > 0) {
                        showToast(`Bulk delete finished. ${successCount} removed, ${failCount} failed.`, 'error');
                    } else {
                        showToast(`${successCount} navigation links were removed successfully.`, 'success');
                    }
                } catch (error) {
                    console.error('Bulk delete error:', error);
                    showToast('An error occurred during bulk deletion.', 'error');
                } finally {
                    setIsBulkDeleting(false);
                    load();
                }
            }
        });
    };

    const toggleVisibility = async (item: NavItem) => {
        await fetch(`/api/nav-items?id=${item.id}`, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ is_visible: !item.is_visible }) });
        showToast(`Navigation link "${item.label}" is now ${!item.is_visible ? 'visible' : 'hidden'}.`, 'success');
        load();
    };

    const toggleSelectAll = () => {
        const visibleIds = filteredItems.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage).map(i => i.id);
        const allVisibleSelected = visibleIds.every(id => selectedIds.has(id));

        setSelectedIds(prev => {
            const next = new Set(prev);
            if (allVisibleSelected) {
                visibleIds.forEach(id => next.delete(id));
            } else {
                visibleIds.forEach(id => next.add(id));
            }
            return next;
        });
    };

    const toggleSelect = (id: string) => {
        setSelectedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            return next;
        });
    };

    const filteredItems = items.filter(item =>
        item.label.toLowerCase().includes(searchQuery.toLowerCase()) ||
        item.url.toLowerCase().includes(searchQuery.toLowerCase())
    );

    // Calculate stats
    const visibleCount = items.filter(i => i.is_visible).length;
    const hiddenCount = items.filter(i => !i.is_visible).length;

    return (
        <AdminPageLayout
            title="Navigation Editor"
            subtitle="Control what links appear in your storefront header"
            actions={
                <button
                    onClick={openCreate}
                    className="flex items-center gap-2 px-4 py-2 bg-[#d41132] hover:bg-[#b30f2a] text-white text-sm font-bold rounded-lg shadow-md transition-colors"
                >
                    <span className="material-symbols-outlined text-[20px]">add</span>
                    Add Link
                </button>
            }
            stats={
                <>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Total Items</p>
                        <p className="text-base font-black text-[#0d141b] dark:text-white leading-none mt-0.5">{items.length}</p>
                    </div>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Visible</p>
                        <p className="text-base font-black text-emerald-500 leading-none mt-0.5">{visibleCount}</p>
                    </div>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Hidden</p>
                        <p className={`text-base font-black leading-none mt-0.5 ${hiddenCount > 0 ? 'text-[#d41132]' : 'text-[#0d141b] dark:text-white'}`}>{hiddenCount}</p>
                    </div>
                </>
            }
            filters={
                <div className="flex-1 min-w-[200px] relative">
                    <span className="absolute left-3 top-2.5 text-black/40 dark:text-white/40 material-symbols-outlined text-[20px]">search</span>
                    <input type="text" placeholder="Search navigation..." value={searchQuery}
                        onChange={(e) => { setSearchQuery(e.target.value); setCurrentPage(1); }}
                        className="w-full pl-10 pr-4 py-2 rounded-lg bg-white dark:bg-[#1a2632] border border-[#e5e7eb] dark:border-[#2d3b4a] focus:ring-2 focus:ring-[#d41132] outline-none transition-all dark:text-white text-sm" />
                </div>
            }
            pagination={
                <AdminPagination
                    currentPage={currentPage}
                    totalItems={filteredItems.length}
                    itemsPerPage={itemsPerPage}
                    onPageChange={setCurrentPage}
                    onItemsPerPageChange={(val) => {
                        setItemsPerPage(val);
                        setCurrentPage(1);
                    }}
                />
            }
            bulkActions={
                <AdminBulkActionsBar
                    selectedCount={selectedIds.size}
                    onCancel={() => setSelectedIds(new Set())}
                    onDelete={handleBulkDelete}
                    isDeleting={isBulkDeleting}
                />
            }
        >
            <AdminTable
                headers={['Label', 'URL', 'Order', 'Status', 'Actions']}
                onSelectAll={toggleSelectAll}
                isAllSelected={filteredItems.length > 0 && filteredItems.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage).every(i => selectedIds.has(i.id))}
            >
                {loading ? (
                    <tr>
                        <td colSpan={6} className="px-6 py-8 text-center text-gray-500">
                            <div className="flex items-center justify-center gap-2">
                                <span className="material-symbols-outlined animate-spin">progress_activity</span>
                                Loading navigation items...
                            </div>
                        </td>
                    </tr>
                ) : filteredItems.length === 0 ? (
                    <tr>
                        <td colSpan={6} className="px-6 py-8 text-center text-gray-500">
                            No navigation items found. Add your first link to get started.
                        </td>
                    </tr>
                ) : (
                    filteredItems.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage).map((item) => (
                        <tr key={item.id} className={`hover:bg-[#f6f7f8] dark:hover:bg-[#17202b] transition-colors group ${selectedIds.has(item.id) ? 'bg-[#d41132]/5 dark:bg-[#d41132]/10' : ''}`}>
                            <td className="px-6 py-4" onClick={(e) => e.stopPropagation()}>
                                <input
                                    type="checkbox"
                                    className="rounded border-slate-300 text-[#d41132] focus:ring-[#d41132] bg-transparent cursor-pointer"
                                    checked={selectedIds.has(item.id)}
                                    onChange={() => toggleSelect(item.id)}
                                />
                            </td>
                            <td className="px-6 py-4">
                                <p className="font-bold text-slate-900 dark:text-white text-sm">{item.label}</p>
                            </td>
                            <td className="px-6 py-4">
                                <p className="text-sm text-slate-500 font-mono truncate">
                                    {item.url}
                                    {item.opens_in_new_tab && <span className="ml-2 text-blue-400">&#8599; new tab</span>}
                                </p>
                            </td>
                            <td className="px-6 py-4 text-sm font-bold text-[#0d141b] dark:text-white">
                                {item.display_order}
                            </td>
                            <td className="px-6 py-4 text-sm">
                                <span className={`text-[10px] font-black uppercase tracking-widest px-2.5 py-1 rounded-full ${item.is_visible ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400' : 'bg-slate-100 text-slate-400 dark:bg-slate-700'}`}>
                                    {item.is_visible ? 'Visible' : 'Hidden'}
                                </span>
                            </td>
                            <td className="px-6 py-4 text-right relative">
                                <button
                                    onClick={(e) => toggleMenu(item.id, e)}
                                    className="action-menu-trigger text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 p-1 rounded-full hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors"
                                >
                                    <span className="material-symbols-outlined">more_vert</span>
                                </button>
                                {activeMenu === item.id && (
                                    <div className="absolute right-8 top-12 z-20 w-48 bg-white dark:bg-slate-800 rounded-lg shadow-lg border border-slate-200 dark:border-slate-700 py-1 action-menu animate-in zoom-in-95 duration-150 origin-top-right">
                                        <button onClick={() => { toggleVisibility(item); setActiveMenu(null); }} className="w-full text-left px-4 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700 flex items-center gap-2">
                                            <span className="material-symbols-outlined text-lg">{item.is_visible ? 'visibility_off' : 'visibility'}</span> {item.is_visible ? 'Hide' : 'Show'}
                                        </button>
                                        <button onClick={() => { openEdit(item); setActiveMenu(null); }} className="w-full text-left px-4 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700 flex items-center gap-2">
                                            <span className="material-symbols-outlined text-lg">edit</span> Edit
                                        </button>
                                        <div className="h-px bg-slate-100 dark:bg-slate-700 my-1"></div>
                                        <button onClick={() => { handleDelete(item.id); setActiveMenu(null); }} className="w-full text-left px-4 py-2 text-sm text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 flex items-center gap-2">
                                            <span className="material-symbols-outlined text-lg">delete</span> Delete
                                        </button>
                                    </div>
                                )}
                            </td>
                        </tr>
                    ))
                )}
            </AdminTable>

            {/* Modal */}
            {showModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
                    <div className="bg-white dark:bg-slate-800 rounded-2xl w-full sm:max-w-md shadow-2xl border border-slate-200 dark:border-slate-700">
                        <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 p-6 border-b border-slate-200 dark:border-slate-700">
                            <h2 className="text-lg font-black text-slate-900 dark:text-white">{editingItem ? 'Edit Link' : 'New Nav Link'}</h2>
                            <button onClick={() => setShowModal(false)} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg"><span className="material-symbols-outlined">close</span></button>
                        </div>
                        <div className="p-6 space-y-4">
                            <div>
                                <label className="block text-xs font-bold uppercase tracking-widest text-slate-500 mb-1.5">Label *</label>
                                <input value={form.label} onChange={e => setForm(f => ({ ...f, label: e.target.value }))} placeholder="Shop" className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm focus:border-[#d41132] outline-none dark:text-white" />
                            </div>
                            <div>
                                <label className="block text-xs font-bold uppercase tracking-widest text-slate-500 mb-1.5">URL *</label>
                                <input value={form.url} onChange={e => setForm(f => ({ ...f, url: e.target.value }))} placeholder="/shop or https://example.com" className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm font-mono focus:border-[#d41132] outline-none dark:text-white" />
                            </div>
                            <div>
                                <label className="block text-xs font-bold uppercase tracking-widest text-slate-500 mb-1.5">Display Order</label>
                                <input type="number" value={form.display_order} onChange={e => setForm(f => ({ ...f, display_order: e.target.value }))} className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm focus:border-[#d41132] outline-none dark:text-white" />
                            </div>
                            <div className="flex gap-6">
                                <label className="flex items-center gap-2 cursor-pointer">
                                    <div onClick={() => setForm(f => ({ ...f, is_visible: !f.is_visible }))} className={`relative w-10 h-5 rounded-full transition-all ${form.is_visible ? 'bg-green-500' : 'bg-slate-300 dark:bg-slate-600'}`}>
                                        <span className={`absolute top-0.5 left-0.5 w-4 h-4 bg-white rounded-full shadow transition-transform ${form.is_visible ? 'translate-x-5' : ''}`} />
                                    </div>
                                    <span className="text-sm text-slate-700 dark:text-slate-300">Visible</span>
                                </label>
                                <label className="flex items-center gap-2 cursor-pointer">
                                    <div onClick={() => setForm(f => ({ ...f, opens_in_new_tab: !f.opens_in_new_tab }))} className={`relative w-10 h-5 rounded-full transition-all ${form.opens_in_new_tab ? 'bg-blue-500' : 'bg-slate-300 dark:bg-slate-600'}`}>
                                        <span className={`absolute top-0.5 left-0.5 w-4 h-4 bg-white rounded-full shadow transition-transform ${form.opens_in_new_tab ? 'translate-x-5' : ''}`} />
                                    </div>
                                    <span className="text-sm text-slate-700 dark:text-slate-300">New Tab</span>
                                </label>
                            </div>
                        </div>
                        <div className="flex gap-3 p-6 border-t border-slate-200 dark:border-slate-700">
                            <button onClick={() => setShowModal(false)} className="flex-1 py-2.5 rounded-xl border border-slate-200 dark:border-slate-600 text-slate-600 dark:text-slate-300 font-bold text-sm hover:bg-slate-50 transition-colors">Cancel</button>
                            <button onClick={handleSave} disabled={saving || !form.label || !form.url} className="flex-1 py-2.5 rounded-xl bg-[#d41132] hover:bg-[#b30f2a] text-white font-bold text-sm transition-colors disabled:opacity-50">
                                {saving ? 'Saving...' : (editingItem ? 'Save Changes' : 'Add Link')}
                            </button>
                        </div>
                    </div>
                </div>
            )}

            <ConfirmModal
                isOpen={confirmModal.isOpen}
                title={confirmModal.title}
                message={confirmModal.message}
                onConfirm={confirmModal.onConfirm}
                onCancel={() => setConfirmModal(prev => ({ ...prev, isOpen: false }))}
            />
        </AdminPageLayout>
    );
}

'use client';

import { useEffect, useState } from 'react';
import AdminPageLayout from '@/components/admin/shared/AdminPageLayout';
import AdminTable from '@/components/admin/shared/AdminTable';
import AdminPagination from '@/components/admin/shared/AdminPagination';
import AdminBulkActionsBar from '@/components/admin/shared/AdminBulkActionsBar';

import { useToast } from '@/contexts/ToastContext';
import type { Order } from '@/lib/supabase';
import AdminOrderModal from '@/components/admin/AdminOrderModal';
import ConfirmModal from '@/components/admin/ConfirmModal';
import AdminFilterTabs from '@/components/admin/shared/AdminFilterTabs';

interface OrderRow {
    id: string;
    customer_name: string;
    customer_email: string;
    total: number;
    status: Order['status'];
    created_at: string;
    items_count: number;
}

export default function AdminOrdersPage() {
    const { showToast } = useToast();
    const [orders, setOrders] = useState<OrderRow[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [statusFilter, setStatusFilter] = useState<string>('all');
    const [currentPage, setCurrentPage] = useState(1);
    const [itemsPerPage, setItemsPerPage] = useState(10);

    // Modal state
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [selectedOrder, setSelectedOrder] = useState<OrderRow | null>(null);
    const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
    const [isBulkDeleting, setIsBulkDeleting] = useState(false);
    const [isMounted, setIsMounted] = useState(false);
    const [confirmModal, setConfirmModal] = useState<{
        isOpen: boolean;
        title: string;
        message: string;
        onConfirm: () => void;
    }>({
        isOpen: false,
        title: '',
        message: '',
        onConfirm: () => { },
    });

    useEffect(() => {
        setIsMounted(true);
    }, []);

    useEffect(() => {
        loadOrders();
    }, [statusFilter]); // Reload when filter changes if server-side filtering is preferred, but we will filter client side for search

    const loadOrders = async () => {
        try {
            setLoading(true);
            const query = new URLSearchParams();
            if (statusFilter !== 'all') query.append('status', statusFilter);

            const res = await fetch(`/api/orders?${query.toString()}`);
            const data = await res.json();

            if (data.success) {
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                const mapped: OrderRow[] = (data.data || []).map((o: any) => ({
                    id: o.id,
                    customer_name: o.customers?.name || 'Unknown',
                    customer_email: o.customers?.email || '',
                    total: Number(o.total),
                    status: o.status,
                    created_at: o.created_at || o.createdAt,
                    items_count: Array.isArray(o.order_items) ? o.order_items.length :
                        Array.isArray(o.items) ? o.items.length : 0
                }));
                setOrders(mapped);
            } else {
                console.error('Failed to load orders:', data.error);
            }
        } catch (error) {
            console.error('Failed to load orders:', error);
        } finally {
            setLoading(false);
        }
    };

    const handleStatusChange = async (orderId: string, newStatus: Order['status']) => {
        try {
            const res = await fetch(`/api/orders/${orderId}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ status: newStatus }),
            });
            const data = await res.json();

            if (data.success) {
                await loadOrders();
                showToast(`Order #${orderId.slice(-8).toUpperCase()} moved to ${newStatus}.`, 'success');
            } else {
                console.error('Failed to update order status:', data.error);
                showToast(`Failed to update Order #${orderId.slice(-8).toUpperCase()}.`, 'error');
            }
        } catch (err) {
            console.error('Failed to update order status:', err);
            showToast('An error occurred while updating the order status.', 'error');
        }
    };

    const handleCreateOrder = async (orderData: any) => {
        try {
            const res = await fetch('/api/orders', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(orderData),
            });
            const result = await res.json();

            if (result.success) {
                await loadOrders();
                setIsModalOpen(false);
                showToast(`Order created successfully for ${orderData.customer_name || 'customer'}.`, 'success');
            } else {
                showToast('Failed to create order: ' + (result.error || result.message), 'error');
            }
        } catch (error) {
            console.error('Error creating order:', error);
            showToast('An error occurred while creating/saving the order', 'error');
        }
    };

    const handleDelete = async (orderId: string) => {
        if (isBulkDeleting) return;

        const order = orders.find(o => o.id === orderId);
        if (!order) return;

        setConfirmModal({
            isOpen: true,
            title: `Archive Order #${order.id.slice(-8).toUpperCase()}`,
            message: `Are you sure you want to archive this order for ${order.customer_name}? For financial integrity, orders are never permanently deleted.`,
            onConfirm: async () => {
                try {
                    const res = await fetch(`/api/orders/${orderId}`, { method: 'DELETE' });
                    const data = await res.json();
                    if (data.success) {
                        // Optimistic update
                        setOrders(prev => prev.filter(o => o.id !== orderId));
                        setSelectedIds(prev => {
                            const next = new Set(prev);
                            next.delete(orderId);
                            return next;
                        });
                        showToast(`Order #${order.id.slice(-8).toUpperCase()} was archived.`, 'success');
                    } else {
                        showToast('Failed to archive order: ' + (data.error || 'Unknown error'), 'error');
                    }
                } catch (err) {
                    showToast('An unexpected error occurred during archiving.', 'error');
                    console.error('Failed to archive order:', err);
                } finally {
                    setConfirmModal(prev => ({ ...prev, isOpen: false }));
                }
            }
        });
    };

    const handleBulkDelete = async () => {
        if (isBulkDeleting || selectedIds.size === 0) return;

        const count = selectedIds.size;
        setConfirmModal({
            isOpen: true,
            title: `Archive ${count} Orders`,
            message: `Are you sure you want to archive ${count} selected orders? For financial integrity, orders are never permanently deleted.`,
            onConfirm: async () => {
                setIsBulkDeleting(true);
                const idsToDelete = Array.from(selectedIds);
                let successCount = 0;
                let failCount = 0;

                try {
                    await Promise.all(idsToDelete.map(async (id) => {
                        try {
                            const res = await fetch(`/api/orders/${id}`, { method: 'DELETE' });
                            if (res.ok) successCount++;
                            else failCount++;
                        } catch (err) {
                            failCount++;
                        }
                    }));

                    if (successCount > 0) {
                        setOrders(prev => prev.filter(o => !selectedIds.has(o.id)));
                        setSelectedIds(new Set());
                    }

                    if (failCount > 0) {
                        showToast(`Bulk archive finished with errors. Archived: ${successCount}, Failed: ${failCount}`, 'error');
                    } else {
                        showToast(`Successfully archived ${successCount} orders.`, 'success');
                    }
                } catch (error) {
                    console.error('Bulk archive error:', error);
                    showToast('An error occurred during bulk archiving.', 'error');
                } finally {
                    setIsBulkDeleting(false);
                    setConfirmModal(prev => ({ ...prev, isOpen: false }));
                    loadOrders(); // Refresh to ensure sync
                }
            }
        });
    };

    const toggleSelectAll = () => {
        const visibleIds = filteredOrders.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage).map(o => o.id);
        const allVisibleSelected = visibleIds.every(id => selectedIds.has(id));

        setSelectedIds(prev => {
            const next = new Set(prev);
            if (allVisibleSelected) {
                visibleIds.forEach(id => next.delete(id));
            } else {
                visibleIds.forEach(id => next.add(id));
            }
            return next;
        });
    };

    const toggleSelect = (id: string) => {
        setSelectedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            return next;
        });
    };

    const getStatusBadge = (status: Order['status']) => {
        const styles = {
            PENDING: 'bg-yellow-100 text-yellow-full md:w-800 dark:bg-yellow-900/20 dark:text-yellow-400',
            PROCESSING: 'bg-blue-100 text-blue-800 dark:bg-blue-900/20 dark:text-blue-400',
            SHIPPED: 'bg-purple-100 text-purple-800 dark:bg-purple-900/20 dark:text-purple-400',
            DELIVERED: 'bg-green-100 text-green-800 dark:bg-green-900/20 dark:text-green-400',
            CANCELLED: 'bg-red-100 text-red-800 dark:bg-red-900/20 dark:text-red-400'
        };

        return (
            <span className={`px-2 py-1 rounded-full text-xs font-medium ${styles[status]}`}>
                {status.charAt(0) + status.slice(1).toLowerCase()}
            </span>
        );
    };

    const filteredOrders = orders.filter(order => {
        const matchesSearch = order.customer_name.toLowerCase().includes(searchQuery.toLowerCase()) ||
            order.customer_email.toLowerCase().includes(searchQuery.toLowerCase()) ||
            order.id.includes(searchQuery);
        // Status filtering is now handled by the API mostly, but if 'all' is fetched we can filter client side too
        // However, since we reload on status change, this check is redundant but safe
        const matchesStatus = statusFilter === 'all' || order.status === statusFilter;
        return matchesSearch && matchesStatus;
    });

    const [activeMenu, setActiveMenu] = useState<string | null>(null);

    // Close menu when clicking outside
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            const target = event.target as Element;
            if (activeMenu && !target.closest('.action-menu-trigger') && !target.closest('.action-menu')) {
                setActiveMenu(null);
            }
        };
        document.addEventListener('click', handleClickOutside);
        return () => document.removeEventListener('click', handleClickOutside);
    }, [activeMenu]);

    const handleExport = () => {
        const headers = ['Order ID', 'Customer', 'Email', 'Items', 'Total', 'Status', 'Date'];
        const csvContent = [
            headers.join(','),
            ...filteredOrders.map(order => [
                order.id,
                `"${order.customer_name}"`,
                order.customer_email,
                order.items_count,
                order.total,
                order.status,
                new Date(order.created_at).toLocaleDateString()
            ].join(','))
        ].join('\n');

        const blob = new Blob([csvContent], { type: 'text/csv' });
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `orders-export-${new Date().toISOString().split('T')[0]}.csv`;
        a.click();
        window.URL.revokeObjectURL(url);
    };

    const toggleMenu = (orderId: string, e: React.MouseEvent) => {
        e.stopPropagation();
        setActiveMenu(activeMenu === orderId ? null : orderId);
    };

    return (
        <AdminPageLayout
            title="Order Management"
            subtitle="View and manage all customer orders."
            stats={
                <>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Total Orders</p>
                        <p className="text-base font-black text-[#0d141b] dark:text-white leading-none mt-0.5">{orders.length}</p>
                    </div>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Pending</p>
                        <p className="text-base font-black text-[#0d141b] dark:text-white leading-none mt-0.5">{orders.filter(o => o.status === 'PENDING').length}</p>
                    </div>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Revenue</p>
                        <p className="text-base font-black text-[#0d141b] dark:text-white leading-none mt-0.5">${orders.reduce((sum, o) => sum + o.total, 0).toFixed(2)}</p>
                    </div>
                </>
            }
            actions={
                <>
                    <button
                        onClick={handleExport}
                        className="flex items-center gap-2 px-4 py-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg text-slate-700 dark:text-slate-200 font-medium text-sm hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors"
                    >
                        <span className="material-symbols-outlined text-lg">download</span>
                        Export
                    </button>
                    <button
                        onClick={() => setIsModalOpen(true)}
                        className="flex items-center gap-2 px-4 py-2 bg-[#d41132] text-white rounded-lg font-medium text-sm hover:bg-[#b30f2a] transition-colors shadow-sm shadow-red-200 dark:shadow-none">
                        <span className="material-symbols-outlined text-lg">add</span>
                        New Order
                    </button>
                </>
            }
            filters={
                <div className="flex flex-col lg:flex-row justify-between items-center gap-4 w-full">
                    {/* Search */}
                    <div className="relative w-full lg:w-full md:w-96 group">
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                            <span className="material-symbols-outlined text-slate-400">search</span>
                        </div>
                        <input
                            className="block w-full pl-10 pr-3 py-2.5 border-none rounded-lg bg-slate-100 dark:bg-slate-800 text-slate-900 dark:text-white placeholder-slate-500 dark:placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-[#d41132]/50 text-sm transition-all"
                            placeholder="Search by order ID, customer name, or email..."
                            type="text"
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                        />
                    </div>
                    {/* Status Filters */}
                    <AdminFilterTabs
                        tabs={[
                            { label: 'All Orders', value: 'all' },
                            { label: 'Pending', value: 'PENDING' },
                            { label: 'Processing', value: 'PROCESSING' },
                            { label: 'Shipped', value: 'SHIPPED' },
                            { label: 'Delivered', value: 'DELIVERED' },
                        ]}
                        activeTab={statusFilter}
                        onTabChange={setStatusFilter}
                    />
                </div>
            }
            pagination={
                <AdminPagination
                    currentPage={currentPage}
                    totalItems={filteredOrders.length}
                    itemsPerPage={itemsPerPage}
                    onPageChange={setCurrentPage}
                    onItemsPerPageChange={(val) => {
                        setItemsPerPage(val);
                        setCurrentPage(1);
                    }}
                />
            }
            bulkActions={
                <AdminBulkActionsBar
                    selectedCount={selectedIds.size}
                    onCancel={() => setSelectedIds(new Set())}
                    onDelete={handleBulkDelete}
                    isDeleting={isBulkDeleting}
                />
            }
        >
            <AdminTable
                headers={['Order ID', 'Customer', 'Items', 'Total', 'Status', 'Date', '']}
                onSelectAll={toggleSelectAll}
                isAllSelected={filteredOrders.length > 0 && filteredOrders.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage).every(o => selectedIds.has(o.id))}
            >
                {loading ? (
                    <tr>
                        <td colSpan={8} className="py-12 text-center text-slate-500 dark:text-slate-400 font-bold">
                            <div className="flex items-center justify-center gap-2">
                                <span className="material-symbols-outlined animate-spin">progress_activity</span>
                                Loading orders...
                            </div>
                        </td>
                    </tr>
                ) : filteredOrders.length === 0 ? (
                    <tr>
                        <td colSpan={8} className="py-12 text-center text-slate-500 dark:text-slate-400">
                            No orders found.
                        </td>
                    </tr>
                ) : (
                    filteredOrders.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage).map((order) => (
                        <tr key={order.id} className={`group hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors ${selectedIds.has(order.id) ? 'bg-[#d41132]/5 dark:bg-[#d41132]/10' : ''}`}>
                            <td className="py-4 px-6" onClick={(e) => e.stopPropagation()}>
                                <input
                                    type="checkbox"
                                    className="rounded border-slate-300 text-[#d41132] focus:ring-[#d41132] bg-transparent cursor-pointer"
                                    checked={selectedIds.has(order.id)}
                                    onChange={() => toggleSelect(order.id)}
                                />
                            </td>
                            <td className="py-4 px-6">
                                <span className="text-sm font-mono font-medium text-slate-900 dark:text-white" title={order.id}>#{order.id.slice(-8).toUpperCase()}</span>
                            </td>
                            <td className="py-4 px-6">
                                <div className="flex flex-col gap-1">
                                    <p className="font-medium text-slate-900 dark:text-white text-sm">{order.customer_name}</p>
                                    <p className="text-xs text-slate-400">{order.customer_email}</p>
                                </div>
                            </td>
                            <td className="py-4 px-6">
                                <span className="text-sm text-slate-600 dark:text-slate-300">{order.items_count} items</span>
                            </td>
                            <td className="py-4 px-6">
                                <span className="text-sm font-bold text-slate-900 dark:text-white">${order.total.toFixed(2)}</span>
                            </td>
                            <td className="py-4 px-6">
                                {getStatusBadge(order.status)}
                            </td>
                            <td className="py-4 px-6">
                                <span className="text-sm text-slate-500 dark:text-slate-400">
                                    {isMounted ? new Date(order.created_at).toLocaleDateString() : '...'}
                                </span>
                            </td>
                            <td className="py-4 px-6 text-right relative">
                                <button
                                    onClick={(e) => toggleMenu(order.id, e)}
                                    className="action-menu-trigger text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 p-1 rounded-full hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors"
                                >
                                    <span className="material-symbols-outlined">more_vert</span>
                                </button>
                                {activeMenu === order.id && (
                                    <div className="absolute right-8 top-12 z-20 w-48 bg-white dark:bg-slate-800 rounded-lg shadow-lg border border-slate-200 dark:border-slate-700 py-1 action-menu">
                                        <button onClick={() => { setSelectedOrder(order); setActiveMenu(null); }} className="w-full text-left px-4 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700 flex items-center gap-2">
                                            <span className="material-symbols-outlined text-lg">visibility</span> View Details
                                        </button>
                                        <button onClick={() => { const next: Record<string, Order['status']> = { PENDING: 'PROCESSING', PROCESSING: 'SHIPPED', SHIPPED: 'DELIVERED', DELIVERED: 'DELIVERED', CANCELLED: 'CANCELLED' }; handleStatusChange(order.id, next[order.status] || 'PROCESSING'); setActiveMenu(null); }} className="w-full text-left px-4 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700 flex items-center gap-2">
                                            <span className="material-symbols-outlined text-lg">edit</span> Advance Status
                                        </button>
                                        <div className="h-px bg-slate-100 dark:bg-slate-700 my-1"></div>
                                        <button onClick={() => { handleDelete(order.id); setActiveMenu(null); }} className="w-full text-left px-4 py-2 text-sm text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 flex items-center gap-2">
                                            <span className="material-symbols-outlined text-lg">delete</span> Delete
                                        </button>
                                    </div>
                                )}
                            </td>
                        </tr>
                    ))
                )}
            </AdminTable>

            {/* Modals and Side Panels */}
            <AdminOrderModal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                onSubmit={handleCreateOrder}
            />

            {/* Order Detail Drawer */}
            {selectedOrder && (
                <div className="fixed inset-0 z-[110] flex justify-end">
                    <div className="absolute inset-0 bg-black/20 backdrop-blur-sm" onClick={() => setSelectedOrder(null)} />
                    <aside className="relative h-full w-full sm:w-[500px] bg-white dark:bg-[#1a2632] shadow-2xl border-l border-slate-200 dark:border-slate-700 flex flex-col animate-in slide-in-from-right duration-300">
                        {/* Drawer Header */}
                        <div className="px-6 py-4 border-b border-slate-200 dark:border-slate-700 flex items-center justify-between bg-slate-50/50 dark:bg-slate-900/50">
                            <div className="flex flex-col">
                                <span className="text-xs font-mono text-slate-500 mb-1">#{selectedOrder.id.slice(-8).toUpperCase()}</span>
                                <h3 className="text-lg font-bold text-slate-900 dark:text-white">Order Details</h3>
                            </div>
                            <button onClick={() => setSelectedOrder(null)} className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors p-1 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800">
                                <span className="material-symbols-outlined">close</span>
                            </button>
                        </div>

                        <div className="flex-1 overflow-y-auto p-6 space-y-6">
                            {/* Status Badge */}
                            <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                                {getStatusBadge(selectedOrder.status)}
                                <span className="text-xs text-slate-500">
                                    {isMounted ? new Date(selectedOrder.created_at).toLocaleDateString('en-US', { day: 'numeric', month: 'long', year: 'numeric' }) : '...'}
                                </span>
                            </div>

                            {/* Customer Info */}
                            <div className="bg-slate-50 dark:bg-slate-900/50 rounded-lg p-4 border border-slate-100 dark:border-slate-700">
                                <h4 className="text-xs font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider mb-3">Customer</h4>
                                <div className="flex items-center gap-3">
                                    <div className="size-10 rounded-full bg-[#d41132]/10 text-[#d41132] flex items-center justify-center text-sm font-bold">
                                        {selectedOrder.customer_name.split(' ').map((n: string) => n[0]).join('').slice(0, 2)}
                                    </div>
                                    <div>
                                        <p className="text-sm font-bold text-slate-900 dark:text-white">{selectedOrder.customer_name}</p>
                                        <p className="text-xs text-slate-500">{selectedOrder.customer_email}</p>
                                    </div>
                                </div>
                            </div>

                            {/* Order Summary */}
                            <div className="space-y-3">
                                <h4 className="text-xs font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Order Summary</h4>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                                    <div className="bg-white dark:bg-[#1a2632] rounded-lg p-3 border border-slate-200 dark:border-slate-700">
                                        <p className="text-xs text-slate-500">Items</p>
                                        <p className="text-lg font-black text-slate-900 dark:text-white">{selectedOrder.items_count}</p>
                                    </div>
                                    <div className="bg-white dark:bg-[#1a2632] rounded-lg p-3 border border-slate-200 dark:border-slate-700">
                                        <p className="text-xs text-slate-500">Total</p>
                                        <p className="text-lg font-black text-slate-900 dark:text-white">${selectedOrder.total.toFixed(2)}</p>
                                    </div>
                                </div>
                            </div>

                            {/* Status Timeline */}
                            <div className="space-y-3">
                                <h4 className="text-xs font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Status Flow</h4>
                                <div className="flex items-center gap-1">
                                    {(['PENDING', 'PROCESSING', 'SHIPPED', 'DELIVERED'] as Order['status'][]).map((s, i) => {
                                        const statuses = ['PENDING', 'PROCESSING', 'SHIPPED', 'DELIVERED'];
                                        const currentIdx = statuses.indexOf(selectedOrder.status);
                                        const isActive = i <= currentIdx;
                                        return (
                                            <div key={s} className="flex items-center flex-1">
                                                <div className={`w-2 h-2 rounded-full shrink-0 ${isActive ? 'bg-[#d41132]' : 'bg-slate-200 dark:bg-slate-700'}`} />
                                                {i < 3 && <div className={`h-[2px] flex-1 ${i < currentIdx ? 'bg-[#d41132]' : 'bg-slate-200 dark:bg-slate-700'}`} />}
                                            </div>
                                        );
                                    })}
                                </div>
                                <div className="flex justify-between">
                                    {['Pending', 'Processing', 'Shipped', 'Delivered'].map((s) => (
                                        <span key={s} className="text-[9px] font-bold text-slate-400">{s}</span>
                                    ))}
                                </div>
                            </div>
                        </div>

                        {/* Drawer Actions */}
                        <div className="p-6 border-t border-slate-200 dark:border-slate-700 bg-white dark:bg-[#1a2632] flex flex-col gap-3">
                            <button
                                onClick={() => {
                                    const next: Record<string, Order['status']> = { PENDING: 'PROCESSING', PROCESSING: 'SHIPPED', SHIPPED: 'DELIVERED', DELIVERED: 'DELIVERED', CANCELLED: 'CANCELLED' };
                                    handleStatusChange(selectedOrder.id, next[selectedOrder.status] || 'PROCESSING');
                                    setSelectedOrder(null);
                                }}
                                disabled={selectedOrder.status === 'DELIVERED' || selectedOrder.status === 'CANCELLED'}
                                className="w-full flex items-center justify-center gap-2 bg-[#d41132] hover:bg-[#b30f2a] text-white font-bold py-2.5 px-4 rounded-lg transition-all shadow-md disabled:opacity-40 disabled:cursor-not-allowed"
                            >
                                <span className="material-symbols-outlined text-[20px]">forward</span>
                                Advance Status
                            </button>
                            <button
                                onClick={() => { handleDelete(selectedOrder.id); setSelectedOrder(null); }}
                                className="w-full flex items-center justify-center gap-2 bg-white dark:bg-[#1a2632] border border-red-300 text-red-600 font-bold py-2.5 px-4 rounded-lg hover:bg-red-50 dark:hover:bg-red-900/20 transition-all"
                            >
                                <span className="material-symbols-outlined text-[20px]">delete</span>
                                Delete Order
                            </button>
                        </div>
                    </aside>
                </div>
            )}
            <ConfirmModal
                isOpen={confirmModal.isOpen}
                title={confirmModal.title}
                message={confirmModal.message}
                onConfirm={confirmModal.onConfirm}
                onCancel={() => setConfirmModal(prev => ({ ...prev, isOpen: false }))}
            />
        </AdminPageLayout>
    );
}

'use client';

import { useState, useEffect } from 'react';
import AdminPageLayout from '@/components/admin/shared/AdminPageLayout';
import AdminTable from '@/components/admin/shared/AdminTable';
import AdminPagination from '@/components/admin/shared/AdminPagination';
import AdminBulkActionsBar from '@/components/admin/shared/AdminBulkActionsBar';

import { useToast } from '@/contexts/ToastContext';
import { Product } from '@/lib/supabase';

// Extend Product to handle potential array of images from legacy/API difference
interface ExtendedProduct extends Product {
    images?: string[];
    sale_price?: number;
}

import ProductFormModal, { pProduct } from '@/components/admin/ProductFormModal';
import ConfirmModal from '@/components/admin/ConfirmModal';
import AdminFilterTabs from '@/components/admin/shared/AdminFilterTabs';

export default function AdminProductsPage() {
    const { showToast } = useToast();
    const [products, setProducts] = useState<ExtendedProduct[]>([]);
    const [filteredProducts, setFilteredProducts] = useState<ExtendedProduct[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedCategory, setSelectedCategory] = useState('All');
    const [currentPage, setCurrentPage] = useState(1);
    const [itemsPerPage, setItemsPerPage] = useState(10);

    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingProduct, setEditingProduct] = useState<ExtendedProduct | null>(null);
    const [categories, setCategories] = useState<string[]>(['Jackets', 'Full Coats', 'Bags & Satchels', 'Accessories', 'Shoes']);
    const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
    const [isBulkDeleting, setIsBulkDeleting] = useState(false);
    const [isMounted, setIsMounted] = useState(false);
    const [activeMenu, setActiveMenu] = useState<string | null>(null);
    const [confirmModal, setConfirmModal] = useState<{
        isOpen: boolean;
        title: string;
        message: string;
        onConfirm: () => void;
    }>({
        isOpen: false,
        title: '',
        message: '',
        onConfirm: () => { },
    });

    useEffect(() => {
        setIsMounted(true);
    }, []);

    // Close menu when clicking outside
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            const target = event.target as Element;
            if (activeMenu && !target.closest('.action-menu-trigger') && !target.closest('.action-menu')) {
                setActiveMenu(null);
            }
        };
        document.addEventListener('click', handleClickOutside);
        return () => document.removeEventListener('click', handleClickOutside);
    }, [activeMenu]);

    const toggleMenu = (productId: string, e: React.MouseEvent) => {
        e.stopPropagation();
        setActiveMenu(activeMenu === productId ? null : productId);
    };

    // Fetch categories
    useEffect(() => {
        fetch('/api/categories').then(r => r.json()).then(d => {
            if (d.success && d.data?.length > 0) setCategories(d.data.map((c: any) => c.name));
        }).catch(() => { });
    }, []);

    // Fetch products on load
    useEffect(() => {
        fetchProducts();
    }, []);

    // Filter products when search or category changes
    useEffect(() => {
        let result = products;

        if (selectedCategory !== 'All') {
            result = result.filter(p => p.category === selectedCategory);
        }

        if (searchTerm) {
            const lowerTerm = searchTerm.toLowerCase();
            result = result.filter(p =>
                p.name.toLowerCase().includes(lowerTerm) ||
                (p.description && p.description.toLowerCase().includes(lowerTerm))
            );
        }

        setFilteredProducts(result);
        setCurrentPage(1);
    }, [products, searchTerm, selectedCategory]);

    const fetchProducts = async () => {
        setIsLoading(true);
        try {
            // includeInactive=true so admin sees ALL products, including archived
            const res = await fetch('/api/products?includeInactive=true');
            const result = await res.json();
            if (result.success) {
                setProducts(result.data);
                setFilteredProducts(result.data);
            }
        } catch (error) {
            console.error('Error fetching products:', error);
        } finally {
            setIsLoading(false);
        }
    };

    const handleCreateProduct = async (productData: pProduct) => {
        try {
            const res = await fetch('/api/products', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(productData),
            });

            if (!res.ok) throw new Error('Failed to create product');

            await fetchProducts();
            setIsModalOpen(false);
        } catch (error) {
            console.error('Error creating product:', error);
            throw error;
        }
    };

    const handleUpdateProduct = async (productData: pProduct) => {
        if (!editingProduct) return;
        try {
            const res = await fetch(`/api/products/${editingProduct.id}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(productData),
            });

            if (!res.ok) throw new Error('Failed to update product');

            await fetchProducts();
            setIsModalOpen(false);
            setEditingProduct(null);
        } catch (error) {
            console.error('Error updating product:', error);
            throw error;
        }
    };

    const handleDeleteProduct = async (id: string) => {
        if (isBulkDeleting) return;

        const product = products.find(p => p.id === id);
        if (!product) return;

        setConfirmModal({
            isOpen: true,
            title: 'Delete Product',
            message: `Are you sure you want to delete "${product.name}"? If this product has order history, it will be archived (hidden from storefront) instead of permanently deleted.`,
            onConfirm: async () => {
                try {
                    const res = await fetch(`/api/products/${id}`, { method: 'DELETE' });
                    const result = await res.json();

                    if (!res.ok) throw new Error(result.message || 'Failed to delete product');

                    if (result.archived) {
                        showToast(
                            `⚠️ "${product.name}" was archived instead of deleted because it exists in order history.`,
                            'warning'
                        );
                        // Refresh to show updated isActive status
                        await fetchProducts();
                    } else {
                        // Hard deleted — remove from local state optimistically
                        setProducts(products.filter(p => p.id !== id));
                        setSelectedIds(prev => {
                            const next = new Set(prev);
                            next.delete(id);
                            return next;
                        });
                        showToast(`"${product.name}" was permanently deleted.`, 'success');
                    }
                } catch (error) {
                    console.error('Error deleting product:', error);
                    showToast(`Failed to delete "${product.name}". Please try again.`, 'error');
                } finally {
                    setConfirmModal(prev => ({ ...prev, isOpen: false }));
                }
            }
        });
    };

    const handleArchiveProduct = async (id: string) => {
        const product = products.find(p => p.id === id);
        try {
            const res = await fetch(`/api/products/${id}?action=archive`, { method: 'PATCH' });
            const result = await res.json();
            if (!res.ok) throw new Error(result.message);
            showToast(`"${product?.name}" archived and hidden from storefront.`, 'success');
            fetchProducts();
        } catch (error) {
            console.error('Error archiving product:', error);
            showToast(`Failed to archive "${product?.name || 'product'}".`, 'error');
        }
    };

    const handleRestoreProduct = async (id: string) => {
        const product = products.find(p => p.id === id);
        try {
            const res = await fetch(`/api/products/${id}?action=restore`, { method: 'PATCH' });
            const result = await res.json();
            if (!res.ok) throw new Error(result.message);
            showToast(`"${product?.name}" restored and is now visible on the storefront.`, 'success');
            fetchProducts();
        } catch (error) {
            console.error('Error restoring product:', error);
            showToast(`Failed to restore "${product?.name || 'product'}".`, 'error');
        }
    };

    const handleBulkDelete = async () => {
        if (isBulkDeleting || selectedIds.size === 0) return;

        const count = selectedIds.size;
        setConfirmModal({
            isOpen: true,
            title: `Delete ${count} Products`,
            message: `Are you sure you want to delete ${count} products? This action cannot be undone. Products with order history will be archived instead of permanently deleted.`,
            onConfirm: async () => {
                setIsBulkDeleting(true);
                const idsToDelete = Array.from(selectedIds);
                let hardDeletedCount = 0;
                let archivedCount = 0;
                let failCount = 0;

                try {
                    await Promise.all(idsToDelete.map(async (id) => {
                        try {
                            const res = await fetch(`/api/products/${id}`, { method: 'DELETE' });
                            const result = await res.json();

                            if (res.ok) {
                                if (result.archived) {
                                    archivedCount++;
                                } else {
                                    hardDeletedCount++;
                                }
                            } else {
                                failCount++;
                            }
                        } catch (err) {
                            failCount++;
                        }
                    }));

                    setSelectedIds(new Set());
                    await fetchProducts(); // Refresh to ensure sync with DB

                    if (failCount > 0) {
                        showToast(`Bulk delete finished with errors. Deleted: ${hardDeletedCount}, Archived: ${archivedCount}, Failed: ${failCount}`, 'error');
                    } else if (archivedCount > 0 && hardDeletedCount === 0) {
                        showToast(`⚠️ All ${archivedCount} selected products were archived instead of deleted because they exist in order history.`, 'warning');
                    } else if (archivedCount > 0 && hardDeletedCount > 0) {
                        showToast(`⚠️ ${hardDeletedCount} products deleted. ${archivedCount} products were archived instead because they have order history.`, 'warning');
                    } else {
                        showToast(`Successfully deleted ${hardDeletedCount} products.`, 'success');
                    }
                } catch (error) {
                    console.error('Bulk delete error:', error);
                    showToast('An error occurred during bulk deletion.', 'error');
                } finally {
                    setIsBulkDeleting(false);
                    setConfirmModal(prev => ({ ...prev, isOpen: false }));
                }
            }
        });
    };

    const toggleSelectAll = () => {
        const visibleIds = filteredProducts.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage).map(p => p.id);
        const allVisibleSelected = visibleIds.every(id => selectedIds.has(id));

        setSelectedIds(prev => {
            const next = new Set(prev);
            if (allVisibleSelected) {
                visibleIds.forEach(id => next.delete(id));
            } else {
                visibleIds.forEach(id => next.add(id));
            }
            return next;
        });
    };

    const toggleSelect = (id: string) => {
        setSelectedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            return next;
        });
    };

    const openEditModal = (product: ExtendedProduct) => {
        setEditingProduct(product);
        setIsModalOpen(true);
    };

    const openCreateModal = () => {
        setEditingProduct(null);
        setIsModalOpen(true);
    };

    // Calculate stats
    const activeProducts = products.filter(p => p.isActive);
    const archivedCount = products.filter(p => !p.isActive).length;
    const totalInventory = activeProducts.reduce((acc, curr) => acc + curr.stock, 0);
    const lowStockCount = activeProducts.filter(p => p.stock < 5).length;
    const totalValue = activeProducts.reduce((acc, curr) => acc + (curr.price * curr.stock), 0);

    return (
        <AdminPageLayout
            title="Product Inventory"
            subtitle="Manage your catalog, stock levels, and pricing."
            actions={
                <button
                    onClick={openCreateModal}
                    className="flex items-center gap-2 px-4 py-2 bg-[#d41132] hover:bg-[#b30f2a] text-white text-sm font-bold rounded-lg shadow-md transition-colors"
                >
                    <span className="material-symbols-outlined text-[20px]">add</span>
                    Add Product
                </button>
            }
            stats={
                <>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Total Products</p>
                        <p className="text-base font-black text-[#0d141b] dark:text-white leading-none mt-0.5">{activeProducts.length} <span className="text-xs font-medium text-gray-400">active</span></p>
                    </div>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Total Inventory</p>
                        <p className="text-base font-black text-[#0d141b] dark:text-white leading-none mt-0.5">{totalInventory} units</p>
                    </div>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Low Stock Alerts</p>
                        <p className={`text-base font-black leading-none mt-0.5 ${lowStockCount > 0 ? 'text-[#d41132]' : 'text-emerald-500'}`}>{lowStockCount}</p>
                    </div>
                    {archivedCount > 0 && (
                        <div className="bg-amber-50 dark:bg-amber-900/20 p-2.5 rounded-lg border border-amber-200 dark:border-amber-800">
                            <p className="text-[10px] font-bold text-amber-600 dark:text-amber-400 uppercase tracking-wider">Archived</p>
                            <p className="text-base font-black text-amber-700 dark:text-amber-300 leading-none mt-0.5">{archivedCount}</p>
                        </div>
                    )}
                </>
            }
            filters={
                <>
                    <div className="flex-1 min-w-[200px] relative">
                        <span className="absolute left-3 top-2.5 text-black/40 dark:text-white/40 material-symbols-outlined text-[20px]">search</span>
                        <input
                            type="text"
                            placeholder="Search products..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="w-full pl-10 pr-4 py-2 rounded-lg bg-white dark:bg-[#1a2632] border border-[#e5e7eb] dark:border-[#2d3b4a] focus:ring-2 focus:ring-[#d41132] outline-none transition-all dark:text-white"
                        />
                    </div>
                    <AdminFilterTabs
                        tabs={[
                            { label: 'All Categories', value: 'All' },
                            ...categories.map(cat => ({ label: cat, value: cat }))
                        ]}
                        activeTab={selectedCategory}
                        onTabChange={setSelectedCategory}
                    />
                </>
            }
            pagination={
                <AdminPagination
                    currentPage={currentPage}
                    totalItems={filteredProducts.length}
                    itemsPerPage={itemsPerPage}
                    onPageChange={setCurrentPage}
                    onItemsPerPageChange={(val) => {
                        setItemsPerPage(val);
                        setCurrentPage(1);
                    }}
                />
            }
            bulkActions={
                <AdminBulkActionsBar
                    selectedCount={selectedIds.size}
                    onCancel={() => setSelectedIds(new Set())}
                    onDelete={handleBulkDelete}
                    isDeleting={isBulkDeleting}
                />
            }
        >
            <AdminTable
                headers={['Product', 'Category', 'Price', 'Stock', 'Actions']}
                onSelectAll={toggleSelectAll}
                isAllSelected={filteredProducts.length > 0 && filteredProducts.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage).every(p => selectedIds.has(p.id))}
            >
                {isLoading ? (
                    <tr>
                        <td colSpan={6} className="px-6 py-8 text-center text-gray-500">
                            <div className="flex items-center justify-center gap-2">
                                <span className="material-symbols-outlined animate-spin">progress_activity</span>
                                Loading products...
                            </div>
                        </td>
                    </tr>
                ) : filteredProducts.length === 0 ? (
                    <tr>
                        <td colSpan={6} className="px-6 py-8 text-center text-gray-500">
                            No products found matching your criteria.
                        </td>
                    </tr>
                ) : (
                    filteredProducts.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage).map((product) => (
                        <tr key={product.id} className={`hover:bg-[#f6f7f8] dark:hover:bg-[#17202b] transition-colors group ${selectedIds.has(product.id) ? 'bg-[#d41132]/5 dark:bg-[#d41132]/10' : ''}`}>
                            <td className="px-6 py-4" onClick={(e) => e.stopPropagation()}>
                                <input
                                    type="checkbox"
                                    className="rounded border-slate-300 text-[#d41132] focus:ring-[#d41132] bg-transparent cursor-pointer"
                                    checked={selectedIds.has(product.id)}
                                    onChange={() => toggleSelect(product.id)}
                                />
                            </td>
                            <td className="px-6 py-4">
                                <div className="flex items-center gap-3">
                                    <div className="w-10 h-10 rounded-lg bg-gray-200 dark:bg-gray-700 overflow-hidden flex-shrink-0">
                                        {(product.image || (product.images && product.images[0])) ? (
                                            <img src={product.image || (product.images && product.images[0])} alt={product.name} className="w-full h-full object-cover" />
                                        ) : (
                                            <div className="w-full h-full flex items-center justify-center text-gray-400">
                                                <span className="material-symbols-outlined text-sm">image</span>
                                            </div>
                                        )}
                                    </div>
                                    <div>
                                        <p className={`font-bold text-sm ${!product.isActive ? 'text-gray-400 dark:text-gray-500 line-through' : 'text-[#0d141b] dark:text-white'}`}>{product.name}</p>
                                        <div className="flex items-center gap-1 mt-0.5">
                                            {!product.isActive && (
                                                <span className="inline-block px-1.5 py-0.5 rounded text-[10px] font-bold bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400">ARCHIVED</span>
                                            )}
                                            {product.sale_price && product.isActive && (
                                                <span className="inline-block px-1.5 py-0.5 rounded text-[10px] font-bold bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400">SALE</span>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            </td>
                            <td className="px-6 py-4 text-sm font-medium text-gray-600 dark:text-gray-300">
                                {product.category}
                            </td>
                            <td className="px-6 py-4 text-sm font-bold text-[#0d141b] dark:text-white">
                                {product.sale_price ? (
                                    <div className="flex flex-col">
                                        <span className="text-[#d41132]">${product.sale_price.toFixed(2)}</span>
                                        <span className="text-xs text-gray-400 line-through">${product.price.toFixed(2)}</span>
                                    </div>
                                ) : (
                                    <span>${product.price.toFixed(2)}</span>
                                )}
                            </td>
                            <td className="px-6 py-4 text-sm">
                                <div className="flex flex-col">
                                    <span className={`font-bold ${product.stock === 0 ? 'text-red-500' :
                                        product.stock < 5 ? 'text-amber-500' : 'text-emerald-500'
                                        }`}>
                                        {product.stock} units
                                    </span>
                                    <span className="text-xs text-gray-400">
                                        {product.stock === 0 ? 'Out of Stock' : product.stock < 5 ? 'Low Stock' : 'In Stock'}
                                    </span>
                                </div>
                            </td>
                            <td className="px-6 py-4 text-right relative">
                                <button
                                    onClick={(e) => toggleMenu(product.id, e)}
                                    className="action-menu-trigger text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 p-1 rounded-full hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors"
                                >
                                    <span className="material-symbols-outlined">more_vert</span>
                                </button>
                                {activeMenu === product.id && (
                                    <div className="absolute right-8 top-12 z-20 w-52 bg-white dark:bg-slate-800 rounded-lg shadow-lg border border-slate-200 dark:border-slate-700 py-1 action-menu animate-in zoom-in-95 duration-150 origin-top-right">
                                        <button onClick={() => { openEditModal(product); setActiveMenu(null); }} className="w-full text-left px-4 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700 flex items-center gap-2">
                                            <span className="material-symbols-outlined text-lg">edit</span> Edit Product
                                        </button>
                                        <div className="h-px bg-slate-100 dark:bg-slate-700 my-1"></div>
                                        {product.isActive ? (
                                            <button onClick={() => { handleArchiveProduct(product.id); setActiveMenu(null); }} className="w-full text-left px-4 py-2 text-sm text-amber-600 hover:bg-amber-50 dark:hover:bg-amber-900/20 flex items-center gap-2">
                                                <span className="material-symbols-outlined text-lg">inventory_2</span> Archive
                                            </button>
                                        ) : (
                                            <button onClick={() => { handleRestoreProduct(product.id); setActiveMenu(null); }} className="w-full text-left px-4 py-2 text-sm text-emerald-600 hover:bg-emerald-50 dark:hover:bg-emerald-900/20 flex items-center gap-2">
                                                <span className="material-symbols-outlined text-lg">restore</span> Restore
                                            </button>
                                        )}
                                        <button onClick={() => { handleDeleteProduct(product.id); setActiveMenu(null); }} className="w-full text-left px-4 py-2 text-sm text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 flex items-center gap-2">
                                            <span className="material-symbols-outlined text-lg">delete</span> Delete
                                        </button>
                                    </div>
                                )}
                            </td>
                        </tr>
                    ))
                )}
            </AdminTable>

            <ProductFormModal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                onSubmit={editingProduct ? handleUpdateProduct : handleCreateProduct}
                initialData={editingProduct}
            />

            <ConfirmModal
                isOpen={confirmModal.isOpen}
                title={confirmModal.title}
                message={confirmModal.message}
                onConfirm={confirmModal.onConfirm}
                onCancel={() => setConfirmModal(prev => ({ ...prev, isOpen: false }))}
            />
        </AdminPageLayout>
    );
}

'use client';

import { useEffect, useState } from 'react';
import AdminPageLayout from '@/components/admin/shared/AdminPageLayout';
import AdminTable from '@/components/admin/shared/AdminTable';
import AdminPagination from '@/components/admin/shared/AdminPagination';
import AdminBulkActionsBar from '@/components/admin/shared/AdminBulkActionsBar';

import { useToast } from '@/contexts/ToastContext';
import type { CustomRequest } from '@/lib/services/requestService';
import AdminFilterTabs from '@/components/admin/shared/AdminFilterTabs';
import AdminRequestModal, { pRequest } from '@/components/admin/AdminRequestModal';
import ConfirmModal from '@/components/admin/ConfirmModal';

export default function AdminRequestsPage() {
    const { showToast } = useToast();
    const [requests, setRequests] = useState<CustomRequest[]>([]);
    const [loading, setLoading] = useState(true);
    const [selectedRequest, setSelectedRequest] = useState<CustomRequest | null>(null);
    const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
    const [isBulkDeleting, setIsBulkDeleting] = useState(false);
    const [activeMenu, setActiveMenu] = useState<string | null>(null);
    const [searchQuery, setSearchQuery] = useState('');
    const [statusFilter, setStatusFilter] = useState<string>('all');

    // Stats for notifications (could be fetched separately or derived)
    const [newRequestCount, setNewRequestCount] = useState(0);
    const [currentPage, setCurrentPage] = useState(1);
    const [itemsPerPage, setItemsPerPage] = useState(10);

    // Modal state
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [isMounted, setIsMounted] = useState(false);
    const [confirmModal, setConfirmModal] = useState<{
        isOpen: boolean;
        title: string;
        message: string;
        onConfirm: () => void;
    }>({
        isOpen: false,
        title: '',
        message: '',
        onConfirm: () => { },
    });

    useEffect(() => {
        setIsMounted(true);
    }, []);

    // Close menu when clicking outside
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            const target = event.target as Element;
            if (activeMenu && !target.closest('.action-menu-trigger') && !target.closest('.action-menu')) {
                setActiveMenu(null);
            }
        };
        document.addEventListener('click', handleClickOutside);
        return () => document.removeEventListener('click', handleClickOutside);
    }, [activeMenu]);

    const toggleMenu = (id: string, e: React.MouseEvent) => {
        e.stopPropagation();
        setActiveMenu(activeMenu === id ? null : id);
    };

    // Filtered requests for display
    const filteredRequests = requests.filter(req => {
        const matchesStatus = statusFilter === 'all' || req.status?.toLowerCase() === statusFilter;
        const matchesSearch = searchQuery === '' ||
            req.name?.toLowerCase().includes(searchQuery.toLowerCase()) ||
            req.email?.toLowerCase().includes(searchQuery.toLowerCase()) ||
            req.itemType?.toLowerCase().includes(searchQuery.toLowerCase()) ||
            req.description?.toLowerCase().includes(searchQuery.toLowerCase());
        return matchesStatus && matchesSearch;
    });

    useEffect(() => {
        fetchRequests();
    }, [statusFilter]); // Reload when status filter changes

    // Debounce search
    useEffect(() => {
        const timer = setTimeout(() => {
            fetchRequests();
        }, 500);
        return () => clearTimeout(timer);
    }, [searchQuery]);

    const fetchRequests = async () => {
        try {
            setLoading(true);
            const query = new URLSearchParams();
            if (statusFilter !== 'all') query.append('status', statusFilter);
            if (searchQuery) query.append('search', searchQuery);

            const res = await fetch(`/api/requests?${query.toString()}`);
            const data = await res.json();

            if (data.success) {
                setRequests(data.data);
                // If we have data and no selection, select first? Or keep selection if exists?
                // Logic: if selectedRequest is not in new data, maybe deselect?
                // For now, simple:
                if (!selectedRequest && data.data.length > 0) {
                    setSelectedRequest(data.data[0]);
                } else if (selectedRequest && !data.data.some((r: CustomRequest) => r.id === selectedRequest.id)) {
                    // If selected request is no longer in the list, deselect it
                    setSelectedRequest(null);
                }

                // Update new count
                if (statusFilter === 'all' && !searchQuery) {
                    const count = data.data.filter((r: CustomRequest) =>
                        r.status?.toLowerCase() === 'new'
                    ).length;
                    setNewRequestCount(count);
                }
            }
        } catch (error) {
            console.error('Failed to load requests:', error);
        } finally {
            setLoading(false);
        }
    };

    const handleStatusUpdate = async (id: string, newStatus: string) => {
        const req = requests.find(r => r.id === id);
        try {
            const res = await fetch(`/api/requests/${id}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ status: newStatus }),
            });
            const data = await res.json();
            if (data.success) {
                // Update local state
                setRequests(requests.map(r => r.id === id ? { ...r, status: newStatus as any } : r));
                if (selectedRequest?.id === id) {
                    setSelectedRequest({ ...selectedRequest, status: newStatus as any });
                }
                showToast(`Request #${req?.id.slice(-6).toUpperCase()} for ${req?.name} updated to ${newStatus.replace('_', ' ')}.`, 'success');
            } else {
                showToast(`Failed to update Request #${req?.id.slice(-6).toUpperCase()}.`, 'error');
            }
        } catch (error) {
            console.error('Failed to update status:', error);
            showToast('An error occurred while updating the status.', 'error');
        }
    };

    const handleDelete = async (id: string) => {
        if (isBulkDeleting) return;

        const req = requests.find(r => r.id === id);
        if (!req) return;

        setConfirmModal({
            isOpen: true,
            title: `Archive Request #${req.id.slice(-6).toUpperCase()}`,
            message: `Are you sure you want to archive this custom request from "${req.name}"? This will remove it from the active pipeline.`,
            onConfirm: async () => {
                try {
                    const res = await fetch(`/api/requests/${id}`, { method: 'DELETE' });
                    if (res.ok) {
                        // Optimistic update
                        setRequests(requests.filter(r => r.id !== id));
                        setSelectedIds(prev => {
                            const next = new Set(prev);
                            next.delete(id);
                            return next;
                        });
                        if (selectedRequest?.id === id) {
                            setSelectedRequest(null);
                        }
                        showToast(`Request from "${req.name}" was successfully archived.`, 'success');
                    } else {
                        showToast(`Failed to archive request from "${req.name}".`, 'error');
                    }
                } catch (err) {
                    console.error('Delete error:', err);
                    showToast('An unexpected error occurred while archiving.', 'error');
                } finally {
                    setConfirmModal(prev => ({ ...prev, isOpen: false }));
                }
            }
        });
    };

    const handleBulkDelete = async () => {
        if (isBulkDeleting || selectedIds.size === 0) return;

        const count = selectedIds.size;
        setConfirmModal({
            isOpen: true,
            title: `Archive ${count} Requests`,
            message: `Are you sure you want to archive the ${count} selected requests? They will be removed from the active pipeline.`,
            onConfirm: async () => {
                setIsBulkDeleting(true);
                const idsToDelete = Array.from(selectedIds);
                let successCount = 0;
                let failCount = 0;

                try {
                    await Promise.all(idsToDelete.map(async (id) => {
                        try {
                            const res = await fetch(`/api/requests/${id}`, { method: 'DELETE' });
                            if (res.ok) successCount++;
                            else failCount++;
                        } catch (err) {
                            failCount++;
                        }
                    }));

                    if (successCount > 0) {
                        setRequests(prev => prev.filter(r => !selectedIds.has(r.id)));
                        setSelectedIds(new Set());
                        if (selectedRequest && selectedIds.has(selectedRequest.id)) {
                            setSelectedRequest(null);
                        }
                    }

                    if (failCount > 0) {
                        showToast(`Bulk archive finished with errors. Archived: ${successCount}, Failed: ${failCount}`, 'error');
                    } else {
                        showToast(`Successfully archived ${successCount} requests.`, 'success');
                    }
                } catch (error) {
                    console.error('Bulk archive error:', error);
                    showToast('An error occurred during bulk archiving.', 'error');
                } finally {
                    setIsBulkDeleting(false);
                    setConfirmModal(prev => ({ ...prev, isOpen: false }));
                    fetchRequests();
                }
            }
        });
    };

    const toggleSelectAll = () => {
        const visibleIds = filteredRequests.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage).map(r => r.id);
        const allVisibleSelected = visibleIds.every(id => selectedIds.has(id));

        setSelectedIds(prev => {
            const next = new Set(prev);
            if (allVisibleSelected) {
                visibleIds.forEach(id => next.delete(id));
            } else {
                visibleIds.forEach(id => next.add(id));
            }
            return next;
        });
    };

    const toggleSelect = (id: string) => {
        setSelectedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            return next;
        });
    };

    const handleCreateRequest = async (requestData: pRequest) => {
        try {
            const res = await fetch('/api/requests', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(requestData),
            });
            const result = await res.json();

            if (result.success) {
                await fetchRequests();
                setIsModalOpen(false);
                showToast(`Request created successfully for ${requestData.name}.`, 'success');
            } else {
                showToast('Failed to create request: ' + (result.error || result.message), 'error');
            }
        } catch (error) {
            console.error('Error creating request:', error);
            showToast('An error occurred while creating the request.', 'error');
        }
    };

    const StatusBadge = ({ status }: { status: string }) => {
        const styles: Record<string, string> = {
            new: 'bg-blue-50 text-blue-700 ring-blue-600/20 dark:bg-blue-900/30 dark:text-blue-400',
            quote_sent: 'bg-orange-50 text-orange-700 ring-orange-600/20 dark:bg-orange-900/30 dark:text-orange-400',
            quoted: 'bg-orange-50 text-orange-700 ring-orange-600/20 dark:bg-orange-900/30 dark:text-orange-400',
            in_progress: 'bg-yellow-50 text-yellow-700 ring-yellow-600/20 dark:bg-yellow-900/30 dark:text-yellow-400',
            completed: 'bg-green-50 text-green-700 ring-green-600/20 dark:bg-green-900/30 dark:text-green-400',
            cancelled: 'bg-red-50 text-red-700 ring-red-600/20 dark:bg-red-900/30 dark:text-red-400',
        };
        const key = status.toLowerCase();
        const style = styles[key] || styles.new;
        // Format the label
        const label = status === 'QUOTE_SENT' ? 'Quote Sent'
            : status.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase());

        return (
            <span className={`inline-flex items-center rounded-md px-2 py-1 text-xs font-medium ring-1 ring-inset ${style}`}>
                {label}
            </span>
        );
    };

    return (
        <AdminPageLayout
            title="Custom Request Pipeline"
            subtitle="Manage and track incoming custom inquiries."
            stats={
                <>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Total Requests</p>
                        <p className="text-base font-black text-[#0d141b] dark:text-white leading-none mt-0.5">{requests.length}</p>
                    </div>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">New</p>
                        <p className="text-base font-black text-blue-600 leading-none mt-0.5">{newRequestCount}</p>
                    </div>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Completed</p>
                        <p className="text-base font-black text-emerald-500 leading-none mt-0.5">{requests.filter(r => r.status?.toLowerCase() === 'completed').length}</p>
                    </div>
                </>
            }
            actions={
                <button
                    onClick={() => setIsModalOpen(true)}
                    className="bg-[#d41132] hover:bg-[#b30f2a] text-white px-4 py-2 rounded-lg font-bold text-sm shadow-md transition-colors flex items-center gap-2"
                >
                    <span className="material-symbols-outlined text-lg">add</span>
                    New Request
                </button>
            }
            filters={
                <div className="flex flex-col lg:flex-row justify-between items-center gap-4 w-full">
                    <div className="relative w-full lg:max-w-md group">
                        <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none text-slate-400">
                            <span className="material-symbols-outlined">search</span>
                        </div>
                        <input
                            className="block w-full rounded-lg border-0 py-2.5 pl-10 pr-4 text-slate-900 ring-1 ring-inset ring-slate-200 focus:ring-2 focus:ring-[#d41132] sm:text-sm bg-slate-50 dark:bg-slate-800 dark:ring-slate-700 dark:text-white transition-all outline-none"
                            placeholder="Search requests..."
                            type="text"
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                        />
                    </div>
                    <AdminFilterTabs
                        tabs={[
                            { label: 'All', value: 'all' },
                            { label: 'New', value: 'new' },
                            { label: 'Quoted', value: 'quoted' },
                            { label: 'In Progress', value: 'in_progress' },
                            { label: 'Completed', value: 'completed' },
                        ]}
                        activeTab={statusFilter}
                        onTabChange={setStatusFilter}
                    />
                </div>
            }
            pagination={
                <AdminPagination
                    currentPage={currentPage}
                    totalItems={filteredRequests.length}
                    itemsPerPage={itemsPerPage}
                    onPageChange={setCurrentPage}
                    onItemsPerPageChange={(val) => {
                        setItemsPerPage(val);
                        setCurrentPage(1);
                    }}
                />
            }
            bulkActions={
                <AdminBulkActionsBar
                    selectedCount={selectedIds.size}
                    onCancel={() => setSelectedIds(new Set())}
                    onDelete={handleBulkDelete}
                    isDeleting={isBulkDeleting}
                />
            }
        >
            <AdminTable
                headers={['Customer', 'Project', 'Budget', 'Status', 'Date', 'Actions']}
                onSelectAll={toggleSelectAll}
                isAllSelected={filteredRequests.length > 0 && filteredRequests.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage).every(r => selectedIds.has(r.id))}
            >
                {loading ? (
                    <tr>
                        <td colSpan={7} className="py-12 text-center text-slate-500 dark:text-slate-400 font-bold">
                            <div className="flex items-center justify-center gap-2">
                                <span className="material-symbols-outlined animate-spin text-2xl text-[#d41132]">progress_activity</span>
                                Loading requests...
                            </div>
                        </td>
                    </tr>
                ) : filteredRequests.length === 0 ? (
                    <tr>
                        <td colSpan={7} className="py-12 text-center text-slate-500 dark:text-slate-400">
                            No requests found.
                        </td>
                    </tr>
                ) : (
                    filteredRequests.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage).map((req) => (
                        <tr
                            key={req.id}
                            onClick={() => setSelectedRequest(req)}
                            className={`group hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors cursor-pointer ${selectedIds.has(req.id) ? 'bg-[#d41132]/5 dark:bg-[#d41132]/10' : ''}`}
                        >
                            <td className="py-4 px-6" onClick={(e) => e.stopPropagation()}>
                                <input
                                    type="checkbox"
                                    className="rounded border-slate-300 text-[#d41132] focus:ring-[#d41132] bg-transparent cursor-pointer"
                                    checked={selectedIds.has(req.id)}
                                    onChange={() => toggleSelect(req.id)}
                                />
                            </td>
                            <td className="py-4 px-6">
                                <div className="flex items-center gap-3">
                                    <div className="size-8 rounded-full bg-slate-100 dark:bg-slate-800 text-slate-600 flex items-center justify-center text-xs font-bold shrink-0">
                                        {req.name?.slice(0, 2).toUpperCase()}
                                    </div>
                                    <div className="flex flex-col">
                                        <span className="text-sm font-bold text-slate-900 dark:text-white leading-tight">{req.name}</span>
                                        <span className="text-[10px] text-slate-400 font-mono tracking-tighter">#{req.id.slice(-6).toUpperCase()}</span>
                                    </div>
                                </div>
                            </td>
                            <td className="py-4 px-6 text-sm text-slate-700 dark:text-slate-300 font-medium">{req.itemType}</td>
                            <td className="py-4 px-6 text-sm text-slate-900 dark:text-white font-black tabular-nums">${req.budget}</td>
                            <td className="py-4 px-6">
                                <StatusBadge status={req.status} />
                            </td>
                            <td className="py-4 px-6 text-sm text-slate-500 dark:text-slate-400 font-medium tabular-nums">
                                {isMounted ? new Date(req.createdAt).toLocaleDateString() : '...'}
                            </td>
                            <td className="py-4 px-6 text-right relative" onClick={(e) => e.stopPropagation()}>
                                <button
                                    onClick={(e) => toggleMenu(req.id, e)}
                                    className="action-menu-trigger text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 p-1 rounded-full hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors"
                                >
                                    <span className="material-symbols-outlined">more_vert</span>
                                </button>
                                {activeMenu === req.id && (
                                    <div className="absolute right-8 top-12 z-20 w-48 bg-white dark:bg-slate-800 rounded-lg shadow-lg border border-slate-200 dark:border-slate-700 py-1 action-menu animate-in zoom-in-95 duration-150 origin-top-right">
                                        <button onClick={() => { setSelectedRequest(req); setActiveMenu(null); }} className="w-full text-left px-4 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700 flex items-center gap-2">
                                            <span className="material-symbols-outlined text-lg">visibility</span> View Details
                                        </button>
                                        <button onClick={() => { handleStatusUpdate(req.id, 'quoted'); setActiveMenu(null); }} className="w-full text-left px-4 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700 flex items-center gap-2">
                                            <span className="material-symbols-outlined text-lg">request_quote</span> Approve & Quote
                                        </button>
                                        <div className="h-px bg-slate-100 dark:bg-slate-700 my-1"></div>
                                        <button onClick={() => { handleDelete(req.id); setActiveMenu(null); }} className="w-full text-left px-4 py-2 text-sm text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 flex items-center gap-2">
                                            <span className="material-symbols-outlined text-lg">delete</span> Delete
                                        </button>
                                    </div>
                                )}
                            </td>
                        </tr>
                    ))
                )}
            </AdminTable>

            <AdminRequestModal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                onSubmit={handleCreateRequest}
            />

            {/* Detail Modal */}
            {selectedRequest && (
                <div className="fixed inset-0 bg-black/40 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
                    <div className="bg-white dark:bg-[#15202b] w-full sm:max-w-2xl max-h-[90vh] rounded-2xl shadow-2xl relative animate-in zoom-in-95 duration-200 p-8 flex flex-col">
                        <button
                            onClick={() => setSelectedRequest(null)}
                            className="absolute top-6 right-6 text-slate-400 hover:text-slate-600 transition-colors"
                        >
                            <span className="material-symbols-outlined">close</span>
                        </button>

                        <div className="flex items-center gap-4 mb-8 shrink-0">
                            <div className="w-12 h-12 rounded-xl bg-orange-100 dark:bg-orange-900/30 flex items-center justify-center text-orange-600 font-bold">
                                <span className="material-symbols-outlined text-3xl">draw</span>
                            </div>
                            <div>
                                <h3 className="text-xl font-bold dark:text-white text-slate-900">Request Detail</h3>
                                <p className="text-sm text-slate-500 font-mono">#{selectedRequest.id.slice(-8).toUpperCase()}</p>
                            </div>
                        </div>

                        <div className="flex-1 overflow-y-auto pr-2 space-y-6 min-h-0">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 border-b border-slate-100 dark:border-slate-800 pb-6">
                                <div>
                                    <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-1">Customer</label>
                                    <p className="font-semibold dark:text-white text-slate-900">{selectedRequest.name}</p>
                                    <p className="text-sm text-slate-500">{selectedRequest.email}</p>
                                </div>
                                <div>
                                    <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-1">Status</label>
                                    <StatusBadge status={selectedRequest.status} />
                                </div>
                                <div>
                                    <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-1">Budget</label>
                                    <p className="font-bold text-slate-900 dark:text-emerald-400">${selectedRequest.budget}</p>
                                </div>
                                <div>
                                    <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-1">Deadline</label>
                                    <p className="font-semibold dark:text-white text-slate-900">{selectedRequest.deadline}</p>
                                </div>
                            </div>
                            <div>
                                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-2">Description</label>
                                <div className="bg-slate-50 dark:bg-slate-900/50 rounded-xl p-4 border border-slate-100 dark:border-slate-800 text-sm text-slate-600 dark:text-slate-300 leading-relaxed whitespace-pre-wrap">
                                    {selectedRequest.description}
                                </div>
                            </div>
                        </div>

                        <div className="mt-8 pt-8 border-t border-slate-100 dark:border-slate-800 flex items-center justify-between shrink-0">
                            <div className="flex gap-2">
                                <button
                                    onClick={() => handleStatusUpdate(selectedRequest.id, 'quoted')}
                                    className="px-6 py-2.5 bg-[#d41132] hover:bg-[#b30f2a] text-white font-bold rounded-lg transition-all shadow-md text-sm"
                                >
                                    Approve & Quote
                                </button>
                                <button className="px-6 py-2.5 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 text-slate-600 dark:text-white font-bold rounded-lg transition-all text-sm">
                                    Send Message
                                </button>
                            </div>
                            <button
                                onClick={() => { handleDelete(selectedRequest.id); setSelectedRequest(null); }}
                                className="px-6 py-2.5 border border-red-200 text-red-600 hover:bg-red-50 font-bold rounded-lg transition-all text-sm"
                            >
                                Delete Request
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {/* Detail Modal */}
            <ConfirmModal
                isOpen={confirmModal.isOpen}
                title={confirmModal.title}
                message={confirmModal.message}
                onConfirm={confirmModal.onConfirm}
                onCancel={() => setConfirmModal(prev => ({ ...prev, isOpen: false }))}
            />
        </AdminPageLayout>
    );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { useToast } from '@/contexts/ToastContext';
import AdminPageLayout from '@/components/admin/shared/AdminPageLayout';
import AdminFilterTabs from '@/components/admin/shared/AdminFilterTabs';
import AdminTable from '@/components/admin/shared/AdminTable';
import AdminPagination from '@/components/admin/shared/AdminPagination';
import AdminBulkActionsBar from '@/components/admin/shared/AdminBulkActionsBar';
import ConfirmModal from '@/components/admin/ConfirmModal';

interface Review {
    id: string;
    product_id: string | null;
    product_name?: string;
    customer_name: string;
    customer_email: string | null;
    rating: number;
    comment: string | null;
    status: 'pending' | 'approved' | 'rejected';
    is_featured: boolean;
    helpful_count: number;
    created_at: string;
}

export default function AdminReviewsPage() {
    const [reviews, setReviews] = useState<Review[]>([]);
    const [loading, setLoading] = useState(true);
    const [filter, setFilter] = useState<'all' | 'pending' | 'approved' | 'rejected'>('all');
    const { showToast } = useToast();
    const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
    const [isBulkUpdating, setIsBulkUpdating] = useState(false);
    const [currentPage, setCurrentPage] = useState(1);
    const [itemsPerPage, setItemsPerPage] = useState(10);
    const [activeMenu, setActiveMenu] = useState<string | null>(null);
    const [showCreateModal, setShowCreateModal] = useState(false);
    const [products, setProducts] = useState<{ id: string; name: string }[]>([]);
    const [createForm, setCreateForm] = useState({
        product_id: '',
        customer_name: '',
        customer_email: '',
        rating: '5',
        comment: '',
        status: 'pending' as const,
    });
    const [createSaving, setCreateSaving] = useState(false);
    const [confirmModal, setConfirmModal] = useState<{
        isOpen: boolean;
        title: string;
        message: string;
        onConfirm: () => void;
    }>({
        isOpen: false,
        title: '',
        message: '',
        onConfirm: () => { },
    });

    // Close menu when clicking outside
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            const target = event.target as Element;
            if (activeMenu && !target.closest('.action-menu-trigger') && !target.closest('.action-menu')) {
                setActiveMenu(null);
            }
        };
        document.addEventListener('click', handleClickOutside);
        return () => document.removeEventListener('click', handleClickOutside);
    }, [activeMenu]);

    useEffect(() => {
        fetch('/api/products').then(r => r.json()).then(d => {
            if (d.success) setProducts(d.data.map((p: any) => ({ id: p.id, name: p.name })));
        }).catch(() => {});
    }, []);

    const toggleMenu = (id: string, e: React.MouseEvent) => {
        e.stopPropagation();
        setActiveMenu(activeMenu === id ? null : id);
    };

    const load = useCallback(async () => {
        setLoading(true);
        const res = await fetch('/api/reviews');
        const data = await res.json();
        if (data.success) setReviews(data.data);
        setLoading(false);
    }, []);

    useEffect(() => { load(); }, [load]);

    const updateStatus = async (id: string, status: string) => {
        const review = reviews.find(r => r.id === id);
        const res = await fetch(`/api/reviews?id=${id}`, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ status }) });
        const data = await res.json();
        if (data.success) { showToast(`Review from "${review?.customer_name}" marked as ${status}.`, 'success'); load(); }
        else showToast('Failed to update review status.', 'error');
    };

    const toggleFeatured = async (review: Review) => {
        const res = await fetch(`/api/reviews?id=${review.id}`, { method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ is_featured: !review.is_featured }) });
        if ((await res.json()).success) { showToast(`Review from "${review.customer_name}" was ${review.is_featured ? 'unfeatured' : 'featured'}.`, 'success'); load(); }
    };

    const handleDelete = async (id: string) => {
        const review = reviews.find(r => r.id === id);
        setConfirmModal({
            isOpen: true,
            title: `Delete Review from "${review?.customer_name}"`,
            message: 'Delete this review permanently? This action cannot be undone.',
            onConfirm: async () => {
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
                const res = await fetch(`/api/reviews?id=${id}`, { method: 'DELETE' });
                if ((await res.json()).success) { showToast(`Review from "${review?.customer_name}" was deleted successfully.`, 'success'); load(); }
                else showToast(`Failed to delete review from "${review?.customer_name}".`, 'error');
            }
        });
    };

    const handleBulkDelete = async () => {
        if (isBulkUpdating || selectedIds.size === 0) return;
        setConfirmModal({
            isOpen: true,
            title: 'Delete Reviews',
            message: `Are you sure you want to delete ${selectedIds.size} reviews? This action cannot be undone.`,
            onConfirm: async () => {
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
                setIsBulkUpdating(true);
                try {
                    const results = await Promise.all(
                        Array.from(selectedIds).map(id =>
                            fetch(`/api/reviews?id=${id}`, { method: 'DELETE' }).then(res => res.json())
                        )
                    );
                    const successCount = results.filter(r => r.success).length;
                    const failCount = selectedIds.size - successCount;
                    if (failCount > 0) {
                        showToast(`Bulk delete finished. ${successCount} deleted, ${failCount} failed.`, 'error');
                    } else {
                        showToast(`${successCount} reviews were deleted successfully.`, 'success');
                    }
                    load();
                    setSelectedIds(new Set());
                } catch (err) {
                    showToast('An error occurred during bulk deletion.', 'error');
                } finally {
                    setIsBulkUpdating(false);
                }
            }
        });
    };

    const toggleSelectAll = () => {
        const visibleItems = filtered.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);
        const allVisibleSelected = visibleItems.every(r => selectedIds.has(r.id));

        setSelectedIds(prev => {
            const next = new Set(prev);
            if (allVisibleSelected) {
                visibleItems.forEach(r => next.delete(r.id));
            } else {
                visibleItems.forEach(r => next.add(r.id));
            }
            return next;
        });
    };

    const toggleSelect = (id: string) => {
        setSelectedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            return next;
        });
    };

    const handleCreateReview = async () => {
        setCreateSaving(true);
        try {
            const res = await fetch('/api/reviews', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    ...createForm,
                    rating: parseInt(createForm.rating),
                }),
            });
            const data = await res.json();
            if (data.success) {
                showToast(`Review for "${createForm.customer_name}" created successfully.`, 'success');
                setShowCreateModal(false);
                setCreateForm({ product_id: '', customer_name: '', customer_email: '', rating: '5', comment: '', status: 'pending' });
                load();
            } else {
                showToast(data.message || 'Failed to create review.', 'error');
            }
        } catch (err) {
            showToast('An error occurred while creating the review.', 'error');
        } finally {
            setCreateSaving(false);
        }
    };

    const filtered = filter === 'all' ? reviews : reviews.filter(r => r.status === filter);
    const counts = { all: reviews.length, pending: reviews.filter(r => r.status === 'pending').length, approved: reviews.filter(r => r.status === 'approved').length, rejected: reviews.filter(r => r.status === 'rejected').length };
    const totalPages = Math.ceil(filtered.length / itemsPerPage);
    const paginatedReviews = filtered.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

    const StarRating = ({ rating }: { rating: number }) => (
        <div className="flex gap-0.5">
            {[1, 2, 3, 4, 5].map(i => (
                <span key={i} className={`material-symbols-outlined text-[14px] ${i <= rating ? 'text-amber-400' : 'text-slate-200 dark:text-slate-600'}`} style={i <= rating ? { fontVariationSettings: "'FILL' 1" } : {}}>star</span>
            ))}
        </div>
    );

    return (
        <AdminPageLayout
            title="Reviews"
            subtitle="Moderate customer reviews and control what appears on your storefront"
            actions={
                <button
                    onClick={() => setShowCreateModal(true)}
                    className="flex items-center gap-2 px-4 py-2 bg-[#d41132] hover:bg-[#b30f2a] text-white text-sm font-bold rounded-lg shadow-md transition-colors"
                >
                    <span className="material-symbols-outlined text-[20px]">add</span>
                    Add Review
                </button>
            }
            stats={
                <>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">All</p>
                        <p className="text-base font-black text-[#0d141b] dark:text-white leading-none mt-0.5">{counts.all}</p>
                    </div>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Pending</p>
                        <p className="text-base font-black text-[#0d141b] dark:text-white leading-none mt-0.5">{counts.pending}</p>
                    </div>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Approved</p>
                        <p className="text-base font-black text-[#0d141b] dark:text-white leading-none mt-0.5">{counts.approved}</p>
                    </div>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Rejected</p>
                        <p className="text-base font-black text-[#0d141b] dark:text-white leading-none mt-0.5">{counts.rejected}</p>
                    </div>
                </>
            }
            filters={
                <AdminFilterTabs
                    tabs={[
                        { label: 'All Reviews', value: 'all' },
                        { label: 'Pending', value: 'pending' },
                        { label: 'Approved', value: 'approved' },
                        { label: 'Rejected', value: 'rejected' },
                    ]}
                    activeTab={filter}
                    onTabChange={(val) => { setFilter(val as any); setCurrentPage(1); }}
                />
            }
            pagination={
                <AdminPagination
                    currentPage={currentPage}
                    totalItems={filtered.length}
                    itemsPerPage={itemsPerPage}
                    onPageChange={setCurrentPage}
                    onItemsPerPageChange={(val) => {
                        setItemsPerPage(val);
                        setCurrentPage(1);
                    }}
                />
            }
            bulkActions={
                <AdminBulkActionsBar
                    selectedCount={selectedIds.size}
                    onCancel={() => setSelectedIds(new Set())}
                    onDelete={handleBulkDelete}
                    isDeleting={isBulkUpdating}
                />
            }
        >
            <AdminTable
                    headers={['Customer', 'Rating', 'Comment', 'Product', 'Status', 'Actions']}
                    onSelectAll={toggleSelectAll}
                    isAllSelected={filtered.length > 0 && paginatedReviews.every(r => selectedIds.has(r.id))}
                >
                    {loading ? (
                        <tr>
                            <td colSpan={7} className="py-12 text-center text-slate-500 dark:text-slate-400 font-bold">
                                <div className="flex items-center justify-center gap-2">
                                    <span className="material-symbols-outlined animate-spin text-2xl text-[#d41132]">progress_activity</span>
                                    Loading reviews...
                                </div>
                            </td>
                        </tr>
                    ) : filtered.length === 0 ? (
                        <tr>
                            <td colSpan={7} className="py-12 text-center text-slate-500 dark:text-slate-400">
                                No reviews found.
                            </td>
                        </tr>
                    ) : (
                        paginatedReviews.map((review) => (
                            <tr key={review.id} className={`group hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors ${selectedIds.has(review.id) ? 'bg-[#d41132]/5 dark:bg-[#d41132]/10' : ''}`}>
                                <td className="py-4 px-6" onClick={(e) => e.stopPropagation()}>
                                    <input
                                        type="checkbox"
                                        className="rounded border-slate-300 text-[#d41132] focus:ring-[#d41132] bg-transparent cursor-pointer"
                                        checked={selectedIds.has(review.id)}
                                        onChange={() => toggleSelect(review.id)}
                                    />
                                </td>
                                <td className="py-3 px-6">
                                    <div className="flex items-center gap-3">
                                        <div className="w-9 h-9 rounded-full bg-slate-100 dark:bg-slate-700 flex items-center justify-center font-bold text-slate-600 dark:text-slate-300 text-xs flex-shrink-0">
                                            {review.customer_name[0].toUpperCase()}
                                        </div>
                                        <div>
                                            <p className="font-bold text-slate-900 dark:text-white text-sm leading-tight">{review.customer_name}</p>
                                            {review.customer_email && <p className="text-[10px] text-slate-400 truncate max-w-[120px]">{review.customer_email}</p>}
                                        </div>
                                    </div>
                                </td>
                                <td className="py-3 px-6">
                                    <div className="flex flex-col gap-1">
                                        <StarRating rating={review.rating} />
                                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">{new Date(review.created_at).toLocaleDateString()}</p>
                                    </div>
                                </td>
                                <td className="py-3 px-6">
                                    <p className="text-sm text-slate-600 dark:text-slate-300 leading-relaxed italic line-clamp-2 max-w-[250px]">
                                        "{review.comment || 'No comment'}"
                                    </p>
                                </td>
                                <td className="py-3 px-6">
                                    <p className="text-xs font-bold text-slate-900 dark:text-white truncate max-w-[150px]">{review.product_name || 'General'}</p>
                                </td>
                                <td className="py-3 px-6 text-right">
                                    <div className="flex flex-col gap-1 items-end">
                                        <span className={`text-[9px] font-black uppercase tracking-widest px-2 py-0.5 rounded-full ${review.status === 'approved' ? 'bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-400' : review.status === 'pending' ? 'bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-400' : 'bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-400'}`}>
                                            {review.status}
                                        </span>
                                        {review.is_featured && (
                                            <span className="text-[9px] font-black uppercase tracking-widest bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-400 px-2 py-0.5 rounded-full mt-1">Featured</span>
                                        )}
                                    </div>
                                </td>
                                <td className="px-6 py-4 text-right relative">
                                    <button onClick={(e) => toggleMenu(review.id, e)}
                                        className="action-menu-trigger text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 p-1 rounded-full hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors">
                                        <span className="material-symbols-outlined">more_vert</span>
                                    </button>
                                    {activeMenu === review.id && (
                                        <div className="absolute right-8 top-12 z-20 w-48 bg-white dark:bg-slate-800 rounded-lg shadow-lg border border-slate-200 dark:border-slate-700 py-1 action-menu animate-in zoom-in-95 duration-150 origin-top-right">
                                            {review.status !== 'approved' && (
                                                <button onClick={() => { updateStatus(review.id, 'approved'); setActiveMenu(null); }} className="w-full text-left px-4 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700 flex items-center gap-2">
                                                    <span className="material-symbols-outlined text-lg">check</span> Approve
                                                </button>
                                            )}
                                            {review.status !== 'rejected' && (
                                                <button onClick={() => { updateStatus(review.id, 'rejected'); setActiveMenu(null); }} className="w-full text-left px-4 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700 flex items-center gap-2">
                                                    <span className="material-symbols-outlined text-lg">close</span> Reject
                                                </button>
                                            )}
                                            <button onClick={() => { toggleFeatured(review); setActiveMenu(null); }} className="w-full text-left px-4 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700 flex items-center gap-2">
                                                <span className="material-symbols-outlined text-lg">star</span> {review.is_featured ? 'Unfeature' : 'Mark Featured'}
                                            </button>
                                            <div className="h-px bg-slate-100 dark:bg-slate-700 my-1"></div>
                                            <button onClick={() => { handleDelete(review.id); setActiveMenu(null); }} className="w-full text-left px-4 py-2 text-sm text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 flex items-center gap-2">
                                                <span className="material-symbols-outlined text-lg">delete</span> Delete
                                            </button>
                                        </div>
                                    )}
                                </td>
                            </tr>
                        ))
                    )}
                </AdminTable>
            {showCreateModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
                    <div className="bg-white dark:bg-slate-800 rounded-2xl w-full max-w-lg shadow-2xl border border-slate-200 dark:border-slate-700">
                        <div className="flex items-center justify-between p-6 border-b border-slate-200 dark:border-slate-700">
                            <h2 className="text-lg font-black text-slate-900 dark:text-white">Add Review</h2>
                            <button onClick={() => setShowCreateModal(false)} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg">
                                <span className="material-symbols-outlined">close</span>
                            </button>
                        </div>
                        <div className="p-6 space-y-4">
                            <div>
                                <label className="block text-xs font-bold uppercase tracking-widest text-slate-500 mb-1.5">Product</label>
                                <select value={createForm.product_id} onChange={e => setCreateForm(f => ({ ...f, product_id: e.target.value }))}
                                    className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm focus:border-[#d41132] outline-none dark:text-white">
                                    <option value="">Select product...</option>
                                    {products.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                                </select>
                            </div>
                            <div>
                                <label className="block text-xs font-bold uppercase tracking-widest text-slate-500 mb-1.5">Customer Name *</label>
                                <input value={createForm.customer_name} onChange={e => setCreateForm(f => ({ ...f, customer_name: e.target.value }))}
                                    className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm focus:border-[#d41132] outline-none dark:text-white" />
                            </div>
                            <div>
                                <label className="block text-xs font-bold uppercase tracking-widest text-slate-500 mb-1.5">Rating *</label>
                                <select value={createForm.rating} onChange={e => setCreateForm(f => ({ ...f, rating: e.target.value }))}
                                    className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm focus:border-[#d41132] outline-none dark:text-white">
                                    {[5,4,3,2,1].map(n => <option key={n} value={String(n)}>{n} Star{n > 1 ? 's' : ''}</option>)}
                                </select>
                            </div>
                            <div>
                                <label className="block text-xs font-bold uppercase tracking-widest text-slate-500 mb-1.5">Comment</label>
                                <textarea value={createForm.comment} onChange={e => setCreateForm(f => ({ ...f, comment: e.target.value }))} rows={3}
                                    className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm focus:border-[#d41132] outline-none dark:text-white resize-none" />
                            </div>
                        </div>
                        <div className="flex gap-3 p-6 border-t border-slate-200 dark:border-slate-700">
                            <button onClick={() => setShowCreateModal(false)} className="flex-1 py-2.5 rounded-xl border border-slate-200 dark:border-slate-600 text-slate-600 dark:text-slate-300 font-bold text-sm hover:bg-slate-50 transition-colors">Cancel</button>
                            <button onClick={handleCreateReview} disabled={createSaving || !createForm.customer_name}
                                className="flex-1 py-2.5 rounded-xl bg-[#d41132] hover:bg-[#b30f2a] text-white font-bold text-sm transition-colors disabled:opacity-50">
                                {createSaving ? 'Creating...' : 'Create Review'}
                            </button>
                        </div>
                    </div>
                </div>
            )}
            <ConfirmModal
                isOpen={confirmModal.isOpen}
                title={confirmModal.title}
                message={confirmModal.message}
                onConfirm={confirmModal.onConfirm}
                onCancel={() => setConfirmModal(prev => ({ ...prev, isOpen: false }))}
            />
        </AdminPageLayout>
    );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { useToast } from '@/contexts/ToastContext';
import AdminPageLayout from '@/components/admin/shared/AdminPageLayout';
import AdminFilterTabs from '@/components/admin/shared/AdminFilterTabs';
import AdminTable from '@/components/admin/shared/AdminTable';
import AdminPagination from '@/components/admin/shared/AdminPagination';
import AdminBulkActionsBar from '@/components/admin/shared/AdminBulkActionsBar';
import ConfirmModal from '@/components/admin/ConfirmModal';

interface ShippingZone {
    id: string;
    name: string;
    regions: string;
    handling_days: number;
    rate: number;
    free_above: number | null;
    is_active: boolean;
}

const emptyForm = { name: '', regions: '', handling_days: '7', rate: '0', free_above: '', is_active: true };

export default function AdminShippingPage() {
    const [zones, setZones] = useState<ShippingZone[]>([]);
    const [loading, setLoading] = useState(true);
    const [showModal, setShowModal] = useState(false);
    const [editingZone, setEditingZone] = useState<ShippingZone | null>(null);
    const [form, setForm] = useState(emptyForm);
    const [saving, setSaving] = useState(false);
    const { showToast } = useToast();
    const [statusFilter, setStatusFilter] = useState<'all' | 'active' | 'inactive'>('all');
    const [activeMenu, setActiveMenu] = useState<string | null>(null);
    const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
    const [isBulkDeleting, setIsBulkDeleting] = useState(false);
    const [currentPage, setCurrentPage] = useState(1);
    const [itemsPerPage, setItemsPerPage] = useState(10);
    const [confirmModal, setConfirmModal] = useState<{
        isOpen: boolean;
        title: string;
        message: string;
        onConfirm: () => void;
    }>({
        isOpen: false,
        title: '',
        message: '',
        onConfirm: () => { },
    });

    // Close menu when clicking outside
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            const target = event.target as Element;
            if (activeMenu && !target.closest('.action-menu-trigger') && !target.closest('.action-menu')) {
                setActiveMenu(null);
            }
        };
        document.addEventListener('click', handleClickOutside);
        return () => document.removeEventListener('click', handleClickOutside);
    }, [activeMenu]);

    const toggleMenu = (id: string, e: React.MouseEvent) => {
        e.stopPropagation();
        setActiveMenu(activeMenu === id ? null : id);
    };

    const load = useCallback(async () => {
        setLoading(true);
        try {
            const res = await fetch('/api/shipping-zones');
            const data = await res.json();
            if (data.success) setZones(data.data || []);
        } catch (_) { }
        setLoading(false);
    }, []);

    useEffect(() => { load(); }, [load]);

    const openCreate = () => { setEditingZone(null); setForm(emptyForm); setShowModal(true); };
    const openEdit = (zone: ShippingZone) => {
        setEditingZone(zone);
        setForm({ name: zone.name, regions: zone.regions, handling_days: String(zone.handling_days), rate: String(zone.rate), free_above: zone.free_above ? String(zone.free_above) : '', is_active: zone.is_active });
        setShowModal(true);
    };

    const handleSave = async () => {
        setSaving(true);
        const payload = { name: form.name, regions: form.regions, handling_days: parseInt(form.handling_days), rate: parseFloat(form.rate), free_above: form.free_above ? parseFloat(form.free_above) : null, is_active: form.is_active };
        const method = editingZone ? 'PUT' : 'POST';
        const url = editingZone ? `/api/shipping-zones?id=${editingZone.id}` : '/api/shipping-zones';
        const res = await fetch(url, { method, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
        const data = await res.json();
        if (data.success) { showToast(editingZone ? `Shipping Zone "${form.name}" updated successfully.` : `Shipping Zone "${form.name}" created successfully.`, 'success'); setShowModal(false); load(); }
        else showToast(data.message || 'Failed to save shipping zone.', 'error');
        setSaving(false);
    };

    const handleDelete = async (id: string) => {
        const zone = zones.find(z => z.id === id);
        setConfirmModal({
            isOpen: true,
            title: `Delete Shipping Zone "${zone?.name}"`,
            message: 'Delete this shipping zone? This action cannot be undone.',
            onConfirm: async () => {
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
                const res = await fetch(`/api/shipping-zones?id=${id}`, { method: 'DELETE' });
                if ((await res.json()).success) { showToast(`Shipping Zone "${zone?.name}" was deleted successfully.`, 'success'); load(); }
                else showToast(`Failed to delete shipping zone "${zone?.name}".`, 'error');
            }
        });
    };

    const handleBulkDelete = async () => {
        if (isBulkDeleting || selectedIds.size === 0) return;
        setConfirmModal({
            isOpen: true,
            title: 'Delete Shipping Zones',
            message: `Are you sure you want to delete ${selectedIds.size} shipping zones? This action cannot be undone.`,
            onConfirm: async () => {
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
                setIsBulkDeleting(true);
                try {
                    const results = await Promise.all(
                        Array.from(selectedIds).map(id =>
                            fetch(`/api/shipping-zones?id=${id}`, { method: 'DELETE' }).then(res => res.json())
                        )
                    );
                    const successCount = results.filter(r => r.success).length;
                    const failCount = selectedIds.size - successCount;
                    if (failCount > 0) {
                        showToast(`Bulk delete finished. ${successCount} deleted, ${failCount} failed.`, 'error');
                    } else {
                        showToast(`${successCount} shipping zones were deleted successfully.`, 'success');
                    }
                    load();
                    setSelectedIds(new Set());
                } catch (err) {
                    showToast('An error occurred during bulk deletion.', 'error');
                } finally {
                    setIsBulkDeleting(false);
                }
            }
        });
    };

    const toggleSelectAll = () => {
        const visibleItems = filteredZones.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);
        const allVisibleSelected = visibleItems.every(z => selectedIds.has(z.id));

        setSelectedIds(prev => {
            const next = new Set(prev);
            if (allVisibleSelected) {
                visibleItems.forEach(z => next.delete(z.id));
            } else {
                visibleItems.forEach(z => next.add(z.id));
            }
            return next;
        });
    };

    const toggleSelect = (id: string) => {
        setSelectedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            return next;
        });
    };

    const formatRate = (zone: ShippingZone) => {
        if (zone.rate === 0) return 'Free';
        return `$${zone.rate.toFixed(2)}${zone.free_above ? ` (free above $${zone.free_above})` : ''}`;
    };

    const filteredZones = zones.filter(z => {
        if (statusFilter === 'active') return z.is_active;
        if (statusFilter === 'inactive') return !z.is_active;
        return true;
    });

    return (
        <AdminPageLayout
            title="Shipping Zones"
            subtitle="Manage shipping rates and delivery regions for your store"
            actions={
                <button onClick={openCreate} className="flex items-center gap-2 bg-[#d41132] hover:bg-[#b30f2a] text-white px-5 py-2.5 rounded-xl font-bold text-sm transition-all shadow-md">
                    <span className="material-symbols-outlined text-[18px]">add</span> Add Zone
                </button>
            }
            filters={
                <AdminFilterTabs
                    tabs={[
                        { label: 'All Zones', value: 'all' },
                        { label: 'Active', value: 'active' },
                        { label: 'Inactive', value: 'inactive' },
                    ]}
                    activeTab={statusFilter}
                    onTabChange={(val) => setStatusFilter(val as any)}
                />
            }
            pagination={
                <AdminPagination
                    currentPage={currentPage}
                    totalItems={filteredZones.length}
                    itemsPerPage={itemsPerPage}
                    onPageChange={setCurrentPage}
                    onItemsPerPageChange={(val) => {
                        setItemsPerPage(val);
                        setCurrentPage(1);
                    }}
                />
            }
            stats={
                <>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Total Zones</p>
                        <p className="text-base font-black text-[#0d141b] dark:text-white leading-none mt-0.5">{zones.length}</p>
                    </div>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Active</p>
                        <p className="text-base font-black text-[#0d141b] dark:text-white leading-none mt-0.5">{zones.filter(z => z.is_active).length}</p>
                    </div>
                    <div className="bg-[#f6f7f8] dark:bg-[#101922] p-2.5 rounded-lg border border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <p className="text-[10px] font-bold text-[#4c739a] dark:text-[#94a3b8] uppercase tracking-wider">Free Shipping Zones</p>
                        <p className="text-base font-black text-[#0d141b] dark:text-white leading-none mt-0.5">{zones.filter(z => z.rate === 0).length}</p>
                    </div>
                </>
            }
            bulkActions={
                <AdminBulkActionsBar
                    selectedCount={selectedIds.size}
                    onCancel={() => setSelectedIds(new Set())}
                    onDelete={handleBulkDelete}
                    isDeleting={isBulkDeleting}
                />
            }
        >
            <AdminTable
                    headers={['Zone Name', 'Regions', 'Rate', 'Delivery Time', 'Status', 'Actions']}
                    onSelectAll={toggleSelectAll}
                    isAllSelected={filteredZones.length > 0 && filteredZones.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage).every(z => selectedIds.has(z.id))}
                >
                    {loading ? (
                        <tr>
                            <td colSpan={7} className="py-12 text-center text-slate-500 dark:text-slate-400 font-bold">
                                <div className="flex items-center justify-center gap-2">
                                    <span className="material-symbols-outlined animate-spin text-2xl text-[#d41132]">progress_activity</span>
                                    Loading zones...
                                </div>
                            </td>
                        </tr>
                    ) : filteredZones.length === 0 ? (
                        <tr>
                            <td colSpan={7} className="py-12 text-center text-slate-500 dark:text-slate-400">
                                No shipping zones found.
                            </td>
                        </tr>
                    ) : (
                        filteredZones.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage).map((zone) => (
                            <tr key={zone.id} className={`group hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors ${selectedIds.has(zone.id) ? 'bg-[#d41132]/5 dark:bg-[#d41132]/10' : ''}`}>
                                <td className="py-4 px-6" onClick={(e) => e.stopPropagation()}>
                                    <input
                                        type="checkbox"
                                        className="rounded border-slate-300 text-[#d41132] focus:ring-[#d41132] bg-transparent cursor-pointer"
                                        checked={selectedIds.has(zone.id)}
                                        onChange={() => toggleSelect(zone.id)}
                                    />
                                </td>
                                <td className="px-6 py-4">
                                    <p className="font-bold text-slate-900 dark:text-white">{zone.name}</p>
                                </td>
                                <td className="px-6 py-4 text-slate-500 dark:text-slate-400 max-w-xs truncate font-medium">{zone.regions}</td>
                                <td className="px-6 py-4 font-black text-slate-700 dark:text-slate-300">{formatRate(zone)}</td>
                                <td className="px-6 py-4 text-slate-500 dark:text-slate-400 font-medium whitespace-nowrap">{zone.handling_days} days</td>
                                <td className="px-6 py-4">
                                    <span className={`text-[10px] font-black uppercase tracking-widest px-2.5 py-1 rounded-full ${zone.is_active ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400' : 'bg-slate-100 text-slate-400 dark:bg-slate-700'}`}>
                                        {zone.is_active ? 'Active' : 'Inactive'}
                                    </span>
                                </td>
                                <td className="px-6 py-4 text-right relative">
                                    <button
                                        onClick={(e) => toggleMenu(zone.id, e)}
                                        className="action-menu-trigger text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 p-1 rounded-full hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors"
                                    >
                                        <span className="material-symbols-outlined">more_vert</span>
                                    </button>
                                    {activeMenu === zone.id && (
                                        <div className="absolute right-8 top-12 z-20 w-48 bg-white dark:bg-slate-800 rounded-lg shadow-lg border border-slate-200 dark:border-slate-700 py-1 action-menu animate-in zoom-in-95 duration-150 origin-top-right">
                                            <button onClick={() => { openEdit(zone); setActiveMenu(null); }} className="w-full text-left px-4 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700 flex items-center gap-2">
                                                <span className="material-symbols-outlined text-lg">edit</span> Edit
                                            </button>
                                            <div className="h-px bg-slate-100 dark:bg-slate-700 my-1"></div>
                                            <button onClick={() => { handleDelete(zone.id); setActiveMenu(null); }} className="w-full text-left px-4 py-2 text-sm text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 flex items-center gap-2">
                                                <span className="material-symbols-outlined text-lg">delete</span> Delete
                                            </button>
                                        </div>
                                    )}
                                </td>
                            </tr>
                        ))
                    )}
                </AdminTable>

            {/* Modal */}
            {showModal && (
                <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
                    <div className="bg-white dark:bg-slate-800 rounded-2xl w-full max-w-lg shadow-2xl border border-slate-200 dark:border-slate-700 animate-in zoom-in-95 duration-200">
                        <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 p-6 border-b border-slate-200 dark:border-slate-700">
                            <h2 className="text-lg font-black text-slate-900 dark:text-white">{editingZone ? 'Edit Shipping Zone' : 'New Shipping Zone'}</h2>
                            <button onClick={() => setShowModal(false)} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg text-slate-500 hover:text-slate-700 dark:hover:text-white transition-colors"><span className="material-symbols-outlined">close</span></button>
                        </div>
                        <div className="p-6 space-y-4 max-h-[70vh] overflow-y-auto custom-scrollbar">
                            {[
                                { key: 'name', label: 'Zone Name', placeholder: 'e.g. North America', type: 'text' },
                                { key: 'regions', label: 'Regions / Countries', placeholder: 'e.g. USA, Canada, Mexico', type: 'text' },
                                { key: 'rate', label: 'Shipping Rate ($)', placeholder: '0 for free shipping', type: 'number' },
                                { key: 'free_above', label: 'Free Shipping Above ($)', placeholder: 'Leave blank to disable', type: 'number' },
                                { key: 'handling_days', label: 'Delivery Time (days)', placeholder: '7', type: 'number' },
                            ].map(field => (
                                <div key={field.key}>
                                    <label className="block text-xs font-bold uppercase tracking-widest text-slate-500 mb-1.5">{field.label}</label>
                                    <input
                                        type={field.type}
                                        value={(form as any)[field.key]}
                                        onChange={e => setForm(f => ({ ...f, [field.key]: e.target.value }))}
                                        placeholder={field.placeholder}
                                        className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-600 rounded-lg px-3 py-2 text-sm focus:border-[#d41132] outline-none dark:text-white transition-all ring-0"
                                    />
                                </div>
                            ))}
                            <label className="flex items-center gap-2 cursor-pointer pt-2 group">
                                <div onClick={() => setForm(f => ({ ...f, is_active: !f.is_active }))} className={`relative w-10 h-5 rounded-full transition-all ${form.is_active ? 'bg-green-500' : 'bg-slate-300 dark:bg-slate-600'}`}>
                                    <span className={`absolute top-0.5 left-0.5 w-4 h-4 bg-white rounded-full shadow transition-transform ${form.is_active ? 'translate-x-5' : ''}`} />
                                </div>
                                <span className="text-sm text-slate-700 dark:text-slate-300 font-bold group-hover:text-slate-900 dark:group-hover:text-white transition-colors">Active</span>
                            </label>
                        </div>
                        <div className="flex gap-3 p-6 border-t border-slate-200 dark:border-slate-700">
                            <button onClick={() => setShowModal(false)} className="flex-1 py-2.5 rounded-xl border border-slate-200 dark:border-slate-600 text-slate-600 dark:text-slate-300 font-bold text-sm hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors">Cancel</button>
                            <button onClick={handleSave} disabled={saving || !form.name || !form.regions} className="flex-1 py-2.5 rounded-xl bg-[#d41132] hover:bg-[#b30f2a] text-white font-bold text-sm transition-colors disabled:opacity-50 shadow-sm shadow-red-200 dark:shadow-none">
                                {saving ? 'Saving...' : (editingZone ? 'Save Changes' : 'Create Zone')}
                            </button>
                        </div>
                    </div>
                </div>
            )}
            <ConfirmModal
                isOpen={confirmModal.isOpen}
                title={confirmModal.title}
                message={confirmModal.message}
                onConfirm={confirmModal.onConfirm}
                onCancel={() => setConfirmModal(prev => ({ ...prev, isOpen: false }))}
            />
        </AdminPageLayout>
    );
}

"use client";

import { useState, useRef, useEffect } from 'react';
import Header from '@/components/storefront/Header';
import Footer from '@/components/storefront/Footer';
import { contentService } from '@/lib/services/contentService';

export default function BespokePage() {
    const [formStatus, setFormStatus] = useState<'idle' | 'submitting' | 'success'>('idle');
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [fileName, setFileName] = useState<string | null>(null);
    const [cmsContent, setCmsContent] = useState<Record<string, string>>({});

    useEffect(() => {
        async function loadCMS() {
            const keys = ['bespoke_hero_title', 'bespoke_hero_subtitle', 'bespoke_cta_text'];
            const content: Record<string, string> = {};
            await Promise.all(keys.map(async (key) => {
                content[key] = await contentService.getBySlug(key);
            }));
            setCmsContent(content);
        }
        loadCMS();
    }, []);

    const handleFileClick = () => {
        fileInputRef.current?.click();
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            setFileName(e.target.files[0].name);
        }
    };

    const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        setFormStatus('submitting');
        try {
            const form = e.currentTarget;
            const data = new FormData(form);

            // Upload file to Supabase Storage if present
            let imageUrl = '';
            const file = data.get('project_image') as File | null;
            if (file && file.size > 0) {
                const imageFormData = new FormData();
                imageFormData.append('file', file);
                const mediaRes = await fetch('/api/media', { method: 'POST', body: imageFormData });
                const mediaData = await mediaRes.json();
                imageUrl = mediaData.url || '';
            }

            const res = await fetch('/api/requests', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    name: data.get('name') as string,
                    email: data.get('email') as string,
                    phone: data.get('phone') as string,
                    itemType: data.get('item_type') as string,
                    description: data.get('description') as string,
                    budget: data.get('budget_range') as string,
                    deadline: data.get('deadline') as string,
                    inspiration: imageUrl,
                }),
            });
            const result = await res.json();
            if (!res.ok || !result.success) {
                throw new Error(result.message || 'Failed to submit request');
            }
            setFormStatus('success');
            window.scrollTo({ top: 0, behavior: 'smooth' });
        } catch (err) {
            console.error('Failed to submit request:', err);
            alert('Failed to submit request. Please try again.');
