"use client";

import { useState } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { useCart } from "@/contexts/CartContext";
import Header from "@/components/storefront/Header";
import Footer from "@/components/storefront/Footer";

export default function CartPage() {
    const {
        cartItems,
        updateQuantity,
        removeFromCart,
        cartTotal,
        appliedCoupon,
        discount,
        totalAfterDiscount,
        applyCoupon,
        removeCoupon
    } = useCart();

    const [couponCode, setCouponCode] = useState("");
    const [isLoading, setIsLoading] = useState(false);
    const [message, setMessage] = useState<{ text: string, type: 'error' | 'success' } | null>(null);
    const [checkoutError, setCheckoutError] = useState<string | null>(null);
    const [isCheckingOut, setIsCheckingOut] = useState(false);
    const router = useRouter();
    const { validateCheckoutStock } = useCart();

    const handleCheckout = async () => {
        setCheckoutError(null);
        setIsCheckingOut(true);
        const result = await validateCheckoutStock();
        setIsCheckingOut(false);

        if (result.success) {
            router.push('/checkout');
        } else {
            setCheckoutError(result.message || 'Failed to validate stock.');
        }
    };

    const handleApplyCoupon = async () => {
        if (!couponCode) return;
        setIsLoading(true);
        setMessage(null);
        const result = await applyCoupon(couponCode);
        if (result.success) {
            setMessage({ text: result.message, type: 'success' });
            setCouponCode("");
        } else {
            setMessage({ text: result.message, type: 'error' });
        }
        setIsLoading(false);
    };

    if (cartItems.length === 0) {
        return (
            <div className="min-h-screen flex flex-col bg-[#FDFDFB] dark:bg-[#120d09] font-[family-name:var(--font-inter)]">
                <Header />
                <div className="flex-1 flex flex-col items-center justify-center px-4 py-24">
