                    <div className="lg:col-span-2 space-y-8">
                        {cartItems.map((item) => (
                            <div key={`${item.id}-${item.variant}`} className="flex flex-col sm:flex-row gap-6 pb-8 border-b border-gray-100 dark:border-white/5 group">
