        price: 0,
        category: "",
        image: "",
        stock: 0,
    });

    // Load products
    const loadProducts = async () => {
        try {
            setLoading(true);
            setError(null);
            const res = await fetch('/api/products');
            const result = await res.json();
            if (result.success) {
                setProducts(result.data);
            } else {
                throw new Error(result.message || "Failed to load products");
            }
        } catch (err: any) {
            setError(err.message || "Failed to load products");
            console.error("Error loading products:", err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        loadProducts();
    }, []);

    // Handle create/update
    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            if (editingProduct) {
                const res = await fetch(`/api/products/${editingProduct.id}`, {
                    method: 'PUT',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify(formData),
                });
                const result = await res.json();
                if (!result.success) throw new Error(result.message);
            } else {
                const res = await fetch('/api/products', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify(formData),
                });
                const result = await res.json();
                if (!result.success) throw new Error(result.message);
            }
            setIsModalOpen(false);
            resetForm();
            loadProducts();
        } catch (err: any) {
            alert("Error: " + err.message);
        }
    };

    // Handle delete
    const handleDelete = async (id: string) => {
        if (!confirm("Are you sure you want to delete this product?")) return;
        try {
            const res = await fetch(`/api/products/${id}`, {
                method: 'DELETE',
            });
            const result = await res.json();
            if (!result.success) throw new Error(result.message);

            loadProducts();
        } catch (err: any) {
            alert("Error: " + err.message);
        }
    };

    // Reset form
    const resetForm = () => {
        setFormData({
            name: "",
            description: "",
            price: 0,
            category: "",
            image: "",
            stock: 0,
        });
        setEditingProduct(null);
    };

    // Open modal for editing
    const handleEdit = (product: Product) => {
        setEditingProduct(product);
        setFormData({
            name: product.name,
            description: product.description || "",
            price: product.price,
            category: product.category,
            image: product.image || "",
            stock: product.stock,
        });
        setIsModalOpen(true);
    };

    return (
        <div className="min-h-screen p-8 bg-background-light dark:bg-background-dark">
            <div className="max-w-7xl mx-auto space-y-8">
                {/* Header */}
                <div className="flex items-center justify-between">
                    <div>
                        <h1 className="text-4xl font-bold text-text-primary-light dark:text-text-primary-dark mb-2">
                            Products Management
                        </h1>
                        <p className="text-text-secondary-light dark:text-text-secondary-dark">
                            Testing Supabase CRUD Operations
                        </p>
                    </div>
                    <Button
                        onClick={() => {
                            resetForm();
                            setIsModalOpen(true);
                        }}
                        variant="primary"
                    >
                        <span className="material-symbols-outlined">add</span>
                        Add Product
                    </Button>
                </div>

                {/* Error State */}
                {error && (
                    <Card variant="bordered" padding="md">
                        <div className="flex items-center gap-3 text-error">
                            <span className="material-symbols-outlined text-3xl">error</span>
                            <div>
                                <h3 className="font-bold">Database Connection Error</h3>
                                <p className="text-sm mt-1">{error}</p>
                                <p className="text-xs mt-2 text-text-secondary-light dark:text-text-secondary-dark">
                                    Make sure you've:
                                    <br />
                                    1. Created the database tables (run supabase-schema.sql)
                                    <br />
                                    2. Added NEXT_PUBLIC_SUPABASE_ANON_KEY to .env.local
                                    <br />
                                    3. Restarted the dev server
                                </p>
                            </div>
                        </div>
                    </Card>
                )}

                {/* Loading State */}
                {loading && (
                    <div className="text-center py-12">
                        <div className="inline-block animate-spin rounded-full h-12 w-12 border-4 border-primary border-t-transparent"></div>
                        <p className="mt-4 text-text-secondary-light dark:text-text-secondary-dark">
                            Loading products...
                        </p>
                    </div>
                )}

                {/* Products Grid */}
                {!loading && !error && (
                    <>
                        <div className="flex items-center justify-between">
                            <h2 className="text-2xl font-bold text-text-primary-light dark:text-text-primary-dark">
                                All Products ({products.length})
                            </h2>
                        </div>

                        {products.length === 0 ? (
                            <Card padding="lg">
                                <div className="text-center py-8">
                                    <span className="material-symbols-outlined text-6xl text-text-secondary-light dark:text-text-secondary-dark mb-4">
                                        inventory_2
                                    </span>
                                    <h3 className="text-xl font-bold mb-2">No products yet</h3>
                                    <p className="text-text-secondary-light dark:text-text-secondary-dark mb-4">
                                        Run the SQL schema to add sample products, or create your first product.
                                    </p>
                                    <Button onClick={() => setIsModalOpen(true)}>
                                        Create First Product
                                    </Button>
                                </div>
                            </Card>
                        ) : (
                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                                {products.map((product) => (
                                    <Card key={product.id} variant="elevated" padding="none">
                                        {/* Product Image */}
                                        {product.image && (
                                            <div className="h-48 bg-gray-200 dark:bg-gray-700 rounded-t-xl overflow-hidden">
                                                <img
                                                    src={product.image}
                                                    alt={product.name}
                                                    className="w-full h-full object-cover"
                                                />
                                            </div>
                                        )}

                                        {/* Product Info */}
                                        <div className="p-6 space-y-4">
                                            <div>
                                                <div className="flex items-start justify-between mb-2">
                                                    <h3 className="text-lg font-bold text-text-primary-light dark:text-text-primary-dark">
                                                        {product.name}
                                                    </h3>
                                                    <Badge variant="primary">{product.category}</Badge>
                                                </div>
                                                <p className="text-sm text-text-secondary-light dark:text-text-secondary-dark line-clamp-2">
                                                    {product.description}
                                                </p>
                                            </div>

                                            <div className="flex items-center justify-between">
                                                <div>
                                                    <div className="text-2xl font-bold text-primary">
                                                        {formatCurrency(product.price)}
                                                    </div>
                                                    <div className="text-sm text-text-secondary-light dark:text-text-secondary-dark">
                                                        Stock: {product.stock}
                                                    </div>
                                                </div>
                                            </div>

                                            {/* Actions */}
                                            <div className="flex gap-2 pt-4 border-t border-border-light dark:border-border-dark">
                                                <Button
                                                    size="sm"
                                                    variant="outline"
                                                    onClick={() => handleEdit(product)}
                                                    fullWidth
                                                >
                                                    <span className="material-symbols-outlined text-sm">
                                                        edit
                                                    </span>
                                                    Edit
                                                </Button>
                                                <Button
                                                    size="sm"
                                                    variant="danger"
                                                    onClick={() => handleDelete(product.id)}
                                                    fullWidth
                                                >
                                                    <span className="material-symbols-outlined text-sm">
                                                        delete
                                                    </span>
                                                    Delete
                                                </Button>
                                            </div>
                                        </div>
                                    </Card>
                                ))}
                            </div>
                        )}
                    </>
                )}

                {/* Create/Edit Modal */}
                <Modal
                    isOpen={isModalOpen}
                    onClose={() => {
                        setIsModalOpen(false);
                        resetForm();
                    }}
                    title={editingProduct ? "Edit Product" : "Create Product"}
                    size="lg"
                >
                    <form onSubmit={handleSubmit} className="p-6 space-y-4">
                        <Input
                            label="Product Name"
                            value={formData.name}
                            onChange={(e) =>
                                setFormData({ ...formData, name: e.target.value })
                            }
                            required
                        />
                        <Input
                            label="Description"
                            value={formData.description}
                            onChange={(e) =>
                                setFormData({ ...formData, description: e.target.value })
                            }
                        />
                        <div className="grid grid-cols-2 gap-4">
                            <Input
                                label="Price"
                                type="number"
                                step="0.01"
                                value={formData.price}
                                onChange={(e) =>
                                    setFormData({ ...formData, price: parseFloat(e.target.value) })
                                }
                                required
                            />
                            <Input
                                label="Stock"
                                type="number"
                                value={formData.stock}
                                onChange={(e) =>
                                    setFormData({ ...formData, stock: parseInt(e.target.value) })
                                }
                                required
                            />
                        </div>
                        <Input
                            label="Category"
                            value={formData.category}
                            onChange={(e) =>
                                setFormData({ ...formData, category: e.target.value })
                            }
                            required
                        />
                        <Input
                            label="Image URL"
                            value={formData.image}
                            onChange={(e) =>
                                setFormData({ ...formData, image: e.target.value })
                            }
                        />

                        <div className="flex gap-3 pt-4">
                            <Button type="submit" variant="primary" fullWidth>
                                {editingProduct ? "Update Product" : "Create Product"}
                            </Button>
                            <Button
                                type="button"
                                variant="outline"
                                onClick={() => {
                                    setIsModalOpen(false);
                                    resetForm();
                                }}
                                fullWidth
                            >
                                Cancel
                            </Button>
                        </div>
                    </form>
                </Modal>
            </div>
        </div>
    );
}

