'use client';

import { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { Order } from '@/lib/supabase';
import { useToast } from '@/contexts/ToastContext';

interface AdminOrderModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSubmit: (orderData: any) => Promise<void>;
}

// Simplified types for the selection lists
type SimpleCustomer = { id: string; name: string; email: string };
type SimpleProduct = { id: string; name: string; price: number; stock: number };

export default function AdminOrderModal({ isOpen, onClose, onSubmit }: AdminOrderModalProps) {
    const { showToast } = useToast();
    const [mounted, setMounted] = useState(false);

    useEffect(() => {
        setMounted(true);
        return () => setMounted(false);
    }, []);

    const [isLoading, setIsLoading] = useState(false);
    const [isFetchingData, setIsFetchingData] = useState(false);

    // Data lists
    const [customers, setCustomers] = useState<SimpleCustomer[]>([]);
    const [products, setProducts] = useState<SimpleProduct[]>([]);

    // Form State
    const [customerId, setCustomerId] = useState('');
    const [status, setStatus] = useState<Order['status']>('PENDING');
    const [items, setItems] = useState<{ product_id: string; quantity: number; price: number }[]>([]);

    // Load data on open
    useEffect(() => {
        if (isOpen && (customers.length === 0 || products.length === 0)) {
            fetchData();
        }
        if (isOpen) {
            // Reset form
            setCustomerId('');
            setStatus('PENDING');
            setItems([]);
        }
    }, [isOpen, customers.length, products.length]);

    const fetchData = async () => {
        setIsFetchingData(true);
        try {
            // Concurrent fetch
            const [custRes, prodRes] = await Promise.all([
                fetch('/api/customers?limit=1000'),
                fetch('/api/products')
            ]);

            const custData = await custRes.json();
            const prodData = await prodRes.json();

            if (custData.success) setCustomers(custData.data);
            if (prodData.success) setProducts(prodData.data);

        } catch (error) {
            console.error("Failed to load data", error);
        } finally {
            setIsFetchingData(false);
        }
    };

    const handleAddItem = () => {
        if (products.length === 0) return;
        setItems([...items, { product_id: products[0].id, quantity: 1, price: products[0].price }]);
    };

    const handleRemoveItem = (index: number) => {
        const newItems = [...items];
        newItems.splice(index, 1);
        setItems(newItems);
    };

    const handleItemChange = (index: number, field: 'product_id' | 'quantity', value: string | number) => {
        const newItems = [...items];
        const item = { ...newItems[index] };

        if (field === 'product_id') {
            const prod = products.find(p => p.id === value);
            if (prod) {
                item.product_id = prod.id;
                item.price = prod.price; // Update price when product changes
            }
        } else if (field === 'quantity') {
            item.quantity = Number(value);
        }

        newItems[index] = item;
        setItems(newItems);
    };

    const calculateTotal = () => {
        return items.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!customerId) { showToast('Please select a customer', 'error'); return; }
        if (items.length === 0) { showToast('Please add at least one item', 'error'); return; }

        setIsLoading(true);
        try {
            const orderData = {
                customer_id: customerId,
                status,
                total: calculateTotal(),
                items
            };
            await onSubmit(orderData);
            onClose();
        } catch (error) {
            console.error('Error submitting order:', error);
            showToast('Failed to create order', 'error');
        } finally {
            setIsLoading(false);
        }
    };

    if (!isOpen || !mounted) return null;

    const container = typeof document !== 'undefined' ? document.body : null;
    if (!container) return null;

    return createPortal(
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
            <div className="bg-white dark:bg-[#1a2632] rounded-xl shadow-xl w-full max-h-[90vh] overflow-y-auto" style={{ maxWidth: '672px' }}>
                <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 p-6 border-b border-[#e5e7eb] dark:border-[#2d3b4a]">
                    <h2 className="text-xl font-bold text-[#0d141b] dark:text-white">Create New Order</h2>
                    <button onClick={onClose} className="p-2 text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-lg">
                        <span className="material-symbols-outlined">close</span>
                    </button>
                </div>

                <form onSubmit={handleSubmit} className="p-6 flex flex-col gap-6">
                    {isFetchingData ? (
                        <div className="flex justify-center py-8">
                            <span className="material-symbols-outlined animate-spin text-3xl text-[#d41132]">progress_activity</span>
                        </div>
                    ) : (
                        <>
                            {/* Customer & Status */}
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div className="flex flex-col gap-2">
                                    <label className="text-sm font-bold text-[#0d141b] dark:text-white">Customer</label>
                                    <select
                                        required
                                        value={customerId}
                                        onChange={(e) => setCustomerId(e.target.value)}
                                        className="w-full px-4 py-2 rounded-lg bg-[#f6f7f8] dark:bg-[#101922] border border-gray-300 dark:border-gray-600 focus:ring-2 focus:ring-[#d41132] outline-none"
                                    >
                                        <option value="">Select a customer...</option>
                                        {customers.map(c => (
                                            <option key={c.id} value={c.id}>{c.name} ({c.email})</option>
                                        ))}
                                    </select>
                                </div>
                                <div className="flex flex-col gap-2">
                                    <label className="text-sm font-bold text-[#0d141b] dark:text-white">Status</label>
                                    <select
                                        value={status}
                                        onChange={(e) => setStatus(e.target.value as any)}
                                        className="w-full px-4 py-2 rounded-lg bg-[#f6f7f8] dark:bg-[#101922] border border-gray-300 dark:border-gray-600 focus:ring-2 focus:ring-[#d41132] outline-none"
                                    >
                                        <option value="pending">Pending</option>
                                        <option value="processing">Processing</option>
                                        <option value="shipped">Shipped</option>
                                        <option value="delivered">Delivered</option>
                                        <option value="cancelled">Cancelled</option>
                                    </select>
                                </div>
                            </div>

                            {/* Items */}
                            <div className="flex flex-col gap-3">
                                <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                                    <label className="text-sm font-bold text-[#0d141b] dark:text-white">Order Items</label>
                                    <button
                                        type="button"
                                        onClick={handleAddItem}
                                        className="text-sm text-[#d41132] font-bold hover:underline flex items-center gap-1"
                                    >
                                        <span className="material-symbols-outlined text-sm">add</span> Add Item
                                    </button>
                                </div>

                                {items.length === 0 ? (
                                    <div className="p-4 bg-gray-50 dark:bg-slate-800/50 rounded-lg text-center text-sm text-gray-400 border border-dashed border-gray-200 dark:border-gray-700">
                                        No items added. Click "Add Item" to start.
                                    </div>
                                ) : (
                                    <div className="flex flex-col gap-3">
                                        {items.map((item, idx) => (
                                            <div key={idx} className="flex gap-3 items-start bg-gray-50 dark:bg-slate-800/50 p-3 rounded-lg border border-gray-100 dark:border-gray-700">
                                                <div className="flex-1">
                                                    <label className="text-xs font-semibold text-gray-500 mb-1 block">Product</label>
                                                    <select
                                                        value={item.product_id}
                                                        onChange={(e) => handleItemChange(idx, 'product_id', e.target.value)}
                                                        className="w-full text-sm px-3 py-2 rounded bg-white dark:bg-[#1a2632] border border-gray-300 dark:border-gray-600"
                                                    >
                                                        {products.map(p => (
                                                            <option key={p.id} value={p.id}>{p.name} (${p.price})</option>
                                                        ))}
                                                    </select>
                                                </div>
                                                <div className="w-24">
                                                    <label className="text-xs font-semibold text-gray-500 mb-1 block">Qty</label>
                                                    <input
                                                        type="number"
                                                        min="1"
                                                        value={item.quantity}
                                                        onChange={(e) => handleItemChange(idx, 'quantity', e.target.value)}
                                                        className="w-full text-sm px-3 py-2 rounded bg-white dark:bg-[#1a2632] border border-gray-300 dark:border-gray-600"
                                                    />
                                                </div>
                                                <div className="w-24 text-right">
                                                    <label className="text-xs font-semibold text-gray-500 mb-1 block">Subtotal</label>
                                                    <p className="text-sm font-bold pt-2">${(item.price * item.quantity).toFixed(2)}</p>
                                                </div>
                                                <button
                                                    type="button"
                                                    onClick={() => handleRemoveItem(idx)}
                                                    className="mt-6 text-gray-400 hover:text-red-500"
                                                >
                                                    <span className="material-symbols-outlined">delete</span>
                                                </button>
                                            </div>
                                        ))}
                                    </div>
                                )}
                            </div>

                            {/* Total */}
                            <div className="flex justify-between items-center pt-4 border-t border-[#e5e7eb] dark:border-[#2d3b4a]">
                                <span className="font-bold text-lg text-[#0d141b] dark:text-white">Total</span>
                                <span className="font-bold text-2xl text-[#d41132]">${calculateTotal().toFixed(2)}</span>
                            </div>
                        </>
                    )}

                    <div className="flex justify-end gap-3 pt-4 border-t border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <button type="button" onClick={onClose} className="px-4 py-2 font-bold text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-lg">Cancel</button>
                        <button
                            type="submit"
                            disabled={isLoading || isFetchingData}
                            className="px-6 py-2 bg-[#d41132] hover:bg-[#b30f2a] text-white font-bold rounded-lg shadow-md transition-colors disabled:opacity-50"
                        >
                            {isLoading ? 'Creating...' : 'Create Order'}
                        </button>
                    </div>
                </form>
            </div>
        </div>,
        container
    );
}

'use client';

import { useState, useEffect, useRef, useCallback } from 'react';
import { createPortal } from 'react-dom';
import { Product } from '@/lib/supabase';
import { useToast } from '@/contexts/ToastContext';

interface ProductFormModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSubmit: (product: pProduct) => Promise<void>;
    initialData?: Product | null;
}

// Partial product type for creation/editing
export type pProduct = Omit<Product, 'id' | 'createdAt' | 'updatedAt'>;

export default function ProductFormModal({ isOpen, onClose, onSubmit, initialData }: ProductFormModalProps) {
    const { showToast } = useToast();
    const [mounted, setMounted] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [categories, setCategories] = useState<string[]>([
        'Jackets', 'Full Coats', 'Bags & Satchels', 'Accessories', 'Shoes'
    ]);

    useEffect(() => {
        setMounted(true);
        // Load categories from admin API
        fetch('/api/categories')
            .then(r => r.json())
            .then(d => { if (d.success && d.data?.length > 0) setCategories(d.data.map((c: any) => c.name)); })
            .catch(() => { });
        return () => setMounted(false);
    }, []);

    const [isLoading, setIsLoading] = useState(false);
    const [isUploading, setIsUploading] = useState(false);
    const [formData, setFormData] = useState<pProduct>({
        name: '',
        description: '',
        price: 0,
        category: 'Accessories',
        image: '',
        stock: 0,
        is_featured: false,
        featured_tag: null,
        isActive: true,
    });

    // Reset or populate form
    useEffect(() => {
        if (isOpen) {
            if (initialData) {
                setFormData({
                    name: initialData.name,
                    description: initialData.description,
                    price: initialData.price,
                    category: initialData.category,
                    image: initialData.image || '',
                    stock: initialData.stock,
                    is_featured: initialData.is_featured || false,
                    featured_tag: initialData.featured_tag || null,
                    isActive: initialData.isActive !== undefined ? initialData.isActive : true,
                });
            } else {
                setFormData({
                    name: '',
                    description: '',
                    price: 0,
                    category: 'Accessories',
                    image: '',
                    stock: 0,
                    is_featured: false,
                    featured_tag: null,
                    isActive: true,
                });
            }
        }
    }, [isOpen, initialData]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);
        try {
            await onSubmit(formData);
            onClose();
        } catch (error) {
            console.error('Error submitting form:', error);
            showToast('Failed to save product. Please try again.', 'error');
        } finally {
            setIsLoading(false);
        }
    };

    const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        setIsUploading(true);
        try {
            const formData = new FormData();
            formData.append('file', file);

            const res = await fetch('/api/media', {
                method: 'POST',
                body: formData,
            });

            const data = await res.json();
            if (!data.success) throw new Error(data.message);

            setFormData(prev => ({ ...prev, image: data.url }));
        } catch (error) {
            console.error('Upload failed:', error);
            showToast('Failed to upload image', 'error');
        } finally {
            setIsUploading(false);
        }
    };

    if (!isOpen || !mounted) return null;

    const container = typeof document !== 'undefined' ? document.body : null;
    if (!container) return null;

    return createPortal(
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
            <div className="bg-white dark:bg-[#1a2632] rounded-xl shadow-xl w-full max-h-[90vh] overflow-y-auto" style={{ maxWidth: '672px' }}>
                <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 p-6 border-b border-[#e5e7eb] dark:border-[#2d3b4a]">
                    <h2 className="text-xl font-bold text-[#0d141b] dark:text-white">
                        {initialData ? 'Edit Product' : 'Add New Product'}
                    </h2>
                    <button
                        onClick={onClose}
                        className="p-2 text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-lg transition-colors"
                    >
                        <span className="material-symbols-outlined">close</span>
                    </button>
                </div>

                <form onSubmit={handleSubmit} className="p-6 flex flex-col gap-6">
                    {/* Basic Info */}
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="flex flex-col gap-2">
                            <label className="text-sm font-bold text-[#0d141b] dark:text-white">Product Name</label>
                            <input
                                required
                                type="text"
                                value={formData.name}
                                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                className="w-full px-4 py-2 rounded-lg bg-[#f6f7f8] dark:bg-[#101922] border border-gray-300 dark:border-gray-600 focus:ring-2 focus:ring-[#d41132] outline-none transition-all"
                                placeholder="e.g. Classic Leather Wallet"
                            />
                        </div>
                        <div className="flex flex-col gap-2">
                            <label className="text-sm font-bold text-[#0d141b] dark:text-white">Category</label>
                            <select
                                value={formData.category}
                                onChange={(e) => setFormData({ ...formData, category: e.target.value })}
                                className="w-full px-4 py-2 rounded-lg bg-[#f6f7f8] dark:bg-[#101922] border border-gray-300 dark:border-gray-600 focus:ring-2 focus:ring-[#d41132] outline-none transition-all"
                            >
                                {categories.map(cat => (
                                    <option key={cat} value={cat}>{cat}</option>
                                ))}
                            </select>
                        </div>
                    </div>

                    {/* Pricing & Stock */}
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="flex flex-col gap-2">
                            <label className="text-sm font-bold text-[#0d141b] dark:text-white">Price ($)</label>
                            <input
                                required
                                type="number"
                                min="0" step="0.01"
                                value={formData.price}
                                onChange={(e) => setFormData({ ...formData, price: parseFloat(e.target.value) || 0 })}
                                className="w-full px-4 py-2 rounded-lg bg-[#f6f7f8] dark:bg-[#101922] border border-gray-300 dark:border-gray-600 focus:ring-2 focus:ring-[#d41132] outline-none transition-all"
                            />
                        </div>
                        <div className="flex flex-col gap-2">
                            <label className="text-sm font-bold text-[#0d141b] dark:text-white">Stock</label>
                            <input
                                required
                                type="number"
                                min="0"
                                value={formData.stock}
                                onChange={(e) => setFormData({ ...formData, stock: parseInt(e.target.value) || 0 })}
                                className="w-full px-4 py-2 rounded-lg bg-[#f6f7f8] dark:bg-[#101922] border border-gray-300 dark:border-gray-600 focus:ring-2 focus:ring-[#d41132] outline-none transition-all"
                            />
                        </div>
                    </div>

                    {/* Featured Toggle */}
                    <div className="flex items-center gap-3 p-4 bg-gray-50 dark:bg-gray-800/50 rounded-xl border border-gray-200 dark:border-gray-700">
                        <div className="flex-1">
                            <h3 className="text-sm font-bold text-gray-900 dark:text-white">Feature on Homepage</h3>
                            <p className="text-xs text-gray-500">Showcase this product in the Featured Collections section.</p>
                        </div>
                        <label className="relative inline-flex items-center cursor-pointer">
                            <input
                                type="checkbox"
                                className="sr-only peer"
                                checked={formData.is_featured || false}
                                onChange={(e) => setFormData({ ...formData, is_featured: e.target.checked })}
                            />
                            <div className="w-11 h-6 bg-gray-300 peer-focus:outline-none rounded-full peer dark:bg-gray-700 peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all dark:border-gray-600 peer-checked:bg-[#d41132]"></div>
                        </label>
                    </div>

                    {/* Image */}
                    <div className="flex flex-col gap-2">
                        <label className="text-sm font-bold text-[#0d141b] dark:text-white">Product Image</label>
                        <div className="flex gap-4 items-center">
                            {formData.image && (
                                <img
                                    src={formData.image}
                                    alt="Preview"
                                    className="w-16 h-16 object-cover rounded-lg border border-gray-200 dark:border-gray-700"
                                />
                            )}
                            <div className="flex-1 flex gap-2">
                                <input
                                    type="text"
                                    value={formData.image}
                                    onChange={(e) => setFormData({ ...formData, image: e.target.value })}
                                    className="flex-1 px-4 py-2 rounded-lg bg-[#f6f7f8] dark:bg-[#101922] border border-gray-300 dark:border-gray-600 focus:ring-2 focus:ring-[#d41132] outline-none transition-all"
                                    placeholder="https://example.com/image.jpg"
                                />
                                <input
                                    type="file"
                                    ref={fileInputRef}
                                    onChange={handleImageUpload}
                                    className="hidden"
                                    accept="image/*"
                                />
                                <button
                                    type="button"
                                    onClick={() => fileInputRef.current?.click()}
                                    disabled={isUploading}
                                    className="px-4 py-2 bg-gray-200 dark:bg-gray-700 hover:bg-gray-300 dark:hover:bg-gray-600 rounded-lg transition-colors flex items-center justify-center"
                                >
                                    {isUploading ? (
                                        <span className="material-symbols-outlined animate-spin">refresh</span>
                                    ) : (
                                        <span className="material-symbols-outlined">cloud_upload</span>
                                    )}
                                </button>
                            </div>
                        </div>

                        <div className="flex items-center mt-2">
                            <label className="flex items-center gap-3 cursor-pointer">
                                <div onClick={() => setFormData({ ...formData, is_featured: !formData.is_featured })} className={`relative w-11 h-6 rounded-full transition-all ${formData.is_featured ? 'bg-amber-500' : 'bg-slate-300 dark:bg-slate-600'}`}>
                                    <span className={`absolute top-0.5 left-0.5 w-5 h-5 bg-white rounded-full shadow transition-transform ${formData.is_featured ? 'translate-x-5' : ''}`} />
                                </div>
                                <span className="text-sm font-medium text-amber-700 dark:text-amber-500">Feature on Homepage</span>
                            </label>
                        </div>

                        {formData.is_featured && (
                            <div className="bg-amber-50 dark:bg-amber-900/10 border border-amber-200 dark:border-amber-800 rounded-lg p-4 animate-in fade-in zoom-in-95 duration-200 mt-2">
                                <label className="block text-xs font-bold uppercase tracking-widest text-amber-800 dark:text-amber-500 mb-3">Featured Badge Tag</label>
                                <div className="grid grid-cols-2 gap-3">
                                    {['Most Purchased', 'Top Selling', 'New Arrival', 'Top Rated'].map(tag => (
                                        <label key={tag} className="flex items-center gap-2 cursor-pointer group">
                                            <div onClick={() => setFormData({ ...formData, featured_tag: tag })} className={`w-4 h-4 rounded-full border-2 flex items-center justify-center transition-colors ${formData.featured_tag === tag ? 'border-amber-500' : 'border-slate-300 dark:border-slate-600 group-hover:border-amber-400'}`}>
                                                {formData.featured_tag === tag && <div className="w-2 h-2 rounded-full bg-amber-500" />}
                                            </div>
                                            <span className={`text-sm font-medium ${formData.featured_tag === tag ? 'text-amber-900 dark:text-amber-400' : 'text-slate-600 dark:text-slate-400 group-hover:text-amber-700 dark:group-hover:text-amber-300'}`}>{tag}</span>
                                        </label>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>

                    {/* Description */}
                    <div className="flex flex-col gap-2">
                        <label className="text-sm font-bold text-[#0d141b] dark:text-white">Description</label>
                        <textarea
                            required
                            rows={4}
                            value={formData.description || ''}
                            onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                            className="w-full px-4 py-2 rounded-lg bg-[#f6f7f8] dark:bg-[#101922] border border-gray-300 dark:border-gray-600 focus:ring-2 focus:ring-[#d41132] outline-none transition-all resize-none"
                            placeholder="Product description..."
                        />
                    </div>

                    {/* Actions */}
                    <div className="flex justify-end gap-3 pt-4 border-t border-[#e5e7eb] dark:border-[#2d3b4a]">
                        <button
                            type="button"
                            onClick={onClose}
                            className="px-4 py-2 font-bold text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-lg transition-colors"
                        >
                            Cancel
                        </button>
                        <button
                            type="submit"
                            disabled={isLoading || isUploading}
                            className="px-6 py-2 bg-[#d41132] hover:bg-[#b30f2a] text-white font-bold rounded-lg shadow-md transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
                        >
                            {isLoading && <span className="material-symbols-outlined animate-spin text-sm">progress_activity</span>}
                            {initialData ? 'Update Product' : 'Create Product'}
                        </button>
                    </div>
                </form>
            </div>
        </div>,
        container
    );
}

'use client';

import React from 'react';

interface AdminTableProps {
    headers: string[];
    children: React.ReactNode;
    onSelectAll?: (checked: boolean) => void;
    isAllSelected?: boolean;
    colSpan?: number;
    containerClassName?: string;
    stickyHeader?: boolean;
}

export default function AdminTable({
    headers,
    children,
    onSelectAll,
    isAllSelected = false,
    colSpan,
    containerClassName = "",
    stickyHeader = true
}: AdminTableProps) {
    return (
        <div className={`overflow-auto flex-1 ${containerClassName}`}>
            <table className="w-full text-left min-w-[800px] border-collapse">
                <thead className={`${stickyHeader ? 'sticky top-0 z-10' : ''} bg-[#f6f7f8] dark:bg-[#101922] border-b border-[#e5e7eb] dark:border-[#2d3b4a]`}>
                    <tr>
                        {onSelectAll && (
                            <th className="px-6 py-4 w-12 text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">
