                        )}
                        {headers.map((header, idx) => (
                            <th 
                                key={idx} 
                                className={`px-6 py-4 text-xs font-bold uppercase tracking-wider text-[#4c739a] dark:text-[#94a3b8] ${idx === headers.length - 1 ? 'text-right' : ''}`}
