                </thead>
                <tbody className="divide-y divide-[#e5e7eb] dark:divide-[#2d3b4a]">
                    {children}
                </tbody>
            </table>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { contentService } from "@/lib/services/contentService";

const DEFAULT_ANNOUNCEMENTS = [
    "Handcrafted Premium Leather | Free Worldwide Shipping",
    "Bespoke Orders Available | 12-15 Days Timeline",
    "Quality that Lasts a Lifetime | Lifetime Warranty"
];

export default function AnnouncementBar() {
    const [currentIndex, setCurrentIndex] = useState(0);
    const [announcementList, setAnnouncementList] = useState(DEFAULT_ANNOUNCEMENTS);

    useEffect(() => {
        async function fetchAnnouncements() {
            try {
                const [a1, a2, a3] = await Promise.all([
                    contentService.getBySlug('announcement_bar_text'),
                    contentService.getBySlug('announcement_bar_2'),
                    contentService.getBySlug('announcement_bar_3'),
                ]);
                const cms = [a1, a2, a3].filter(Boolean) as string[];
                if (cms.length > 0) setAnnouncementList(cms);
            } catch (_) {
                // fallback to defaults on error
            }
        }
        fetchAnnouncements();
    }, []);

    useEffect(() => {
        const interval = setInterval(() => {
            setCurrentIndex((prev) => (prev + 1) % announcementList.length);
        }, 5000);
        return () => clearInterval(interval);
    }, [announcementList.length]);

    return (
        <div className="w-full bg-[#1A1A1A] text-white py-2 px-6 overflow-hidden relative border-b border-white/5">
            <div className="max-w-[1440px] mx-auto flex items-center justify-center min-h-[24px]">
                {announcementList.map((text, index) => (
                    <div
                        key={index}
                        className={`absolute inset-0 flex items-center justify-center transition-all duration-1000 transform px-6 text-center ${index === currentIndex
                            ? "opacity-100 translate-y-0"
                            : "opacity-0 translate-y-2 pointer-events-none"
                            }`}
                    >
                        <p className="text-[11px] font-bold tracking-[0.2em] uppercase">
                            {text}
                        </p>
                    </div>
                ))}
            </div>
            <div className="absolute top-0 left-0 w-1/3 h-full bg-gradient-to-r from-transparent via-white/5 to-transparent skew-x-[-20deg] animate-[shimmer_8s_infinite]"></div>
        </div>
    );
}

'use client';

import { useState } from "react";
import Link from "next/link";
import { useCart } from "@/contexts/CartContext";
import { useRouter } from "next/navigation";

interface CartSidebarProps {
    isOpen: boolean;
    onClose: () => void;
}

export default function CartSidebar({ isOpen, onClose }: CartSidebarProps) {
    const { cartItems, removeFromCart, updateQuantity, cartTotal, closeCart, discount, totalAfterDiscount, removedItems, validateCheckoutStock } = useCart();
    const router = useRouter();
    const [error, setError] = useState<string | null>(null);
    const [isValidating, setIsValidating] = useState(false);

    const handleCheckoutRoute = async (route: string) => {
        setError(null);
        setIsValidating(true);
        const result = await validateCheckoutStock();
        setIsValidating(false);

        if (result.success) {
            onClose();
            router.push(route);
        } else {
            setError(result.message || "Failed to validate stock.");
        }
    };

    return (
        <>
            {/* Overlay */}
            {isOpen && (
                <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-40 transition-opacity" onClick={onClose} />
            )}

            {/* Sidebar */}
            <div className={`fixed top-0 right-0 z-50 h-full w-full max-w-[460px] flex flex-col bg-white dark:bg-[#111827] shadow-2xl transform transition-transform duration-500 ease-out ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}>
                {/* Header */}
                <div className="flex items-center justify-between p-8 border-b border-gray-100 dark:border-gray-800 shrink-0">
                    <div className="flex items-center gap-3">
                        <span className="material-symbols-outlined text-[#137fec] text-2xl">shopping_bag</span>
                        <h2 className="text-xl font-bold text-slate-900 dark:text-white">Your Bag</h2>
                        <span className="bg-[#137fec] text-white text-xs font-bold px-2.5 py-0.5 rounded-full">{cartItems.length}</span>
                    </div>
                    <button onClick={onClose} className="p-2 -mr-2 rounded-full text-gray-400 hover:text-slate-900 dark:hover:text-white hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors">
                        <span className="material-symbols-outlined">close</span>
                    </button>
                </div>

                {/* Unavailable items removed notification */}
                {removedItems.length > 0 && (
                    <div className="mx-4 mt-3 p-3 bg-amber-50 dark:bg-amber-900/30 border border-amber-200 dark:border-amber-700 rounded-lg flex items-start gap-2">
                        <span className="material-symbols-outlined text-amber-500 text-[18px] shrink-0 mt-0.5">warning</span>
                        <div>
                            <p className="text-xs font-bold text-amber-700 dark:text-amber-300">
                                {removedItems.length === 1
                                    ? `"${removedItems[0]}" was removed from your bag`
                                    : `${removedItems.length} items were removed from your bag`}
                            </p>
                            <p className="text-xs text-amber-600 dark:text-amber-400 mt-0.5">
                                {removedItems.length === 1 ? 'This item is' : 'These items are'} no longer available.
                            </p>
                        </div>
                    </div>
                )}

                {/* Items List */}
                <div className="flex-1 overflow-y-auto p-8 flex flex-col gap-6" style={{ scrollbarWidth: 'thin' }}>
                    {cartItems.length === 0 ? (
                        <div className="flex flex-col items-center justify-center h-full text-center space-y-4">
                            <span className="material-symbols-outlined text-6xl text-gray-300">shopping_cart_off</span>
                            <p className="text-gray-500 text-lg font-medium">Your bag is empty.</p>
                        </div>
                    ) : (
                        cartItems.map((item, index) => (
                            <div key={`${item.id}-${item.variant || index}`} className="group flex gap-5">
                                <div className="relative shrink-0 w-24 h-24 rounded-lg overflow-hidden bg-gray-100 border border-gray-200 dark:border-gray-700">
                                    <div className="absolute inset-0 bg-cover bg-center" style={{ backgroundImage: `url('${item.image}')` }} />
                                </div>
                                <div className="flex flex-col flex-1 justify-between py-0.5">
                                    <div>
                                        <div className="flex justify-between items-start gap-2">
                                            <h3 className="font-semibold text-slate-900 dark:text-white text-base leading-tight">{item.name}</h3>
                                            <button onClick={() => removeFromCart(item.id, item.variant)} className="text-gray-400 hover:text-red-500 transition-colors">
                                                <span className="material-symbols-outlined text-[20px]">delete</span>
                                            </button>
                                        </div>
                                        <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">
                                            {item.variant?.replace(/undefined/g, 'Standard') || 'Standard'}
                                        </p>
                                    </div>
                                    <div className="flex items-end justify-between mt-2">
                                        <div className="flex items-center border border-gray-200 dark:border-gray-700 rounded-md h-8">
                                            <button onClick={() => updateQuantity(item.id, -1, item.variant)} className="px-2.5 h-full hover:bg-gray-50 dark:hover:bg-gray-800 text-gray-500 dark:text-gray-400 transition-colors">
                                                <span className="material-symbols-outlined text-[16px]">remove</span>
                                            </button>
                                            <span className="w-8 text-center text-sm font-medium">{item.quantity}</span>
                                            <button onClick={() => updateQuantity(item.id, 1, item.variant)} className="px-2.5 h-full hover:bg-gray-50 dark:hover:bg-gray-800 text-gray-500 dark:text-gray-400 transition-colors">
                                                <span className="material-symbols-outlined text-[16px]">add</span>
                                            </button>
                                        </div>
                                        <p className="font-medium text-slate-900 dark:text-white">${(item.price * item.quantity).toFixed(2)}</p>
                                    </div>
                                </div>
                            </div>
                        ))
                    )}
                    {/* Shipping Notice */}
                    {cartItems.length > 0 && (
                        <div className="p-4 bg-gray-50 dark:bg-white/5 rounded-lg flex gap-3 items-start">
                            <span className="material-symbols-outlined text-[#137fec] text-xl shrink-0 mt-0.5">local_shipping</span>
                            <p className="text-sm text-gray-600 dark:text-gray-300">Free shipping automatically applied to all orders over $200.</p>
                        </div>
                    )}
                </div>

                {/* Footer */}
                {cartItems.length > 0 ? (
                    <div className="border-t border-gray-100 dark:border-gray-800 p-8 bg-white dark:bg-[#111827] space-y-4 shrink-0 shadow-[0_-10px_40px_-15px_rgba(0,0,0,0.05)] z-20">
                        <div className="space-y-2 mb-6">
                            <div className="flex justify-between items-center text-sm text-gray-500 dark:text-gray-400">
                                <span className="text-xs font-bold uppercase tracking-widest">Subtotal</span>
                                <span className="font-medium text-slate-900 dark:text-white">${cartTotal.toFixed(2)}</span>
                            </div>
                            {discount > 0 && (
                                <div className="flex justify-between items-center text-sm text-green-600 dark:text-green-400 animate-in fade-in slide-in-from-right-2 duration-300">
                                    <span className="text-xs font-bold uppercase tracking-widest italic">Discount Applied</span>
                                    <span className="font-bold">-${discount.toFixed(2)}</span>
                                </div>
                            )}
                            <div className="flex justify-between items-center text-sm text-gray-500 dark:text-gray-400">
                                <span className="text-xs font-bold uppercase tracking-widest">Shipping</span>
                                <span>Calculated next step</span>
                            </div>
                            <div className="flex justify-between items-center text-lg font-bold text-slate-900 dark:text-white pt-2 border-t border-dashed border-gray-200 dark:border-gray-700 mt-2">
                                <span className="text-sm font-black uppercase tracking-widest">Total</span>
                                <span className="text-xl font-black text-[#c27a2a]">${totalAfterDiscount.toFixed(2)}</span>
                            </div>
                        </div>

                        {error && (
                            <div className="mx-0 mt-2 p-3 bg-red-50 border border-red-200 rounded-lg flex items-start gap-2 animate-in fade-in slide-in-from-bottom-2">
                                <span className="material-symbols-outlined text-red-500 text-[18px] shrink-0 mt-0.5">error</span>
                                <p className="text-xs font-bold text-red-700 leading-tight">
                                    {error}
                                </p>
                            </div>
                        )}

                        <div className="flex flex-col gap-3 mt-4">
                            <button
                                onClick={() => {
                                    onClose();
                                    router.push('/cart');
                                }}
                                className="w-full h-14 flex items-center justify-center gap-3 rounded-xl border-2 border-[#1c140d] dark:border-[#c27a2a] text-[#1c140d] dark:text-[#c27a2a] font-black uppercase tracking-widest transition-all hover:bg-gray-50 dark:hover:bg-white/5 active:scale-[0.98]"
                            >
                                <span className="material-symbols-outlined text-[20px]">shopping_bag</span>
                                <span>View Full Cart</span>
                            </button>

                            <button
                                onClick={() => handleCheckoutRoute('/checkout')}
                                disabled={isValidating}
                                className="w-full h-14 flex items-center justify-center gap-3 rounded-xl bg-[#c27a2a] hover:bg-[#a35508] text-white font-black uppercase tracking-widest transition-all shadow-xl shadow-[#c27a2a]/20 hover:shadow-[#c27a2a]/30 active:scale-[0.98] disabled:opacity-50"
                            >
                                {isValidating ? (
                                    <span className="material-symbols-outlined animate-spin text-[20px]">progress_activity</span>
                                ) : (
                                    <>
                                        <span>Proceed to Checkout</span>
                                        <span className="material-symbols-outlined text-[20px]">lock</span>
                                    </>
                                )}
                            </button>
                        </div>
                        <p className="text-[10px] text-center text-gray-400 font-bold uppercase tracking-tighter mt-4">
                            Trusted Concierge Service • Free Worldwide Shipping
                        </p>
                    </div>
                ) : (
                    <div className="p-8 pb-12">
                        <button onClick={onClose} className="w-full h-12 rounded-lg bg-black dark:bg-white text-white dark:text-black font-bold hover:opacity-90 transition-all">
                            Continue Shopping
                        </button>
                    </div>
                )}
            </div>
        </>
    );
}

"use client";

import Link from "next/link";
import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useCart } from "@/contexts/CartContext";
import AnnouncementBar from "./AnnouncementBar";
import { STOREFRONT_NAV_ITEMS } from "@/lib/constants/navigation";

interface NavItem {
    id: string;
    label: string;
    url: string;
    is_visible: boolean;
    opens_in_new_tab: boolean;
    display_order: number;
}

export default function Header() {
    const { cartCount, cartTotal, openCart } = useCart();
    const router = useRouter();
    const [navItems, setNavItems] = useState<NavItem[]>([]);
    const [showAccountToast, setShowAccountToast] = useState(false);

    useEffect(() => {
        const homeItem: NavItem = { id: 'home', label: 'Home', url: '/', is_visible: true, opens_in_new_tab: false, display_order: -1 };

        fetch('/api/nav-items')
            .then(r => r.json())
            .then(data => {
                if (data.success && data.data.length > 0) {
                    const apiItems = data.data
                        .filter((i: NavItem) => i.is_visible)
                        .sort((a: NavItem, b: NavItem) => a.display_order - b.display_order);
                    // Only add Home if not already in the API data
                    const hasHome = apiItems.some((i: NavItem) => i.url === '/' || i.label.toLowerCase() === 'home');
                    setNavItems(hasHome ? apiItems : [homeItem, ...apiItems]);
                } else {
                    setNavItems(STOREFRONT_NAV_ITEMS.map((i, idx) => ({ id: String(idx), label: i.name, url: i.path, is_visible: true, opens_in_new_tab: false, display_order: idx })));
                }
            })
            .catch(() => {
                setNavItems(STOREFRONT_NAV_ITEMS.map((i, idx) => ({ id: String(idx), label: i.name, url: i.path, is_visible: true, opens_in_new_tab: false, display_order: idx })));
            });
    }, []);

    return (
        <>
            <AnnouncementBar />
            <header className="sticky top-0 z-50 w-full bg-[var(--color-background-light)]/95 dark:bg-[var(--color-background-dark)]/95 backdrop-blur-md border-b border-[#E5E5E5] dark:border-gray-800 transition-all duration-300">
                <div className="max-w-[1440px] mx-auto px-6 h-20 flex items-center justify-between relative">
                    {/* Logo (Left) */}
                    <Link href="/" className="flex items-center gap-2">
                        <div className="size-8 text-[#d41132]">
                            <span className="material-symbols-outlined text-[32px]">
                                checkroom
                            </span>
                        </div>
                        <span className="text-xl font-extrabold tracking-tight uppercase font-[family-name:var(--font-playfair)]">
                            Luxe Leather
                        </span>
                    </Link>

                    {/* Links (Center) - Dynamic from /api/nav-items */}
                    <nav className="hidden md:flex items-center gap-8 transition-opacity duration-200">
                        {navItems.map((item) => (
                            <Link
                                key={item.id}
                                href={item.url}
                                target={item.opens_in_new_tab ? '_blank' : undefined}
                                rel={item.opens_in_new_tab ? 'noopener noreferrer' : undefined}
                                className="text-sm font-bold text-[#1A1A1A] dark:text-white hover:text-[#d41132] transition-colors"
                            >
                                {item.label}
                            </Link>
                        ))}
                    </nav>

                    {/* Utilities (Right) */}
                    <div className="flex items-center gap-2 z-20">
                        <button
                            onClick={() => window.dispatchEvent(new CustomEvent('openSearch'))}
                            aria-label="Search"
                            className="p-2 hover:bg-black/5 dark:hover:bg-white/10 rounded-full transition-colors flex items-center justify-center"
                        >
                            <span className="material-symbols-outlined text-[24px]">
                                search
                            </span>
                        </button>
                        <div className="relative">
                            <button
                                onClick={() => { setShowAccountToast(true); setTimeout(() => setShowAccountToast(false), 2000); }}
                                aria-label="Account"
                                className="p-2 hover:bg-black/5 dark:hover:bg-white/10 rounded-full transition-colors hidden md:flex items-center justify-center"
                            >
                                <span className="material-symbols-outlined text-[24px]">
                                    person
                                </span>
                            </button>
                            {showAccountToast && (
                                <div className="absolute top-full right-0 mt-2 px-3 py-2 bg-slate-900 text-white text-xs rounded-lg whitespace-nowrap shadow-lg z-50">
                                    Coming soon
                                </div>
                            )}
                        </div>
                        <button
                            onClick={openCart}
                            aria-label="Cart"
                            className="flex items-center group/cart p-1.5 pl-3 hover:bg-black/5 dark:hover:bg-white/10 rounded-full transition-all gap-2"
                        >
                            <div className="flex flex-col items-end mr-1 hidden sm:flex">
                                <span className="text-[10px] font-bold text-gray-400 uppercase tracking-tighter leading-none mb-0.5">Your Bag</span>
                                <span className="text-sm font-black text-[#1c140d] dark:text-white leading-none">${cartTotal.toFixed(2)}</span>
                            </div>
                            <div className="relative p-2 bg-[#c27a2a] text-white rounded-full shadow-sm group-hover/cart:scale-110 transition-transform">
                                <span className="material-symbols-outlined text-[20px]">
                                    shopping_bag
                                </span>
                                {cartCount > 0 && (
                                    <span className="absolute -top-1 -right-1 flex h-4 w-4 items-center justify-center rounded-full bg-white text-[#c27a2a] text-[10px] font-black shadow-sm ring-1 ring-[#c27a2a]/10">
                                        {cartCount}
                                    </span>
                                )}
                            </div>
                        </button>
                    </div>
                </div>
            </header>
        </>
    );
}

